def _invalidate_case_data_caches() -> None:
    with _CASES_INVENTORY_STATS_CACHE_LOCK:
        _CASES_INVENTORY_STATS_CACHE.clear()
    with _COVERAGE_MATRIX_CACHE_LOCK:
        _COVERAGE_MATRIX_CACHE.clear()
    with _PORTAL_CASE_SEARCH_CACHE_LOCK:
        _PORTAL_CASE_SEARCH_CACHE.clear()
    with _PORTAL_CASE_SEARCH_EXACT_COUNT_LOCK:
        _PORTAL_CASE_SEARCH_EXACT_COUNT_CACHE.clear()
        _PORTAL_CASE_SEARCH_EXACT_COUNT_JOBS.clear()
    with _CASE_PAGE_HTML_CACHE_LOCK:
        _CASE_PAGE_HTML_CACHE.clear()
    with _CASE_RELATED_NEWS_CACHE_LOCK:
        _CASE_RELATED_NEWS_CACHE.clear()
_COVERAGE_MATRIX_CACHE_MAX = 32


def _case_page_html_cache_ttl() -> float:
    try:
        # Detail pages normalize a complete listing/gallery. Keep a rendered
        # page warm for the daily recommendation cycle; write paths invalidate it.
        return max(0.0, min(86400.0, float(os.getenv("SCLAW_CASE_PAGE_CACHE_TTL", "86400") or 86400)))
    except Exception:
        return 86400.0


def _case_page_html_disk_cache_path(source_item_id: int, fingerprint: str) -> Path:
    sid = max(0, int(source_item_id or 0))
    digest = hashlib.sha1(f"{sid}|{fingerprint}".encode("utf-8")).hexdigest()
    return _CASE_PAGE_HTML_DISK_CACHE_DIR / digest[:2] / f"{digest}.html"


def _case_related_news_cache_ttl() -> float:
    """Keep the existing related-articles section stable for one daily cycle."""
    try:
        return max(0.0, min(86400.0, float(os.getenv("SCLAW_CASE_RELATED_CACHE_TTL", "86400") or 86400)))
    except Exception:
        return 86400.0


def _case_page_fingerprint(item: dict[str, Any]) -> str:
    parts = [
        _CASE_PAGE_HTML_CACHE_VERSION,
        str(item.get("updated_at") or ""),
        str(item.get("last_checked_at") or ""),
        str(item.get("crawled_at") or ""),
        str(len(str(item.get("body_zh_hant") or ""))),
        str(len(str(item.get("body_original") or ""))),
        str(len(str(item.get("image_urls") or ""))),
        str(len(str(item.get("listing_media_json") or ""))),
    ]
    for rel in ("templates/case.html", "templates/partials/portal_suumo_listing.html", "static/site.css"):
        try:
            parts.append(str((Path.cwd() / rel).stat().st_mtime_ns))
        except Exception:
            parts.append("")
    return "|".join(parts)


def _case_page_html_cache_get(source_item_id: int, fingerprint: str) -> str | None:
    ttl = _case_page_html_cache_ttl()
    if ttl <= 0:
        return None
    now = time.monotonic()
    sid = int(source_item_id or 0)
    key = (sid, str(fingerprint))
    with _CASE_PAGE_HTML_CACHE_LOCK:
        hit = _CASE_PAGE_HTML_CACHE.get(key)
        if not hit:
            return None
        ts, html = hit
        if now - ts > ttl:
            _CASE_PAGE_HTML_CACHE.pop(key, None)
        else:
            return html
    try:
        path = _case_page_html_disk_cache_path(source_item_id, fingerprint)
        if not path.is_file() or path.stat().st_size < 256:
            return None
        html = path.read_text(encoding="utf-8")
        if not html:
            return None
    except Exception:
        return None
    with _CASE_PAGE_HTML_CACHE_LOCK:
        _CASE_PAGE_HTML_CACHE[key] = (now, html)
        while len(_CASE_PAGE_HTML_CACHE) > _CASE_PAGE_HTML_CACHE_MAX:
            oldest = min(_CASE_PAGE_HTML_CACHE.items(), key=lambda kv: kv[1][0])[0]
            _CASE_PAGE_HTML_CACHE.pop(oldest, None)
    return html


def _case_page_html_cache_set(source_item_id: int, fingerprint: str, html: str) -> None:
    if _case_page_html_cache_ttl() <= 0:
        return
    sid = int(source_item_id or 0)
    if sid <= 0 or not html:
        return
    key = (sid, str(fingerprint))
    with _CASE_PAGE_HTML_CACHE_LOCK:
        _CASE_PAGE_HTML_CACHE[key] = (time.monotonic(), str(html))
        while len(_CASE_PAGE_HTML_CACHE) > _CASE_PAGE_HTML_CACHE_MAX:
            oldest = min(_CASE_PAGE_HTML_CACHE.items(), key=lambda kv: kv[1][0])[0]
            _CASE_PAGE_HTML_CACHE.pop(oldest, None)
    try:
        path = _case_page_html_disk_cache_path(source_item_id, fingerprint)
        path.parent.mkdir(parents=True, exist_ok=True)
        tmp = path.with_name(f"{path.name}.{uuid4().hex}.tmp")
        tmp.write_text(str(html), encoding="utf-8")
        tmp.replace(path)
    except Exception:
        pass


def _serialize_case_page_render(handler: Callable[..., Response]) -> Callable[..., Response]:
    """Coalesce concurrent cold renders for the same standalone case page.

    Case rendering validates galleries and related articles, so a cold page is
    materially more expensive than a cached response.  Without this guard, a
    burst of clicks on one card starts the same render on multiple thread-pool
    workers.  The first request fills the existing HTML cache; followers then
    reuse it instead of doing duplicate work.
    """

    @wraps(handler)
    def wrapped(request: Request, source_item_id: int, *args: Any, **kwargs: Any) -> Response:
        try:
            sid = max(0, int(source_item_id or 0))
        except (TypeError, ValueError):
            sid = 0
        return_to = str(request.query_params.get("return_to") or "")[:512]
        key = (sid, return_to)
        with _CASE_PAGE_RENDER_LOCKS_LOCK:
            render_lock = _CASE_PAGE_RENDER_LOCKS.get(key)
            if render_lock is None:
                if len(_CASE_PAGE_RENDER_LOCKS) >= _CASE_PAGE_RENDER_LOCKS_MAX:
                    stale_key = next(
                        (lock_key for lock_key, lock in _CASE_PAGE_RENDER_LOCKS.items() if not lock.locked()),
                        None,
                    )
                    if stale_key is not None:
                        _CASE_PAGE_RENDER_LOCKS.pop(stale_key, None)
                render_lock = threading.Lock()
                _CASE_PAGE_RENDER_LOCKS[key] = render_lock
        with render_lock:
            return handler(request, source_item_id, *args, **kwargs)

    return wrapped


def _coverage_matrix_cache_ttl() -> float:
    try:
        return max(0.0, min(3600.0, float(os.getenv("SCLAW_COVERAGE_MATRIX_CACHE_TTL", "300") or 300)))
    except Exception:
        return 300.0


def _coverage_matrix_cache_key(age_days: int, threshold: int) -> str:
    return f"{int(age_days)}:{int(threshold)}"


def _coverage_matrix_cache_get(key: str) -> bytes | None:
    ttl = _coverage_matrix_cache_ttl()
    if ttl <= 0:
        return None
    now = time.monotonic()
    with _COVERAGE_MATRIX_CACHE_LOCK:
        hit = _COVERAGE_MATRIX_CACHE.get(str(key))
        if not hit:
            return None
        ts, body = hit
        if now - ts > ttl:
            _COVERAGE_MATRIX_CACHE.pop(str(key), None)
            return None
        return body


def _coverage_matrix_cache_set(key: str, body: bytes) -> None:
    if _coverage_matrix_cache_ttl() <= 0:
        return
    with _COVERAGE_MATRIX_CACHE_LOCK:
        _COVERAGE_MATRIX_CACHE[str(key)] = (time.monotonic(), bytes(body))
        while len(_COVERAGE_MATRIX_CACHE) > _COVERAGE_MATRIX_CACHE_MAX:
            oldest = min(_COVERAGE_MATRIX_CACHE.items(), key=lambda kv: kv[1][0])[0]
            _COVERAGE_MATRIX_CACHE.pop(oldest, None)


