def _portal_case_search_cache_prewarm_loop() -> None:
    """Keep common region searches warm without running ingestion or media repair."""
    try:
        ttl = _portal_case_search_cache_ttl()
        if ttl <= 0:
            return
        interval = float(os.getenv("SCLAW_PORTAL_SEARCH_PREWARM_INTERVAL", "") or 0)
        if interval <= 0:
            interval = min(600.0, max(60.0, ttl * 0.65))
    except Exception:
        interval = 600.0
    while True:
        try:
            _prewarm_portal_case_search_cache(force=True)
            time.sleep(interval)
        except Exception:
            time.sleep(60.0)


def _portal_case_search_cache_ttl() -> float:
    try:
        return max(0.0, min(3600.0, float(os.getenv("SCLAW_PORTAL_SEARCH_CACHE_TTL", "900") or 900)))
    except Exception:
        return 900.0


def _portal_case_search_cache_stale_ttl() -> float:
    try:
        ttl = _portal_case_search_cache_ttl()
        default_stale = max(1800.0, ttl * 4.0)
        return max(
            ttl,
            min(21600.0, float(os.getenv("SCLAW_PORTAL_SEARCH_STALE_TTL", str(default_stale)) or default_stale)),
        )
    except Exception:
        return 3600.0


def _portal_case_search_cache_key(payload: dict[str, Any]) -> str:
    return json.dumps(payload, ensure_ascii=False, sort_keys=True, separators=(",", ":"))


def _portal_case_search_cache_get_with_status(key: str) -> tuple[str | None, str]:
    ttl = _portal_case_search_cache_ttl()
    if ttl <= 0:
        return None, "disabled"
    now = time.monotonic()
    with _PORTAL_CASE_SEARCH_CACHE_LOCK:
        hit = _PORTAL_CASE_SEARCH_CACHE.get(key)
        if not hit:
            return None, "miss"
        ts, body = hit
        age = now - ts
        if age <= ttl:
            return body, "hit"
        if age <= _portal_case_search_cache_stale_ttl():
            return body, "stale"
        else:
            _PORTAL_CASE_SEARCH_CACHE.pop(key, None)
            return None, "expired"


def _portal_case_search_cache_get(key: str) -> str | None:
    body, status = _portal_case_search_cache_get_with_status(key)
    if status in ("hit", "stale"):
        return body
    return None


def _portal_case_search_cache_set(key: str, body: str) -> None:
    if _portal_case_search_cache_ttl() <= 0:
        return
    with _PORTAL_CASE_SEARCH_CACHE_LOCK:
        _PORTAL_CASE_SEARCH_CACHE[key] = (time.monotonic(), body)
        while len(_PORTAL_CASE_SEARCH_CACHE) > _PORTAL_CASE_SEARCH_CACHE_MAX:
            oldest = min(_PORTAL_CASE_SEARCH_CACHE.items(), key=lambda kv: kv[1][0])[0]
            _PORTAL_CASE_SEARCH_CACHE.pop(oldest, None)


def _portal_case_search_cache_clear() -> None:
    with _PORTAL_CASE_SEARCH_CACHE_LOCK:
        _PORTAL_CASE_SEARCH_CACHE.clear()


def _portal_case_search_exact_count_ttl() -> float:
    try:
        base = max(1800.0, _portal_case_search_cache_ttl())
        return max(
            300.0,
            min(21600.0, float(os.getenv("SCLAW_PORTAL_SEARCH_EXACT_COUNT_TTL", str(base)) or base)),
        )
    except Exception:
        return 1800.0


def _portal_case_search_exact_count_key(payload: dict[str, Any]) -> str:
    return json.dumps(payload, ensure_ascii=False, sort_keys=True, separators=(",", ":"))


def _portal_case_search_exact_count_get_with_status(key: str) -> tuple[dict[str, Any] | None, str]:
    ttl = _portal_case_search_exact_count_ttl()
    now = time.monotonic()
    with _PORTAL_CASE_SEARCH_EXACT_COUNT_LOCK:
        hit = _PORTAL_CASE_SEARCH_EXACT_COUNT_CACHE.get(key)
        if not hit:
            return None, "miss"
        ts, data = hit
        if now - ts <= ttl:
            return dict(data), "ready"
        _PORTAL_CASE_SEARCH_EXACT_COUNT_CACHE.pop(key, None)
        return None, "expired"


def _portal_case_search_exact_count_set(key: str, data: dict[str, Any]) -> None:
    with _PORTAL_CASE_SEARCH_EXACT_COUNT_LOCK:
        _PORTAL_CASE_SEARCH_EXACT_COUNT_CACHE[key] = (time.monotonic(), dict(data))
        while len(_PORTAL_CASE_SEARCH_EXACT_COUNT_CACHE) > _PORTAL_CASE_SEARCH_EXACT_COUNT_MAX:
            oldest = min(_PORTAL_CASE_SEARCH_EXACT_COUNT_CACHE.items(), key=lambda kv: kv[1][0])[0]
            _PORTAL_CASE_SEARCH_EXACT_COUNT_CACHE.pop(oldest, None)


def _portal_case_search_exact_count_normalized_payload(
    *,
    tx: str,
    portal: str,
    region_hint: str,
    keyword: str,
    property_types: list[str],
    price_min_man: int,
    price_max_man: int,
    layout_min_rooms: int,
    layout_max_rooms: int,
    layout_exact_zero: bool,
    max_age_days: int,
    limit: int,
    jp_line_id: int,
    jp_station_id: int,
    walk_max: int,
    coverage_matrix_aligned: bool,
) -> dict[str, Any]:
    return {
        "tx": str(tx or "").strip().lower() or "buy",
        "portal": str(portal or "").strip().lower() or "all",
        "region": str(region_hint or "").strip(),
        "keyword": str(keyword or "").strip(),
        "property_types": [str(x or "").strip() for x in (property_types or []) if str(x or "").strip()],
        "price_min_man": int(price_min_man or 0),
        "price_max_man": int(price_max_man or 0),
        "layout_min_rooms": int(layout_min_rooms or 0),
        "layout_max_rooms": int(layout_max_rooms or 0),
        "layout_exact_zero": bool(layout_exact_zero),
        "max_age_days": int(max_age_days or 0),
        "limit": int(limit or 0),
        "jp_line_id": int(jp_line_id or 0),
        "jp_station_id": int(jp_station_id or 0),
        "walk_max": int(walk_max or 0),
        "coverage_matrix_aligned": bool(coverage_matrix_aligned),
        "price_policy": "ignore_price_filter_v1",
    }


def _portal_case_search_exact_count_start(payload: dict[str, Any]) -> str:
    cache_key = _portal_case_search_exact_count_key(payload)
    cached, status = _portal_case_search_exact_count_get_with_status(cache_key)
    if cached is not None and status == "ready":
        return "ready"
    with _PORTAL_CASE_SEARCH_EXACT_COUNT_LOCK:
        if cache_key in _PORTAL_CASE_SEARCH_EXACT_COUNT_JOBS:
            return "pending"
        _PORTAL_CASE_SEARCH_EXACT_COUNT_JOBS.add(cache_key)

    def _runner() -> None:
        try:
            data = search_portal_cases(
                transaction=str(payload.get("tx") or "buy"),
                portal=str(payload.get("portal") or "all"),
                region_hint=str(payload.get("region") or ""),
                keyword=str(payload.get("keyword") or ""),
                property_types=list(payload.get("property_types") or []),
                price_min_man=int(payload.get("price_min_man") or 0),
                price_max_man=int(payload.get("price_max_man") or 0),
                layout_min_rooms=int(payload.get("layout_min_rooms") or 0),
                layout_max_rooms=int(payload.get("layout_max_rooms") or 0),
                layout_exact_zero=bool(payload.get("layout_exact_zero")),
                max_age_days=int(payload.get("max_age_days") or 0),
                limit=int(payload.get("limit") or 0),
                offset=0,
                page_size=1,
                jp_line_id=int(payload.get("jp_line_id") or 0),
                jp_station_id=int(payload.get("jp_station_id") or 0),
                walk_max=int(payload.get("walk_max") or 0),
                coverage_matrix_aligned=bool(payload.get("coverage_matrix_aligned")),
            )
            _portal_case_search_exact_count_set(
                cache_key,
                {
                    "count": int(data.get("count") or 0),
                    "limit": int(payload.get("limit") or 0),
                    "computed_at": int(time.time()),
                },
            )
        except Exception:
            pass
        finally:
            with _PORTAL_CASE_SEARCH_EXACT_COUNT_LOCK:
                _PORTAL_CASE_SEARCH_EXACT_COUNT_JOBS.discard(cache_key)

    threading.Thread(target=_runner, daemon=True).start()
    return "pending"


def _site_search_cache_ttl() -> float:
    try:
        return max(0.0, min(180.0, float(os.getenv("SCLAW_SITE_SEARCH_CACHE_TTL", "25") or 25)))
    except Exception:
        return 25.0


def _site_search_cache_key(payload: dict[str, Any]) -> str:
    return json.dumps(payload, ensure_ascii=False, sort_keys=True, separators=(",", ":"))


def _site_search_cache_get(key: str) -> bytes | None:
    ttl = _site_search_cache_ttl()
    if ttl <= 0:
        return None
    now = time.monotonic()
    with _SITE_SEARCH_CACHE_LOCK:
        hit = _SITE_SEARCH_CACHE.get(key)
        if not hit:
            return None
        ts, body = hit
        if now - ts > ttl:
            _SITE_SEARCH_CACHE.pop(key, None)
            return None
        return body


def _site_search_cache_set(key: str, body: bytes) -> None:
    if _site_search_cache_ttl() <= 0:
        return
    with _SITE_SEARCH_CACHE_LOCK:
        _SITE_SEARCH_CACHE[key] = (time.monotonic(), body)
        while len(_SITE_SEARCH_CACHE) > _SITE_SEARCH_CACHE_MAX:
            oldest = min(_SITE_SEARCH_CACHE.items(), key=lambda kv: kv[1][0])[0]
            _SITE_SEARCH_CACHE.pop(oldest, None)


def _jp_transit_api_cache_ttl() -> float:
    try:
        # Transit dropdown data updates hourly; cache for up to 2 hours by default.
        return max(0.0, min(6 * 3600.0, float(os.getenv("SCLAW_JP_TRANSIT_CACHE_TTL", "7200") or 7200)))
    except Exception:
        return 7200.0


def _jp_transit_api_cache_get(key: str) -> str | None:
    ttl = _jp_transit_api_cache_ttl()
    if ttl <= 0:
        return None
    now = time.monotonic()
    with _JP_TRANSIT_API_CACHE_LOCK:
        hit = _JP_TRANSIT_API_CACHE.get(key)
        if not hit:
            return None
        ts, body = hit
        if now - ts > ttl:
            _JP_TRANSIT_API_CACHE.pop(key, None)
            return None
        return body


def _jp_transit_api_cache_set(key: str, body: str) -> None:
    if _jp_transit_api_cache_ttl() <= 0:
        return
    with _JP_TRANSIT_API_CACHE_LOCK:
        _JP_TRANSIT_API_CACHE[key] = (time.monotonic(), body)
        while len(_JP_TRANSIT_API_CACHE) > _JP_TRANSIT_API_CACHE_MAX:
            oldest = min(_JP_TRANSIT_API_CACHE.items(), key=lambda kv: kv[1][0])[0]
            _JP_TRANSIT_API_CACHE.pop(oldest, None)


def _cases_inventory_stats_cache_get(age_days: int) -> dict[str, Any] | None:
    try:
        ttl = max(0.0, min(3600.0, float(os.getenv("SCLAW_INVENTORY_STATS_CACHE_TTL", "600") or 600)))
    except Exception:
        ttl = 600.0
    now = time.monotonic()
    with _CASES_INVENTORY_STATS_CACHE_LOCK:
        hit = _CASES_INVENTORY_STATS_CACHE.get(int(age_days))
        if not hit:
            return None
        ts, payload = hit
        if now - ts > ttl:
            _CASES_INVENTORY_STATS_CACHE.pop(int(age_days), None)
            return None
        return dict(payload)


def _cases_inventory_stats_cache_set(age_days: int, payload: dict[str, Any]) -> None:
    with _CASES_INVENTORY_STATS_CACHE_LOCK:
        _CASES_INVENTORY_STATS_CACHE[int(age_days)] = (time.monotonic(), dict(payload))

