HOME_HERO_VIDEO_EXTS = {".mp4", ".webm", ".mov", ".m4v"}
HOME_HERO_AUDIO_EXTS = {".mp3", ".wav", ".m4a", ".aac", ".ogg", ".flac"}
HOME_HERO_IMAGE_EXTS = {".jpg", ".jpeg", ".png", ".webp", ".gif"}
