def _env_bool(name: str, default: bool = False) -> bool:
    raw = os.getenv(name)
    if raw is None or str(raw).strip() == "":
        return bool(default)
    return str(raw).strip().lower() in ("1", "true", "yes", "on")


def _env_float(name: str, default: float, *, min_value: float | None = None, max_value: float | None = None) -> float:
    try:
        value = float(os.getenv(name, str(default)) or default)
    except Exception:
        value = float(default)
    if min_value is not None:
        value = max(float(min_value), value)
    if max_value is not None:
        value = min(float(max_value), value)
    return value


def _env_int(name: str, default: int, *, min_value: int | None = None, max_value: int | None = None) -> int:
    value = int(_env_float(name, float(default), min_value=min_value, max_value=max_value))
    return value


def _cache_file_age_days(path: Path, now: float) -> float:
    try:
        return max(0.0, (now - path.stat().st_mtime) / 86400.0)
    except Exception:
        return 0.0


def _cache_file_sort_ts(path: Path) -> float:
    try:
        st = path.stat()
        atime = float(getattr(st, "st_atime", 0.0) or 0.0)
        mtime = float(getattr(st, "st_mtime", 0.0) or 0.0)
        return min(ts for ts in (atime, mtime) if ts > 0) if atime or mtime else 0.0
    except Exception:
        return 0.0


def _cache_directory_stats(root: Path) -> dict[str, int]:
    files = 0
    bytes_total = 0
    if not root.exists():
        return {"files": 0, "bytes": 0}
    try:
        for path in root.rglob("*"):
            try:
                if path.is_file():
                    files += 1
                    bytes_total += int(path.stat().st_size or 0)
            except Exception:
                continue
    except Exception:
        pass
    return {"files": files, "bytes": bytes_total}


def _cleanup_empty_cache_dirs(root: Path, *, dry_run: bool = False, limit: int = 800) -> int:
    if not root.exists():
        return 0
    removed = 0
    try:
        dirs = [p for p in root.rglob("*") if p.is_dir()]
    except Exception:
        return 0
    for path in sorted(dirs, key=lambda p: len(str(p)), reverse=True):
        if removed >= limit:
            break
        try:
            if not any(path.iterdir()):
                if not dry_run:
                    path.rmdir()
                removed += 1
        except Exception:
            continue
    return removed


def _cleanup_cache_dir(
    root: Path,
    *,
    max_age_days: float,
    max_bytes: int,
    dry_run: bool = False,
    max_delete_files: int = 3000,
) -> dict[str, Any]:
    """Delete only generated cache files under a known cache directory."""
    root = Path(root)
    report: dict[str, Any] = {
        "path": str(root),
        "before": {"files": 0, "bytes": 0},
        "after": {"files": 0, "bytes": 0},
        "deleted_files": 0,
        "deleted_bytes": 0,
        "deleted_empty_dirs": 0,
        "errors": [],
        "dry_run": bool(dry_run),
    }
    if not root.exists():
        return report
    try:
        resolved = root.resolve()
        allowed = (Path.cwd() / "static" / "cache").resolve()
        if resolved != allowed and allowed not in resolved.parents:
            report["errors"].append("skip: outside static/cache")
            return report
    except Exception as exc:
        report["errors"].append(f"skip: resolve failed {type(exc).__name__}")
        return report

    now = time.time()
    entries: list[tuple[Path, int, float, bool]] = []
    try:
        for path in root.rglob("*"):
            try:
                if not path.is_file():
                    continue
                size = int(path.stat().st_size or 0)
                age_days = _cache_file_age_days(path, now)
                is_tmp = path.name.endswith(".tmp") or ".tmp." in path.name
                entries.append((path, size, age_days, is_tmp))
                report["before"]["files"] += 1
                report["before"]["bytes"] += size
            except Exception:
                continue
    except Exception as exc:
        report["errors"].append(f"scan failed: {type(exc).__name__}: {exc}")
        return report

    victims: dict[Path, int] = {}

    def mark(path: Path, size: int) -> None:
        if len(victims) < max(1, int(max_delete_files or 1)):
            victims[path] = int(size or 0)

    for path, size, age_days, is_tmp in entries:
        if is_tmp and age_days >= (1.0 / 24.0):
            mark(path, size)
        elif max_age_days > 0 and age_days >= max_age_days:
            mark(path, size)

    remaining_bytes = int(report["before"]["bytes"] or 0) - sum(victims.values())
    if max_bytes > 0 and remaining_bytes > max_bytes:
        for path, size, _age_days, _is_tmp in sorted(entries, key=lambda row: _cache_file_sort_ts(row[0])):
            if path in victims:
                continue
            mark(path, size)
            remaining_bytes -= size
            if remaining_bytes <= max_bytes or len(victims) >= max(1, int(max_delete_files or 1)):
                break

    for path, size in list(victims.items()):
        try:
            if not dry_run:
                path.unlink(missing_ok=True)
            report["deleted_files"] += 1
            report["deleted_bytes"] += int(size or 0)
        except Exception as exc:
            if len(report["errors"]) < 8:
                report["errors"].append(f"{path.name}: {type(exc).__name__}")

    report["deleted_empty_dirs"] = _cleanup_empty_cache_dirs(root, dry_run=dry_run)
    after_files = max(0, int(report["before"]["files"] or 0) - int(report["deleted_files"] or 0))
    after_bytes = max(0, int(report["before"]["bytes"] or 0) - int(report["deleted_bytes"] or 0))
    if not dry_run:
        actual = _cache_directory_stats(root)
        after_files = int(actual.get("files") or after_files)
        after_bytes = int(actual.get("bytes") or after_bytes)
    report["after"] = {"files": after_files, "bytes": after_bytes}
    return report


def _prune_timed_memory_cache(cache: dict[Any, Any], lock: Any, ttl: float) -> int:
    if ttl <= 0:
        return 0
    now = time.monotonic()
    removed = 0
    with lock:
        for key, value in list(cache.items()):
            try:
                ts = float(value[0])
            except Exception:
                continue
            if now - ts > ttl:
                cache.pop(key, None)
                removed += 1
    return removed


def _run_cache_maintenance_once(*, dry_run: bool = False) -> dict[str, Any]:
    """Prune generated disk caches and expired in-memory caches.

    This is deliberately local-only: it does not crawl portals, does not rebuild
    listings, and does not delete source DB records. Missing cache files can be
    regenerated by normal image/proxy paths.
    """
    started = time.time()
    with _CACHE_MAINTENANCE_LOCK:
        report: dict[str, Any] = {
            "ok": True,
            "dry_run": bool(dry_run),
            "started_at": datetime.utcnow().replace(microsecond=0).isoformat() + "Z",
            "finished_at": "",
            "elapsed_ms": 0,
            "disk": {},
            "memory": {},
            "lock": "local",
        }
        lock_acquired = False
        lock_fd: int | None = None
        try:
            DATA_DIR.mkdir(parents=True, exist_ok=True)
            stale_after = _env_float("SCLAW_CACHE_MAINTENANCE_LOCK_STALE_SEC", 15 * 60.0, min_value=300.0)
            if _CACHE_MAINTENANCE_LOCK_FILE.exists():
                age = time.time() - _CACHE_MAINTENANCE_LOCK_FILE.stat().st_mtime
                if age > stale_after:
                    _CACHE_MAINTENANCE_LOCK_FILE.unlink(missing_ok=True)
            try:
                lock_fd = os.open(str(_CACHE_MAINTENANCE_LOCK_FILE), os.O_CREAT | os.O_EXCL | os.O_WRONLY)
                os.write(lock_fd, str(os.getpid()).encode("utf-8"))
                lock_acquired = True
            except FileExistsError:
                report["ok"] = True
                report["skipped"] = "another maintenance run is active"
                return report

            case_max_age = _env_float("SCLAW_CACHE_CASE_IMAGES_MAX_AGE_DAYS", 45.0, min_value=1.0, max_value=365.0)
            thumb_max_age = _env_float("SCLAW_CACHE_CASE_THUMBS_MAX_AGE_DAYS", 14.0, min_value=1.0, max_value=180.0)
            case_page_max_age = _env_float("SCLAW_CACHE_CASE_PAGES_MAX_AGE_DAYS", 14.0, min_value=1.0, max_value=180.0)
            poster_max_age = _env_float("SCLAW_CACHE_HOME_POSTERS_MAX_AGE_DAYS", 30.0, min_value=1.0, max_value=365.0)
            case_max_bytes = _env_int("SCLAW_CACHE_CASE_IMAGES_MAX_BYTES", 6 * 1024 * 1024 * 1024, min_value=50 * 1024 * 1024)
            thumb_max_bytes = _env_int("SCLAW_CACHE_CASE_THUMBS_MAX_BYTES", 1536 * 1024 * 1024, min_value=20 * 1024 * 1024)
            case_page_max_bytes = _env_int("SCLAW_CACHE_CASE_PAGES_MAX_BYTES", 512 * 1024 * 1024, min_value=20 * 1024 * 1024)
            poster_max_bytes = _env_int("SCLAW_CACHE_HOME_POSTERS_MAX_BYTES", 512 * 1024 * 1024, min_value=20 * 1024 * 1024)
            max_delete_files = _env_int("SCLAW_CACHE_MAINTENANCE_MAX_DELETE_FILES", 12000, min_value=10, max_value=50000)
            report["disk"]["case_images"] = _cleanup_cache_dir(
                _CASE_IMAGE_CACHE_DIR,
                max_age_days=case_max_age,
                max_bytes=case_max_bytes,
                dry_run=dry_run,
                max_delete_files=max_delete_files,
            )
            report["disk"]["case_thumbs"] = _cleanup_cache_dir(
                _CASE_IMAGE_THUMB_DIR,
                max_age_days=thumb_max_age,
                max_bytes=thumb_max_bytes,
                dry_run=dry_run,
                max_delete_files=max_delete_files,
            )
            report["disk"]["case_pages"] = _cleanup_cache_dir(
                _CASE_PAGE_HTML_DISK_CACHE_DIR,
                max_age_days=case_page_max_age,
                max_bytes=case_page_max_bytes,
                dry_run=dry_run,
                max_delete_files=max_delete_files,
            )
            report["disk"]["home_posters"] = _cleanup_cache_dir(
                _HOME_CAROUSEL_POSTER_CACHE_DIR,
                max_age_days=poster_max_age,
                max_bytes=poster_max_bytes,
                dry_run=dry_run,
                max_delete_files=max_delete_files,
            )
            if not dry_run:
                with _CASE_IMAGE_PREFETCH_LOCK:
                    if report["disk"]["case_images"].get("deleted_files"):
                        _CASE_IMAGE_URL_CACHE.clear()
                    _CASE_IMAGE_PREFETCH_INFLIGHT.clear()
                _HOME_FEATURED_IMAGE_UNSUITABLE_CACHE.clear()
                _CASE_REPRESENTATIVE_VISUAL_CACHE.clear()

            memory_report = {
                "portal_search": 0,
                "portal_exact_count": 0,
                "site_search": 0,
                "jp_transit": 0,
                "coverage_matrix": 0,
                "case_pages": 0,
                "home_featured": 0,
            }
            if not dry_run:
                memory_report.update(
                    {
                        "portal_search": _prune_timed_memory_cache(
                            _PORTAL_CASE_SEARCH_CACHE,
                            _PORTAL_CASE_SEARCH_CACHE_LOCK,
                            _portal_case_search_cache_stale_ttl(),
                        ),
                        "portal_exact_count": _prune_timed_memory_cache(
                            _PORTAL_CASE_SEARCH_EXACT_COUNT_CACHE,
                            _PORTAL_CASE_SEARCH_CACHE_LOCK,
                            _portal_case_search_exact_count_ttl(),
                        ),
                        "site_search": _prune_timed_memory_cache(
                            _SITE_SEARCH_CACHE,
                            _SITE_SEARCH_CACHE_LOCK,
                            _site_search_cache_ttl(),
                        ),
                        "jp_transit": _prune_timed_memory_cache(
                            _JP_TRANSIT_API_CACHE,
                            _JP_TRANSIT_API_CACHE_LOCK,
                            _jp_transit_api_cache_ttl(),
                        ),
                        "coverage_matrix": _prune_timed_memory_cache(
                            _COVERAGE_MATRIX_CACHE,
                            _COVERAGE_MATRIX_CACHE_LOCK,
                            _coverage_matrix_cache_ttl(),
                        ),
                        "case_pages": _prune_timed_memory_cache(
                            _CASE_PAGE_HTML_CACHE,
                            _CASE_PAGE_HTML_CACHE_LOCK,
                            _case_page_html_cache_ttl(),
                        ),
                    }
                )
                now_wall = time.time()
                with _HOME_FEATURED_CASES_CACHE_LOCK:
                    for key, value in list(_HOME_FEATURED_CASES_CACHE.items()):
                        try:
                            if now_wall - float(value[0]) > _HOME_FEATURED_CASES_CACHE_TTL_SECONDS:
                                _HOME_FEATURED_CASES_CACHE.pop(key, None)
                                memory_report["home_featured"] += 1
                        except Exception:
                            continue
            report["memory"] = memory_report
        except Exception as exc:
            report["ok"] = False
            report["error"] = f"{type(exc).__name__}: {str(exc)[:240]}"
        finally:
            if lock_fd is not None:
                try:
                    os.close(lock_fd)
                except Exception:
                    pass
            if lock_acquired:
                try:
                    _CACHE_MAINTENANCE_LOCK_FILE.unlink(missing_ok=True)
                except Exception:
                    pass
            report["finished_at"] = datetime.utcnow().replace(microsecond=0).isoformat() + "Z"
            report["elapsed_ms"] = int((time.time() - started) * 1000)
            with _CACHE_MAINTENANCE_STATUS_LOCK:
                _CACHE_MAINTENANCE_STATUS.update(
                    {
                        "ok": bool(report.get("ok")),
                        "running": False,
                        "last_run_at": str(report.get("started_at") or ""),
                        "last_finished_at": str(report.get("finished_at") or ""),
                        "last_error": str(report.get("error") or ""),
                        "last_report": copy.deepcopy(report),
                    }
                )
            return report


def _cache_maintenance_loop() -> None:
    initial_delay = _env_float("SCLAW_CACHE_MAINTENANCE_INITIAL_DELAY_SEC", 45.0, min_value=0.0, max_value=3600.0)
    interval = _env_float("SCLAW_CACHE_MAINTENANCE_INTERVAL_SEC", 6 * 3600.0, min_value=300.0)
    if initial_delay > 0:
        time.sleep(initial_delay)
    while True:
        try:
            with _CACHE_MAINTENANCE_STATUS_LOCK:
                _CACHE_MAINTENANCE_STATUS["running"] = True
            report = _run_cache_maintenance_once(dry_run=False)
            skipped = str(report.get("skipped") or "")
            print(
                "SCLAW: cache maintenance done "
                f"ok={report.get('ok')} deleted="
                f"{sum(int((v or {}).get('deleted_files') or 0) for v in (report.get('disk') or {}).values())}"
                f"{' skipped=' + skipped if skipped else ''}",
                flush=True,
            )
        except Exception as exc:
            _log_backend_error("cache-maintenance-loop", exc)
            with _CACHE_MAINTENANCE_STATUS_LOCK:
                _CACHE_MAINTENANCE_STATUS.update(
                    {
                        "ok": False,
                        "running": False,
                        "last_error": f"{type(exc).__name__}: {str(exc)[:240]}",
                    }
                )
        time.sleep(interval)


def _start_cache_maintenance_worker() -> None:
    global _CACHE_MAINTENANCE_WORKER_STARTED
    if not _env_bool("SCLAW_CACHE_MAINTENANCE", True):
        with _CACHE_MAINTENANCE_STATUS_LOCK:
            _CACHE_MAINTENANCE_STATUS.update({"started": False, "running": False, "last_error": "disabled"})
        print("SCLAW: cache maintenance disabled（SCLAW_CACHE_MAINTENANCE=0）", flush=True)
        return
    with _CACHE_MAINTENANCE_LOCK:
        if _CACHE_MAINTENANCE_WORKER_STARTED:
            return
        threading.Thread(target=_cache_maintenance_loop, daemon=True, name="cache-maintenance").start()
        _CACHE_MAINTENANCE_WORKER_STARTED = True
        with _CACHE_MAINTENANCE_STATUS_LOCK:
            _CACHE_MAINTENANCE_STATUS.update({"started": True, "running": False, "last_error": ""})


def _case_image_cache_hash(raw_url: Any) -> str:
    return hashlib.sha1(str(raw_url or "").strip().encode("utf-8")).hexdigest()


def _case_image_static_url_from_path(path: Path) -> str:
    try:
        rel = path.resolve().relative_to((Path.cwd() / "static").resolve())
        return "/static/" + str(rel).replace("\\", "/")
    except Exception:
        return "/" + str(path).replace("\\", "/").lstrip("/")


def _case_image_thumbnail_path(static_url: Any, width: int = 520, height: int = 360) -> Path | None:
    src = str(static_url or "").strip()
    if not src.startswith("/static/"):
        return None
    source_path = _url_to_local_static_path(src)
    if not source_path or not source_path.is_file():
        return None
    w = max(120, min(960, int(width or 520)))
    h = max(90, min(960, int(height or 360)))
    digest = hashlib.sha1(f"{src}|{source_path.stat().st_mtime_ns}|{source_path.stat().st_size}|{w}x{h}".encode("utf-8")).hexdigest()
    return _CASE_IMAGE_THUMB_DIR / f"{w}x{h}" / digest[:2] / f"{digest}.webp"


def _case_image_make_thumbnail(static_url: Any, width: int = 520, height: int = 360) -> str:
    src = str(static_url or "").strip()
    thumb_path = _case_image_thumbnail_path(src, width=width, height=height)
    if not thumb_path:
        return src
    try:
        if thumb_path.is_file() and thumb_path.stat().st_size > 256:
            return _case_image_static_url_from_path(thumb_path)
    except Exception:
        pass
    source_path = _url_to_local_static_path(src)
    if not source_path:
        return src
    try:
        from PIL import Image, ImageOps  # type: ignore

        w = max(120, min(960, int(width or 520)))
        h = max(90, min(960, int(height or 360)))
        thumb_path.parent.mkdir(parents=True, exist_ok=True)
        tmp = thumb_path.with_name(thumb_path.name + ".tmp")
        with Image.open(source_path) as im0:
            im = ImageOps.exif_transpose(im0).convert("RGB")
            im.thumbnail((w, h), Image.Resampling.LANCZOS)
            canvas = Image.new("RGB", (w, h), (246, 248, 250))
            x = max(0, (w - im.width) // 2)
            y = max(0, (h - im.height) // 2)
            canvas.paste(im, (x, y))
            canvas.save(tmp, format="WEBP", quality=76, method=4)
        tmp.replace(thumb_path)
        return _case_image_static_url_from_path(thumb_path)
    except Exception:
        try:
            thumb_path.with_name(thumb_path.name + ".tmp").unlink(missing_ok=True)
        except Exception:
            pass
        return src


def case_card_thumb_url(static_url: Any, width: int = 520, height: int = 360) -> str:
    src = str(static_url or "").strip()
    if not src:
        return ""
    if not src.startswith("/static/"):
        return src
    # Pre-generate the thumbnail during server-side rendering, but keep the
    # browser URL identical to the client-side renderer so hydration does not
    # swap image URLs and download the same card art twice.
    _case_image_make_thumbnail(src, width=width, height=height)
    if re.match(r"^/static/cache/case-images/[a-f0-9]{2}/[a-f0-9]{40}\.(?:jpg|jpeg|png|webp)$", src, re.I):
        w = max(120, min(960, int(width or 520)))
        h = max(90, min(720, int(height or 360)))
        return f"/api/case-image-thumb?src={quote(src, safe='')}&w={w}&h={h}"
    return _case_image_make_thumbnail(src, width=width, height=height)


def _case_image_cache_ext(raw_url: Any, content_type: str = "") -> str:
    parsed = urlparse(str(raw_url or ""))
    candidates = [unquote(parsed.path or ""), unquote(parsed.query or "")]
    for text in candidates:
        m = re.search(r"\.(jpe?g|png|webp|gif|bmp)(?:$|[?&#])", text, re.I)
        if m:
            ext = "." + m.group(1).lower()
            return ".jpg" if ext == ".jpeg" else ext
    guessed = mimetypes.guess_extension(str(content_type or "").split(";", 1)[0].strip())
    if guessed in {".jpg", ".jpeg", ".png", ".webp", ".gif", ".bmp"}:
        return ".jpg" if guessed == ".jpeg" else guessed
    return ".jpg"


def _case_image_cached_static_url(raw_url: Any) -> str:
    raw = str(raw_url or "").strip()
    if not raw or not raw.lower().startswith(("http://", "https://")):
        return ""
    with _CASE_IMAGE_PREFETCH_LOCK:
        cached_mem = _CASE_IMAGE_URL_CACHE.get(raw, "")
    if cached_mem:
        return cached_mem
    h = _case_image_cache_hash(raw)
    shard_dir = _CASE_IMAGE_CACHE_DIR / h[:2]
    try:
        for path in shard_dir.glob(f"{h}.*"):
            if path.is_file() and path.stat().st_size > 256:
                cached = _case_image_static_url_from_path(path)
                with _CASE_IMAGE_PREFETCH_LOCK:
                    if len(_CASE_IMAGE_URL_CACHE) >= _CASE_IMAGE_URL_CACHE_MAX:
                        _CASE_IMAGE_URL_CACHE.clear()
                    _CASE_IMAGE_URL_CACHE[raw] = cached
                return cached
    except Exception:
        return ""
    return ""


def _case_image_download_to_cache(raw_url: Any) -> str:
    raw = str(raw_url or "").strip()
    if not raw.lower().startswith(("http://", "https://")):
        return ""
    cached = _case_image_cached_static_url(raw)
    if cached:
        return cached
    headers = dict(BROWSER_HEADERS)
    headers["Accept"] = "image/avif,image/webp,image/apng,image/svg+xml,image/*,*/*;q=0.8"
    max_bytes = 20 * 1024 * 1024
    curl_max_time = max(1.5, min(8.0, float(os.getenv("CASE_IMAGE_DOWNLOAD_MAX_TIME", "2.8") or 2.8)))
    curl_connect_time = max(0.8, min(curl_max_time, float(os.getenv("CASE_IMAGE_DOWNLOAD_CONNECT_TIME", "1.4") or 1.4)))
    fetch_url = raw
    # Yahoo's gallery URLs often carry a display-only `pri/up/nf_` query.
    # Directly requesting that variant intermittently returns HTTP 400, which
    # leaves only an arbitrary portal thumbnail for the card selector. Fetch
    # the underlying original asset while retaining the original URL as the
    # cache identity.
    try:
        parsed_raw = urlparse(raw)
        host = (parsed_raw.netloc or "").lower()
        if host.endswith("realestate-pctr.c.yimg.jp") and "/realestate-buy-image/bld_image/" in (parsed_raw.path or "").lower():
            fetch_url = parsed_raw._replace(query="").geturl()
    except Exception:
        fetch_url = raw
    h = _case_image_cache_hash(raw)
    shard_dir = _CASE_IMAGE_CACHE_DIR / h[:2]
    shard_dir.mkdir(parents=True, exist_ok=True)
    dest = shard_dir / f"{h}{_case_image_cache_ext(raw, '')}"
    tmp = dest.with_name(dest.name + ".tmp")
    downloaded = False
    try:
        tmp.unlink(missing_ok=True)
        referer = ""
        try:
            host = (urlparse(fetch_url).netloc or "").lower()
            if host:
                referer = f"https://{host}/"
        except Exception:
            referer = ""
        if shutil.which("curl"):
            cmd = [
                "curl",
                "--location",
                "--fail",
                "--silent",
                "--show-error",
                "--max-time",
                f"{curl_max_time:.1f}",
                "--connect-timeout",
                f"{curl_connect_time:.1f}",
                "--max-filesize",
                str(max_bytes),
                "--user-agent",
                str(headers.get("User-Agent") or "Mozilla/5.0"),
                "--header",
                f"Accept: {headers['Accept']}",
            ]
            if referer:
                cmd.extend(["--referer", referer])
            cmd.extend(["--output", str(tmp), fetch_url])
            try:
                subprocess.run(
                    cmd,
                    stdout=subprocess.DEVNULL,
                    stderr=subprocess.DEVNULL,
                    timeout=max(2.0, curl_max_time + 1.0),
                    check=True,
                )
                downloaded = True
            except Exception:
                try:
                    tmp.unlink(missing_ok=True)
                except Exception:
                    pass
        if not downloaded:
            http_headers = {
                "User-Agent": str(headers.get("User-Agent") or "Mozilla/5.0"),
                "Accept": headers["Accept"],
            }
            if referer:
                http_headers["Referer"] = referer
            with httpx.Client(follow_redirects=True, timeout=httpx.Timeout(curl_max_time, connect=curl_connect_time)) as client:
                with client.stream("GET", fetch_url, headers=http_headers) as resp:
                    resp.raise_for_status()
                    content_type = str(resp.headers.get("content-type") or "").lower()
                    if content_type and not content_type.startswith("image/") and "octet-stream" not in content_type:
                        return ""
                    size = 0
                    with tmp.open("wb") as fh:
                        for chunk in resp.iter_bytes(chunk_size=65536):
                            if not chunk:
                                continue
                            size += len(chunk)
                            if size > max_bytes:
                                raise ValueError("image too large")
                            fh.write(chunk)
            downloaded = True
        if not tmp.exists() or tmp.stat().st_size <= 256 or tmp.stat().st_size > max_bytes:
            tmp.unlink(missing_ok=True)
            return ""
        tmp.replace(dest)
        cached_probe = _case_image_static_url_from_path(dest)
        reject_reason = _case_image_proxy_reject_reason(cached_probe)
        if reject_reason and not (reject_reason == "access-map" and _is_yahoo_listing_image_url(raw)):
            try:
                dest.unlink(missing_ok=True)
            except Exception:
                pass
            return ""
    except Exception:
        try:
            tmp.unlink(missing_ok=True)
        except Exception:
            pass
        return ""
    cached = _case_image_static_url_from_path(dest)
    with _CASE_IMAGE_PREFETCH_LOCK:
        if len(_CASE_IMAGE_URL_CACHE) >= _CASE_IMAGE_URL_CACHE_MAX:
            _CASE_IMAGE_URL_CACHE.clear()
        _CASE_IMAGE_URL_CACHE[raw] = cached
    return cached


def _case_image_proxy_url(raw_url: Any) -> str:
    raw = str(raw_url or "").strip()
    if not raw.lower().startswith(("http://", "https://")):
        return raw
    h = _case_image_cache_hash(raw)
    return f"/api/case-image-cache/{h}?u={quote(raw, safe='')}"


def _case_image_prefetch_worker(urls: list[str]) -> None:
    try:
        for raw in urls:
            _case_image_download_to_cache(raw)
    finally:
        with _CASE_IMAGE_PREFETCH_LOCK:
            for raw in urls:
                _CASE_IMAGE_PREFETCH_INFLIGHT.discard(raw)


def _case_image_prefetch_enabled() -> bool:
    return str(os.getenv("SCLAW_CASE_IMAGE_PREFETCH", "")).strip().lower() in ("1", "true", "yes")


def _case_image_sync_fetch_enabled() -> bool:
    """Whether an uncached image request may block while downloading the remote image."""
    return str(os.getenv("SCLAW_CASE_IMAGE_SYNC_FETCH", "")).strip().lower() in ("1", "true", "yes")


def _case_image_prefetch(urls: list[Any], *, limit: int = 8, force: bool = False) -> None:
    if not force and not _case_image_prefetch_enabled():
        return
    pending: list[str] = []
    for u in urls:
        raw = str(u or "").strip()
        if not raw.lower().startswith(("http://", "https://")):
            continue
        if _case_image_cached_static_url(raw):
            continue
        with _CASE_IMAGE_PREFETCH_LOCK:
            if raw in _CASE_IMAGE_PREFETCH_INFLIGHT:
                continue
            _CASE_IMAGE_PREFETCH_INFLIGHT.add(raw)
        pending.append(raw)
        if len(pending) >= max(1, int(limit or 1)):
            break
    if pending:
        threading.Thread(target=_case_image_prefetch_worker, args=(pending,), daemon=True, name="case-image-cache").start()


def case_static_image_url(raw_url: Any) -> str:
    raw = str(raw_url or "").strip()
    if not raw:
        return ""
    if not raw.lower().startswith(("http://", "https://")):
        return raw
    cached = _case_image_cached_static_url(raw)
    if cached:
        return cached
    if _case_image_prefetch_enabled():
        _case_image_prefetch([raw], limit=1)
    return _case_image_proxy_url(raw)


_CASE_REPRESENTATIVE_VISUAL_CACHE: dict[str, str] = {}
_CASE_REPRESENTATIVE_VISUAL_CACHE_MAX = 5000


def _case_image_visual_reject_reason(static_url: Any) -> str:
    """Lightweight local visual filter for card thumbnails.

    This intentionally does not call an AI model. It rejects obvious floor plans,
    diagrams, placeholders, full-frame promotional text boards and extreme-ratio
    fragments after the image has been cached locally, then lets ordinary
    exterior/interior photos pass through.
    """
    s = str(static_url or "").strip()
    if not s:
        return "empty"
    if s in _CASE_REPRESENTATIVE_VISUAL_CACHE:
        return str(_CASE_REPRESENTATIVE_VISUAL_CACHE.get(s) or "")
    path = _url_to_local_static_path(s)
    if not path or not path.is_file():
        return ""
    try:
        from PIL import Image, ImageFilter, ImageStat  # type: ignore
    except ImportError:
        return ""

    try:
        with Image.open(path) as im0:
            im = im0.convert("RGB")
            w, h = im.size
            if w <= 0 or h <= 0:
                reason = "invalid"
            else:
                aspect = w / max(1, h)
                if min(w, h) < 120 or max(w, h) < 260:
                    reason = "tiny"
                elif aspect < 0.45 or aspect > 3.2:
                    reason = "extreme-ratio"
                else:
                    small = im.resize((96, 96))
                    hsv = small.convert("HSV")
                    sat_mean = float(ImageStat.Stat(hsv).mean[1]) / 255.0
                    gray = small.convert("L")
                    px = list(gray.getdata())
                    total = max(1, len(px))
                    light_ratio = sum(1 for v in px if v >= 232) / total
                    dark_ratio = sum(1 for v in px if v <= 28) / total
                    mid_gray_ratio = sum(1 for v in px if 88 <= v <= 214) / total
                    edge = gray.filter(ImageFilter.FIND_EDGES)
                    edge_mean = float(ImageStat.Stat(edge).mean[0]) / 255.0
                    color_bins: dict[tuple[int, int, int], int] = {}
                    greenish = 0
                    for red, green, blue in small.getdata():
                        key = (red // 24, green // 24, blue // 24)
                        color_bins[key] = color_bins.get(key, 0) + 1
                        if green >= red + 12 and green >= blue + 8:
                            greenish += 1
                    dominant_color_ratio = max(color_bins.values(), default=0) / total
                    greenish_ratio = greenish / total
                    reason = ""
                    # Floor plans and structure diagrams are usually bright, low-saturation
                    # line drawings with many hard edges. Keep the thresholds conservative
                    # so normal room photos with bright walls are not rejected.
                    if (
                        sat_mean <= 0.04
                        and light_ratio >= 0.82
                        and 0.035 <= mid_gray_ratio <= 0.22
                        and 0.035 <= edge_mean <= 0.12
                        and dark_ratio <= 0.02
                    ):
                        reason = "blank-placeholder"
                    elif light_ratio >= 0.38 and edge_mean >= 0.105 and sat_mean <= 0.38:
                        reason = "floor-plan"
                    elif light_ratio >= 0.58 and edge_mean >= 0.075 and sat_mean <= 0.28:
                        reason = "line-diagram"
                    elif sat_mean <= 0.10 and light_ratio >= 0.20 and dark_ratio <= 0.04 and edge_mean >= 0.16:
                        reason = "access-map"
                    elif sat_mean <= 0.12 and 0.24 <= light_ratio <= 0.55 and dark_ratio <= 0.01 and mid_gray_ratio >= 0.52 and edge_mean >= 0.12:
                        reason = "site-plan"
                    elif sat_mean <= 0.20 and light_ratio <= 0.13 and dark_ratio <= 0.01 and mid_gray_ratio >= 0.58 and edge_mean >= 0.14:
                        reason = "site-plan"
                    elif (
                        sat_mean <= 0.07
                        and dark_ratio <= 0.02
                        and mid_gray_ratio >= 0.24
                        and 0.05 <= edge_mean <= 0.14
                        and dominant_color_ratio >= 0.26
                    ):
                        reason = "site-plan"
                    elif sat_mean <= 0.26 and light_ratio >= 0.18 and mid_gray_ratio >= 0.30 and edge_mean >= 0.18 and aspect <= 1.35:
                        reason = "floor-plan"
                    # A parcel diagram can be a large, lightly textured green
                    # block with a compass/measurement border rather than the
                    # black-line look of a conventional floor plan. Reject that
                    # narrow pattern so it cannot become a homepage hero image.
                    elif (
                        0.75 <= aspect <= 1.35
                        and dominant_color_ratio >= 0.28
                        and greenish_ratio >= 0.40
                        and light_ratio >= 0.12
                        and edge_mean <= 0.10
                    ):
                        reason = "parcel-diagram"
                    # Renovation checklists and similar ad boards can arrive from
                    # listing feeds as opaque image URLs, so URL/context filters
                    # cannot identify them. They are a highly saturated, almost
                    # entirely green panel with dense contrast edges from the
                    # baked-in copy. Keep this deliberately narrow: garden and
                    # exterior photos do not have a single dominant green swatch.
                    elif (
                        0.75 <= aspect <= 2.2
                        and sat_mean >= 0.38
                        and greenish_ratio >= 0.78
                        and dominant_color_ratio >= 0.32
                        and edge_mean >= 0.14
                        and light_ratio <= 0.16
                    ):
                        reason = "promotional-text-board"
                    elif light_ratio >= 0.78 and dark_ratio <= 0.03 and sat_mean <= 0.18:
                        reason = "blank-placeholder"
    except Exception:
        reason = ""
    if len(_CASE_REPRESENTATIVE_VISUAL_CACHE) >= _CASE_REPRESENTATIVE_VISUAL_CACHE_MAX:
        _CASE_REPRESENTATIVE_VISUAL_CACHE.clear()
    _CASE_REPRESENTATIVE_VISUAL_CACHE[s] = str(reason or "")
    return reason


def _case_image_proxy_reject_reason(static_url: Any) -> str:
    """Only reject media that is unsafe/useless for rendering, not subjective card quality."""
    reason = _case_image_visual_reject_reason(static_url)
    if reason in {"empty", "invalid", "tiny", "extreme-ratio", "blank-placeholder"}:
        return reason
    return ""


def _case_image_file_dimensions(path: Path) -> tuple[int, int] | None:
    """Read common image dimensions without requiring Pillow."""
    try:
        data = path.read_bytes()[:128 * 1024]
    except Exception:
        return None
    if len(data) < 24:
        return None
    if data.startswith(b"\x89PNG\r\n\x1a\n") and data[12:16] == b"IHDR":
        return int.from_bytes(data[16:20], "big"), int.from_bytes(data[20:24], "big")
    if data[:2] == b"\xff\xd8":
        i = 2
        n = len(data)
        while i + 9 < n:
            if data[i] != 0xFF:
                i += 1
                continue
            marker = data[i + 1]
            i += 2
            if marker in {0xD8, 0xD9, 0x01} or 0xD0 <= marker <= 0xD7:
                continue
            if i + 2 > n:
                break
            seg_len = int.from_bytes(data[i : i + 2], "big")
            if seg_len < 2 or i + seg_len > n:
                break
            if marker in {0xC0, 0xC1, 0xC2, 0xC3, 0xC5, 0xC6, 0xC7, 0xC9, 0xCA, 0xCB, 0xCD, 0xCE, 0xCF}:
                h = int.from_bytes(data[i + 3 : i + 5], "big")
                w = int.from_bytes(data[i + 5 : i + 7], "big")
                return w, h
            i += seg_len
    if data.startswith(b"RIFF") and data[8:12] == b"WEBP" and len(data) >= 30:
        chunk = data[12:16]
        if chunk == b"VP8X" and len(data) >= 30:
            w = 1 + int.from_bytes(data[24:27], "little")
            h = 1 + int.from_bytes(data[27:30], "little")
            return w, h
        if chunk == b"VP8 " and len(data) >= 30:
            pos = data.find(b"\x9d\x01\x2a", 20, 64)
            if pos >= 0 and pos + 7 <= len(data):
                w = int.from_bytes(data[pos + 3 : pos + 5], "little") & 0x3FFF
                h = int.from_bytes(data[pos + 5 : pos + 7], "little") & 0x3FFF
                return w, h
        if chunk == b"VP8L" and len(data) >= 25:
            b0, b1, b2, b3 = data[21], data[22], data[23], data[24]
            w = 1 + (((b1 & 0x3F) << 8) | b0)
            h = 1 + (((b3 & 0x0F) << 10) | (b2 << 2) | ((b1 & 0xC0) >> 6))
            return w, h
    return None


def _case_image_sparse_content_issue(path: Path, *, file_size: int = 0) -> dict[str, Any]:
    """Detect high-resolution images where the useful content is tiny in a blank canvas."""
    try:
        from PIL import Image  # type: ignore
    except ImportError:
        return {}
    try:
        with Image.open(path) as im0:
            im = im0.convert("RGB")
            w0, h0 = im.size
            if w0 <= 0 or h0 <= 0:
                return {}
            max_side = 128
            ratio = min(1.0, max_side / max(w0, h0))
            w = max(1, int(round(w0 * ratio)))
            h = max(1, int(round(h0 * ratio)))
            sample = im.resize((w, h))
            px = list(sample.getdata())
            total = max(1, len(px))
            min_x = w
            min_y = h
            max_x = -1
            max_y = -1
            hits = 0
            for y in range(h):
                row = y * w
                for x in range(w):
                    r, g, b = px[row + x]
                    spread = max(r, g, b) - min(r, g, b)
                    is_white_margin = r >= 232 and g >= 232 and b >= 232 and spread <= 24
                    is_near_blank = r >= 204 and g >= 204 and b >= 204 and spread <= 34
                    if is_white_margin or is_near_blank:
                        continue
                    hits += 1
                    if x < min_x:
                        min_x = x
                    if y < min_y:
                        min_y = y
                    if x > max_x:
                        max_x = x
                    if y > max_y:
                        max_y = y
            if hits < max(18, int(total * 0.006)) or max_x < min_x or max_y < min_y:
                return {
                    "category": "placeholder",
                    "reason": "圖片幾乎全是空白留白，缺少可用房源內容",
                    "information_value": 4,
                    "metrics": {"width": w0, "height": h0, "bytes": file_size, "content_ratio": 0},
                }
            box_w = (max_x - min_x + 1) / max(1, w)
            box_h = (max_y - min_y + 1) / max(1, h)
            box_area = box_w * box_h
            content_ratio = hits / total
            sparse = (
                (box_area <= 0.12 and content_ratio <= 0.11)
                or (box_area <= 0.20 and content_ratio <= 0.055)
                or (box_w <= 0.42 and box_h <= 0.42 and content_ratio <= 0.14)
            )
            if sparse:
                return {
                    "category": "unclear",
                    "reason": "圖片有效內容占比過低，四周大面積留白，不適合作為房源相冊圖",
                    "information_value": 10,
                    "metrics": {
                        "width": w0,
                        "height": h0,
                        "bytes": file_size,
                        "content_ratio": round(content_ratio, 4),
                        "content_box_area": round(box_area, 4),
                        "content_box_w": round(box_w, 4),
                        "content_box_h": round(box_h, 4),
                    },
                }
    except Exception:
        return {}
    return {}


def _case_gallery_local_quality_issue(static_url: Any) -> dict[str, Any]:
    """Return a conservative local quality issue for gallery cleanup."""
    s = str(static_url or "").strip()
    if not s:
        return {}
    path = _url_to_local_static_path(s)
    if not path or not path.is_file():
        return {}
    try:
        file_size = int(path.stat().st_size or 0)
    except Exception:
        file_size = 0
    header_dims = _case_image_file_dimensions(path)
    if header_dims:
        w, h = header_dims
        aspect = w / max(1, h)
        pixels = w * h
        if min(w, h) < 120 or max(w, h) < 260 or pixels < 60_000:
            return {
                "category": "unclear",
                "reason": f"本地圖片解析度過低（{w}x{h}）",
                "information_value": 8,
                "metrics": {"width": w, "height": h, "bytes": file_size},
            }
        if min(w, h) < 220 or max(w, h) < 480:
            return {
                "category": "unclear",
                "reason": f"本地圖片偏低清，不適合作為相冊資料（{w}x{h}）",
                "information_value": 18,
                "metrics": {"width": w, "height": h, "bytes": file_size},
            }
        if aspect < 0.33 or aspect > 4.2:
            return {
                "category": "unclear",
                "reason": f"本地圖片長寬比異常（{w}x{h}）",
                "information_value": 15,
                "metrics": {"width": w, "height": h, "bytes": file_size},
            }
    sparse_issue = _case_image_sparse_content_issue(path, file_size=file_size)
    if sparse_issue:
        return sparse_issue
    if file_size and file_size < 1500:
        return {
            "category": "unclear",
            "reason": "本地圖片檔案極小，疑似無效低清縮圖",
            "information_value": 5,
            "metrics": {"bytes": file_size},
        }
    try:
        from PIL import Image, ImageFilter, ImageStat  # type: ignore
    except ImportError:
        return {}
    try:
        with Image.open(path) as im0:
            im = im0.convert("RGB")
            w, h = im.size
            if w <= 0 or h <= 0:
                return {
                    "category": "placeholder",
                    "reason": "本地圖片尺寸無效",
                    "information_value": 0,
                    "metrics": {"width": w, "height": h, "bytes": file_size},
                }
            aspect = w / max(1, h)
            pixels = w * h
            if min(w, h) < 120 or max(w, h) < 260 or pixels < 60_000:
                return {
                    "category": "unclear",
                    "reason": f"本地圖片解析度過低（{w}x{h}）",
                    "information_value": 8,
                    "metrics": {"width": w, "height": h, "bytes": file_size},
                }
            if min(w, h) < 220 or max(w, h) < 480:
                return {
                    "category": "unclear",
                    "reason": f"本地圖片偏低清，不適合作為相冊資料（{w}x{h}）",
                    "information_value": 18,
                    "metrics": {"width": w, "height": h, "bytes": file_size},
                }
            if aspect < 0.33 or aspect > 4.2:
                return {
                    "category": "unclear",
                    "reason": f"本地圖片長寬比異常（{w}x{h}）",
                    "information_value": 15,
                    "metrics": {"width": w, "height": h, "bytes": file_size},
                }
            small = im.resize((96, 96))
            gray = small.convert("L")
            edge = gray.filter(ImageFilter.FIND_EDGES)
            edge_mean = float(ImageStat.Stat(edge).mean[0]) / 255.0
            if file_size and file_size < 8_000 and edge_mean < 0.018:
                return {
                    "category": "unclear",
                    "reason": "本地圖片檔案過小且細節不足，疑似低清縮圖",
                    "information_value": 12,
                    "metrics": {"width": w, "height": h, "bytes": file_size, "edge_mean": round(edge_mean, 4)},
                }
    except Exception as exc:
        return {
            "category": "placeholder",
            "reason": f"本地圖片無法讀取：{type(exc).__name__}",
            "information_value": 0,
            "metrics": {"bytes": file_size},
        }
    return {}


def _case_gallery_local_display_issue(static_url: Any) -> bool:
    """Cheap render-time rejection; full visual auditing runs outside page requests."""
    path = _url_to_local_static_path(str(static_url or "").strip())
    if not path or not path.is_file():
        return False
    try:
        file_size = int(path.stat().st_size or 0)
    except OSError:
        return False
    if file_size and file_size < 1500:
        return True
    dims = _case_image_file_dimensions(path)
    if not dims:
        return False
    width, height = dims
    aspect = width / max(1, height)
    return min(width, height) < 120 or max(width, height) < 260 or width * height < 60_000 or aspect < 0.33 or aspect > 4.2


def _case_representative_url_reject_reason(raw_url: Any, *, profile: str = "building") -> str:
    """Reject URLs that are useful in details but poor as a case card hero."""
    s = str(raw_url or "").strip()
    if not s:
        return "empty"
    try:
        parsed_url = urlparse(s)
        host = (parsed_url.netloc or "").lower()
        path = (parsed_url.path or "").lower()
    except Exception:
        host = ""
        path = ""
    try:
        decoded = unquote(s)
    except Exception:
        decoded = s
    hay = f"{s} {decoded}".lower()
    if host.endswith("realestate-pctr.c.yimg.jp") and "/realestate-buy-image/bld_image/" not in path:
        return "opaque-yahoo-proxy"
    if is_likely_agent_portrait_image_url(s):
        return "agent"
    if _is_yahoo_auxiliary_listing_image_url(s):
        return "yahoo-auxiliary-image"
    if is_portal_non_property_image_url(s):
        return "portal-asset"
    reject_tokens = (
        "madori",
        "floorplan",
        "floor_plan",
        "layout",
        "heimen",
        "kukaku",
        "menseki",
        "siteplan",
        "site_plan",
        "間取",
        "間取り",
        "平面図",
        "図面",
        "圖面",
        "区画図",
        "區劃圖",
        "配置図",
        "配置圖",
        "敷地図",
        "敷地圖",
        "測量図",
        "測量圖",
        "公図",
        "公圖",
        "户型",
        "戶型",
        "toire",
        "toilet",
        "bath",
        "bathroom",
        "powder",
        "sanitary",
        "washroom",
        "lavatory",
        "setsubi",
        "facility",
        "equipment",
        "vending",
        "vendingmachine",
        "jihanki",
        "drink",
        "beverage",
        "cocacola",
        "coca-cola",
        "トイレ",
        "便所",
        "浴室",
        "風呂",
        "洗面",
        "脱衣",
        "設備",
        "設備写真",
        "設備画像",
        "自販機",
        "自動販売機",
        "販売機",
        "飲料",
        "ドリンク",
        "宅配ボックス",
        "インターホン",
        "廁",
        "厕",
        "/map/",
        "chizu",
        "access",
        "route",
        "rosen",
        "station",
        "train",
        "bus",
        "guidance",
        "outskirts",
        "shuuhen",
        "environment",
        "案内図",
        "案內圖",
        "現地案内",
        "周辺",
        "周邊",
    )
    if profile in {"land", "parking"}:
        profile_allowed_tokens = {
            "outskirts",
            "shuuhen",
            "environment",
            "周辺",
            "周邊",
        }
        if profile == "parking":
            profile_allowed_tokens |= {"parking"}
        reject_tokens = tuple(tok for tok in reject_tokens if tok not in profile_allowed_tokens)
    if any(tok in hay for tok in reject_tokens):
        return "non-photo-context"
    if "athome.co.jp" in hay and "/mansion/shinchiku/cimages/project_detail_slide/" in hay:
        return "new-build-concept"
    if "athome.co.jp" in hay and "/mansion/shinchiku/cimages/energy_saving/" in hay:
        return "new-build-spec"
    if "athome.co.jp" in hay and "/mansion/shinchiku/cimages/project_free/" in hay:
        return "new-build-promo"
    return ""


