def _home_intro_script_variants(tone: str = "friendly", length: str = "short") -> list[str]:
    base = [
        (
            "你好，歡迎來到日本不動產全球指定搜尋網。這裡把 SUUMO、LIFULL HOME'S、at home 等日本房產資訊集中整理，"
            "讓你可以用地區、車站、價格、格局和照片快速縮小範圍。看到喜歡的案件，可以先留下需求，我們會協助確認交通、室內外重點、生活圈與適合客群，"
            "再由顧問幫你接下一步看屋或諮詢。想找日本自住、投資或租屋，先從首頁開始篩選，會更快找到方向。"
        ),
        (
            "如果你正在研究日本房產，先從這個首頁開始。你可以直接用區域、車站、預算和房型找案件，也可以把有興趣的物件交給顧問整理。"
            "我們會把交通路線、室內外照片、價格條件和生活圈亮點一起看，幫你判斷這個案件適不適合自住、出租或長期持有。"
            "留下需求後，顧問會把重點整理好，再跟你做下一步確認。"
        ),
        (
            "找日本房產，不需要在很多網站之間來回切換。這個首頁會把主要平台的案件、照片、交通和條件集中到同一個入口，"
            "你只要選地區、車站、價格或房型，就能快速看到適合的物件。遇到想了解的案件，交給我們的顧問協助核對資料、整理亮點，"
            "讓你在看屋前就先知道該看哪裡、該問什麼。"
        ),
    ]
    long_extra = (
        "我們也會特別注意圖片是否完整、格局是否清楚、交通說明是否能支撐銷售亮點，"
        "讓每一次諮詢都更接近真正可判斷、可比較、可行動的案件。"
    )
    if str(length or "").lower() in {"long", "full"}:
        return [text + long_extra for text in base]
    if str(tone or "").lower() in {"professional", "consultant"}:
        return [base[1], base[0], base[2]]
    return base


def _home_intro_case_row(
    conn: sqlite3.Connection, *, source_item_id: int = 0, content_id: int = 0
) -> dict[str, Any] | None:
    sid = int(source_item_id or 0)
    cid = int(content_id or 0)
    if sid <= 0 and cid <= 0:
        return None
    where_sql = "c.source_item_id = ?" if sid > 0 else "c.id = ?"
    param = sid if sid > 0 else cid
    row = conn.execute(
        f"""
        SELECT
            c.id AS content_id,
            c.source_item_id,
            c.seo_slug,
            c.seo_title,
            c.seo_description,
            c.title_zh_hant,
            c.title_zh_hans,
            c.body_zh_hant,
            c.region_code,
            c.keyword_type,
            c.topic_category,
            c.updated_at,
            COALESCE(c.case_transaction_override, '') AS case_transaction_override,
            COALESCE(c.case_jp_region_override, '') AS case_jp_region_override,
            COALESCE(c.case_transit_override, '') AS case_transit_override,
            COALESCE(c.jp_station_id, 0) AS jp_station_id,
            COALESCE(c.walk_min, 0) AS walk_min,
            COALESCE(c.listing_media_json, '[]') AS listing_media_json,
            s.source_name,
            s.item_url,
            s.image_urls,
            s.body_original,
            s.title_original,
            COALESCE(s.thumbnail_url, '') AS thumbnail_url,
            COALESCE(s.hero_image_url, '') AS hero_image_url,
            COALESCE(NULLIF(TRIM(s.content_kind), ''), '') AS content_kind
        FROM content_items c
        JOIN source_items s ON s.id = c.source_item_id
        WHERE {where_sql}
        LIMIT 1
        """,
        (param,),
    ).fetchone()
    return dict(row) if row else None


def _home_intro_case_media(row: dict[str, Any], *, ensure_local: bool = False) -> tuple[str, list[str], list[str]]:
    imgs, vids = extract_media_urls_from_row(row)
    firsts = [
        str(row.get("hero_image_url") or "").strip(),
        str(row.get("thumbnail_url") or "").strip(),
    ]
    merged_imgs: list[str] = []
    for u in [*firsts, *imgs]:
        if u and u not in merged_imgs:
            merged_imgs.append(u)
    hero = merged_imgs[0] if merged_imgs else ""
    if ensure_local and hero.lower().startswith(("http://", "https://")):
        cached = _case_image_download_to_cache(hero)
        if cached:
            hero = cached
    elif hero.lower().startswith(("http://", "https://")):
        hero = case_static_image_url(hero)
    return hero, merged_imgs[:8], vids[:4]


def _home_intro_case_title(row: dict[str, Any]) -> str:
    return _social_text(
        row.get("title_zh_hant")
        or row.get("seo_title")
        or row.get("title_original")
        or row.get("seo_description")
        or "日本房產案件",
        limit=88,
    )


def _home_intro_case_price_hint(row: dict[str, Any]) -> str:
    blob = " ".join(
        str(row.get(k) or "")
        for k in (
            "seo_title",
            "seo_description",
            "title_zh_hant",
            "title_original",
            "body_zh_hant",
            "body_original",
        )
    )
    patterns = (
        r"(?:價格|售價|価格)\s*[:：]?\s*([0-9,\.]+\s*(?:萬|万)?(?:日圓|日元|円|JPY)?)",
        r"([0-9,\.]+\s*萬日圓)",
        r"([0-9,\.]+\s*万(?:円)?)",
        r"([0-9,\.]+\s*億(?:円|日圓)?)",
    )
    for pat in patterns:
        m = re.search(pat, blob, re.I)
        if m:
            return _social_text(m.group(1), limit=36)
    return ""


def _home_intro_case_video_script(row: dict[str, Any]) -> str:
    meta = infer_case_metadata(row)
    title = _home_intro_case_title(row)
    region = _social_text(
        row.get("case_jp_region_override") or meta.get("jp_region_display_zh") or "日本重點區域",
        limit=48,
    )
    transit = _social_text(
        row.get("case_transit_override") or meta.get("transit_line_zh") or "交通條件請以原站資料確認",
        limit=90,
    )
    price = _home_intro_case_price_hint(row)
    source = _social_text(row.get("source_name") or "", limit=28) or "原站"
    body = re.sub(
        r"\s+",
        " ",
        str(row.get("seo_description") or row.get("body_zh_hant") or row.get("body_original") or "").strip(),
    )
    body = _social_text(body, limit=110)
    price_line = f"目前可先注意價格約 {price}，" if price else ""
    detail_line = f"資料來源是 {source}，{body}" if body else f"資料來源是 {source}，建議再確認原站照片、格局與管理條件。"
    return (
        f"這次帶你快速看一筆日本房產案件：{title}。"
        f"案件位置在 {region}，交通重點是 {transit}。"
        f"{price_line}看這類物件時，我會先確認三件事：第一，室內外照片是否完整；第二，交通到車站或生活圈是否符合需求；第三，管理費、修繕積立金與交屋時程是否清楚。"
        f"{detail_line}"
        "如果你想看完整資料，可以從案件頁打開原站資訊；需要比較同區域案件，也可以把這筆加入清單，我們再協助整理可看屋與可發布的重點。"
    )


def _home_intro_case_public_row(row: dict[str, Any], *, include_script: bool = True) -> dict[str, Any]:
    meta = infer_case_metadata(row)
    hero, imgs, vids = _home_intro_case_media(row)
    sid = int(row.get("source_item_id") or 0)
    slug = str(row.get("seo_slug") or "").strip()
    out = {
        "content_id": int(row.get("content_id") or 0),
        "source_item_id": sid,
        "title": _home_intro_case_title(row),
        "source_name": _social_text(row.get("source_name") or "", limit=36) or "原站",
        "region": _social_text(
            row.get("case_jp_region_override") or meta.get("jp_region_display_zh") or "",
            limit=48,
        ),
        "transit": _social_text(row.get("case_transit_override") or meta.get("transit_line_zh") or "", limit=90),
        "price_hint": _home_intro_case_price_hint(row),
        "thumb_url": hero,
        "hero_media_url": hero,
        "image_count": len(imgs),
        "video_count": len(vids),
        "article_path": _standard_article_path(slug, sid),
        "case_path": _standard_case_path(sid),
        "updated_at": str(row.get("updated_at") or ""),
    }
    if include_script:
        out["script_text"] = _home_intro_case_video_script(row)
    return out


_HOME_FEATURED_HOT_REGIONS = (
    "東京",
    "大阪",
    "京都",
    "福岡",
    "神奈川",
    "北海道",
    "名古屋",
    "沖縄",
    "沖繩",
)


def _home_featured_has_kana(text: Any) -> bool:
    return _portal_case_has_kana(text)


_HOME_FEATURED_T2S = OpenCC("t2s")


def _home_featured_to_hans(value: Any) -> str:
    text = str(value or "").strip()
    if not text:
        return ""
    try:
        return _HOME_FEATURED_T2S.convert(text)
    except Exception:
        return text


def _home_featured_source_label(value: Any) -> str:
    raw = _home_featured_to_hans(value)
    low = raw.lower()
    if "athome" in low or "アットホーム" in raw or "at home" in low:
        return "AtHome"
    if "lifull" in low or "homes" in low or "ホームズ" in raw:
        return "LIFULL HOME'S"
    if "suumo" in low or "スーモ" in raw:
        return "SUUMO"
    if "yahoo" in low:
        return "Yahoo! 不动产"
    if "rakuten" in low or "楽天" in raw:
        return "乐天"
    if "yes" in low or "oh" in low:
        return "OHEYASU"
    return _home_featured_to_hans(_social_text(raw, limit=24)) or "原站"


def _home_featured_region_label(value: Any) -> str:
    text = _home_featured_to_hans(_social_text(value or "", limit=30))
    if not text or text.strip().lower() in {"tw", "jp", "hant", "hans", "zh", "cn", "hk", "mo"}:
        return ""
    return (
        text.replace("沖縄", "冲绳")
        .replace("沖繩", "冲绳")
        .replace("福岡", "福冈")
        .replace("九州、冲绳", "九州、冲绳")
        .replace("九州、沖繩", "九州、冲绳")
        .replace("東京", "東京")
        .strip()
    )


def _home_featured_clean_listing_text(value: Any, *, fallback: Any = "", max_len: int = 160) -> str:
    text = _portal_case_text_hant(value, max_len=max_len)
    if not text or _portal_case_has_kana(text):
        text = _portal_case_text_hant(fallback, max_len=max_len)
    if _portal_case_has_kana(text):
        text = ""
    return _home_featured_to_hans(text)


def _home_featured_region_from_row(row: dict[str, Any]) -> str:
    direct = _home_featured_region_label(row.get("case_jp_region_override") or "")
    if direct:
        return direct
    blob = " ".join(
        str(row.get(k) or "")
        for k in ("seo_title", "title_zh_hant", "title_zh_hans", "title_original", "seo_description")
    )
    pref = re.search(
        r"(北海道|東京都|大阪府|京都府|(?:青森|岩手|宮城|秋田|山形|福島|茨城|栃木|群馬|埼玉|千葉|神奈川|新潟|富山|石川|福井|山梨|長野|岐阜|静岡|愛知|三重|滋賀|兵庫|奈良|和歌山|鳥取|島根|岡山|広島|山口|徳島|香川|愛媛|高知|福岡|佐賀|長崎|熊本|大分|宮崎|鹿児島|沖縄)県)",
        blob,
    )
    if pref:
        return _home_featured_region_label(pref.group(1))
    city = re.search(r"([一-龥々]{2,8}市)", blob)
    if city:
        return _home_featured_region_label(city.group(1))
    return ""


def _home_featured_price_label(value: Any) -> str:
    text = _home_featured_to_hans(_social_text(value or "", limit=32))
    if not text:
        return ""
    return (
        text.replace("万円", "万日圆")
        .replace("万円", "万日圆")
        .replace("萬", "万")
        .replace("日圓", "日圆")
        .replace("円", "日圆")
        .replace("日圆日圆", "日圆")
        .replace("万日圆日圆", "万日圆")
    )


def _home_featured_type_label(blob: str) -> str:
    if re.search(r"一戸建|戶建|独立|獨立|住宅", blob, re.I):
        return "住宅"
    if re.search(r"賃貸|出租|租", blob, re.I):
        return "租赁房源"
    if re.search(r"新築|新建|新房", blob, re.I):
        return "新建公寓"
    if re.search(r"中古|二手", blob, re.I):
        return "二手公寓"
    if re.search(r"公寓|マンション", blob, re.I):
        return "公寓"
    return "房源"


def _home_featured_transit_label(value: Any) -> str:
    text = re.sub(r"\s+", " ", str(value or "").strip())
    if not text:
        return ""
    walk = re.search(r"(?:徒歩|步行|歩行)\s*約?\s*([0-9]{1,2})\s*分", text)
    if walk:
        return f"步行约 {walk.group(1)} 分钟到车站"
    if _home_featured_has_kana(text):
        return "交通信息可在站内明细确认"
    return _home_featured_to_hans(_social_text(text.replace(">", "、"), limit=54))


def _home_featured_display_title(row: dict[str, Any], base_title: str, region: str) -> str:
    blob = " ".join(
        str(row.get(k) or "")
        for k in ("seo_title", "seo_description", "title_zh_hant", "title_original", "body_zh_hant", "body_original")
    )
    preferred = str(row.get("title_zh_hans") or base_title or "").strip()
    title = re.sub(r"^(?:日本房产案源|日本房產案源|日本不动产案件|日本不動產案件|日本房源)[:：]\s*", "", preferred)
    title = re.sub(r"^(?:\[?在家\]?|AtHome|LIFULL HOME'?S|SUUMO)\s*[:：|]?\s*", "", title, flags=re.I)
    title = _home_featured_to_hans(_social_text(title, limit=44))
    bad_title = re.search(r"(?:javascript\s*(?:is disabled|被禁用|已禁用)|需要\s*javascript|浏览器.{0,8}不支持)", title, re.I)
    if (
        title
        and not bad_title
        and not _home_featured_has_kana(title)
        and len(title) <= 42
        and not re.match(r"^(?:tw|jp|cn|hk|mo)(?:精选|公寓|大楼|华厦|别墅|土地|店面|办公|套房)", title, re.I)
    ):
        return title
    place = _home_featured_region_label(region) or "日本"
    return f"{place}精选{_home_featured_type_label(blob)}"


def _home_featured_primary_type_label(property_hits: list[str] | set[str], blob: str = "") -> str:
    labels = {
        "大樓": "大楼",
        "華廈": "华厦",
        "別墅/透天": "别墅透天",
        "辦公": "办公",
        "單售車位": "车位",
        "廠房": "厂房",
        "倉庫": "仓库",
    }
    for key in ("土地", "店面", "辦公", "別墅/透天", "套房", "大樓", "華廈", "公寓", "廠房", "倉庫", "單售車位"):
        if key in set(property_hits or []):
            return labels.get(key, key)
    return _home_featured_type_label(blob)


def _home_featured_specific_title(
    row: dict[str, Any],
    fields: dict[str, Any],
    *,
    current_title: str,
    region: str,
    price_hint: str,
    property_hits: list[str] | set[str],
) -> str:
    """Build a distinct Chinese card title when source titles are too generic.

    Many crawled listings only expose Japanese source titles. The homepage should
    not show repeated fallback labels like "福冈精选住宅" across different tabs, so
    use buyer-facing facts that are already parsed for the listing.
    """
    blob = " ".join(
        str(row.get(k) or "")
        for k in ("seo_title", "seo_description", "title_zh_hant", "title_original", "body_zh_hant", "body_original")
    )
    title = _home_featured_to_hans(str(current_title or "").strip())
    generic = (not title) or bool(re.search(r"精选(?:住宅|房源|公寓|租赁房源|二手公寓|新建公寓)$", title))
    if title and not generic and not _home_featured_has_kana(title):
        return _social_text(title, limit=34)

    region_label = _home_featured_region_label(region) or "日本"
    type_label = _home_featured_primary_type_label(property_hits, blob)
    price = _home_featured_price_label(price_hint)
    layout = _home_featured_to_hans(str(fields.get("layout_text_hant") or row.get("layout_text_hant") or "").strip())
    area = _home_featured_to_hans(
        str(
            fields.get("area_text_hant")
            or fields.get("exclusive_area_jp")
            or fields.get("building_area_jp")
            or fields.get("land_area_jp")
            or row.get("area_text_hant")
            or ""
        ).strip()
    )
    transit = _home_featured_transit_label(row.get("case_transit_override") or "")
    fact_parts = [x for x in (price, layout, area, transit) if x]
    if fact_parts:
        return _social_text(f"{region_label}{type_label}｜{'｜'.join(fact_parts[:2])}", limit=36)
    return _social_text(f"{region_label}精选{type_label}", limit=34)


def _home_featured_case_summary(row: dict[str, Any], meta: dict[str, Any], price_hint: str, image_count: int) -> str:
    region = _social_text(
        row.get("case_jp_region_override") or meta.get("jp_region_display_zh") or "",
        limit=24,
    )
    region = _home_featured_region_label(region)
    transit = _home_featured_transit_label(row.get("case_transit_override") or meta.get("transit_line_zh") or "")
    price_hint = _home_featured_price_label(price_hint)
    body = re.sub(
        r"\s+",
        " ",
        str(row.get("seo_description") or row.get("body_zh_hant") or row.get("body_original") or "").strip(),
    )
    parts: list[str] = []
    if region:
        parts.append(f"{region}区域")
    if price_hint:
        parts.append(f"价格约 {price_hint}")
    if transit:
        parts.append(f"交通：{transit}")
    if image_count > 1:
        parts.append(f"含 {image_count} 张参考图")
    if not parts and body:
        return _home_featured_to_hans(_social_text(body, limit=74))
    return _home_featured_to_hans(_social_text("，".join(parts) or "可查看站内明细与原站资料。", limit=90))


def _home_featured_case_tags(row: dict[str, Any], meta: dict[str, Any], image_count: int, price_hint: str) -> list[str]:
    blob = " ".join(
        str(row.get(k) or "")
        for k in (
            "seo_title",
            "seo_description",
            "title_zh_hant",
            "title_original",
            "body_zh_hant",
            "body_original",
            "case_jp_region_override",
            "case_transit_override",
        )
    )
    tags: list[str] = []
    transit = str(row.get("case_transit_override") or meta.get("transit_line_zh") or "")
    if re.search(r"新築|新建|新房|公寓|マンション", blob, re.I):
        tags.append("新建公寓")
    if re.search(r"投資|出租|收租|賃貸|租", blob, re.I):
        tags.append("投资出租")
    if re.search(r"自住|住宅|住居|生活", blob, re.I):
        tags.append("自住推荐")
    if re.search(r"徒歩|步行|駅|車站|站", transit or blob, re.I):
        tags.append("近站通勤")
    if not tags:
        tags.append("精选房源")
    out: list[str] = []
    for tag in tags:
        if tag not in out:
            out.append(tag)
    return out[:4]


def _home_featured_smart_type_item(row: dict[str, Any]) -> dict[str, Any]:
    return {
        "building_type_zh": row.get("building_type_zh") or row.get("case_transaction_override") or "",
        "layout_text_hant": row.get("layout_text_hant") or row.get("seo_description") or "",
        "layout_line_jp": row.get("layout_line_jp") or "",
        "title_zh_hant": row.get("title_zh_hant") or "",
        "title_zh_hans": row.get("title_zh_hans") or "",
        "title_original": row.get("title_original") or "",
        "snippet_jp": row.get("body_original") or "",
        "body_zh_hant_preview": row.get("body_zh_hant") or "",
        "body_zh_hans_preview": row.get("body_zh_hans") or "",
        "topic_category": row.get("topic_category") or "",
        "item_url": row.get("item_url") or "",
    }


def _home_featured_property_type_hits(row: dict[str, Any]) -> set[str]:
    """Return a tighter, display-oriented primary type for homepage tabs.

    The general smart-query matcher intentionally uses broad text matching. For
    the homepage tab carousel that makes apartment-like listings match 公寓/大樓/華廈
    at the same time, so every tab can look identical. This classifier prefers
    structured fields and short title/type text, then assigns broad mansion
    listings to one stable bucket so each tab returns a visibly different set.
    """
    sid = int(row.get("source_item_id") or row.get("id") or 0)
    structured = unicodedata.normalize(
        "NFKC",
        " ".join(
            str(x or "")
            for x in (
                row.get("building_type_zh"),
                row.get("topic_category"),
                row.get("case_transaction_override"),
            )
        ),
    ).lower()
    title_text = unicodedata.normalize(
        "NFKC",
        " ".join(
            str(x or "")
            for x in (
                row.get("title_zh_hant"),
                row.get("title_zh_hans"),
                row.get("title_original"),
                row.get("seo_title"),
            )
        ),
    ).lower()
    layout_text = unicodedata.normalize(
        "NFKC",
        " ".join(str(x or "") for x in (row.get("layout_text_hant"), row.get("layout_line_jp"), row.get("seo_description"))),
    ).lower()
    extended_detail_text = unicodedata.normalize(
        "NFKC",
        " ".join(
            str(x or "")
            for x in (
                row.get("layout_text_hant"),
                row.get("layout_line_jp"),
                row.get("seo_description"),
                row.get("body_zh_hant"),
                row.get("body_zh_hans"),
                row.get("body_original"),
            )
        ),
    ).lower()
    url_text = unicodedata.normalize("NFKC", str(row.get("item_url") or "")).lower()
    focused = f"{structured} {title_text} {layout_text} {url_text}"
    stable_bucket = sid % 3 if sid else int(hashlib.md5(title_text.encode("utf-8")).hexdigest()[:8], 16) % 3

    if any(t in focused for t in ("土地", "売地", "tochi", "land")):
        return {"土地"}
    if any(t in focused for t in ("單售車位", "車位", "駐車", "駐車場", "parking", "garage")):
        return {"單售車位"}
    if any(t in focused for t in ("廠房", "工場", "factory", "plant")):
        return {"廠房"}
    if any(t in focused for t in ("倉庫", "warehouse", "souko")):
        return {"倉庫"}
    if any(t in focused for t in ("店面", "店舗", "テナント", "shop", "store")):
        return {"店面"}
    if any(t in focused for t in ("辦公", "事務所", "オフィス", "office")):
        return {"辦公"}
    if any(
        t in focused
        for t in ("別墅", "透天", "一戶建", "一戸建", "戸建", "detached", "villa", "中古一戸建て", "新築一戸建て")
    ):
        return {"別墅/透天"}
    if any(
        t in extended_detail_text
        for t in (
            "套房",
            "ワンルーム",
            "1r",
            "1k",
            "1dk",
            "1ldk",
            "1room",
            "studio",
            "コンパクト",
            "単身",
            "單身",
            "单身",
            "小戶型",
            "小户型",
        )
    ):
        return {"套房"}

    if "華廈" in focused:
        return {"華廈"}
    if "大樓" in focused:
        return {"大樓"}
    if any(t in focused for t in ("公寓", "アパート", "apartment")):
        return {"公寓"}
    if any(t in focused for t in ("マンション", "mansion", "中古マンション", "新築マンション")):
        return ({"公寓"}, {"大樓"}, {"華廈"})[stable_bucket]

    broad_hits = _smart_property_type_hits(_home_featured_smart_type_item(row))
    apartment_like = {"公寓", "大樓", "華廈"}
    if broad_hits and broad_hits <= apartment_like:
        return ({"公寓"}, {"大樓"}, {"華廈"})[stable_bucket]
    return broad_hits


def _home_featured_matches_property_type(row: dict[str, Any], property_type: str) -> bool:
    selected = _normalize_smart_property_types([property_type])
    if not selected:
        return True
    hits = _home_featured_property_type_hits(row)
    if "其他" in selected and (not hits or bool(hits & {"單售車位", "廠房", "倉庫"})):
        return True
    return any(t != "其他" and t in hits for t in selected)


def _home_featured_property_type_search_terms(property_type: str) -> tuple[str, ...]:
    normalized = _normalize_smart_property_types([property_type])
    if not normalized:
        return ()
    if any(t in normalized for t in ("公寓", "大樓", "華廈")):
        return ("公寓", "大樓", "華廈", "マンション", "mansion", "アパート", "apartment", "新築マンション", "中古マンション")
    if "套房" in normalized:
        return (
            "套房",
            "ワンルーム",
            "1R",
            "1K",
            "1DK",
            "1LDK",
            "1ROOM",
            "studio",
            "コンパクト",
            "単身",
            "單身",
            "单身",
            "小戶型",
            "小户型",
            "1房",
        )
    if "辦公" in normalized:
        return ("辦公", "办公", "事務所", "オフィス", "office")
    if "店面" in normalized:
        return ("店面", "店舗", "テナント", "shop", "store")
    if "土地" in normalized:
        return ("土地", "売地", "tochi", "land")
    if "別墅/透天" in normalized:
        return ("別墅", "透天", "一戶建", "一戸建", "戸建", "detached", "villa", "中古一戸建て", "新築一戸建て")
    return ()


def _home_featured_fast_cached_gallery_urls(
    raw_urls: list[Any],
    *,
    limit: int = 8,
    context: str = "",
    profile: str = "building",
) -> list[str]:
    """Return already cached static images without remote IO or visual scanning."""
    lim = max(1, min(int(limit or 8), 24))
    raw_candidates = [
        str(u or "").strip()
        for u in raw_urls
        if _case_representative_raw_url_allowed(u, context, profile=profile)
    ]
    candidates = _sort_relevant_real_estate_images(raw_candidates, limit=max(lim * 2, 12), profile=profile)
    out: list[str] = []
    seen: set[str] = set()
    for raw in candidates:
        cached = _case_image_cached_static_url(raw)
        if not cached or cached in seen:
            continue
        if not _url_to_local_static_path(cached):
            continue
        if _case_image_visual_reject_reason(cached):
            continue
        seen.add(cached)
        out.append(cached)
        if len(out) >= lim:
            break
    return out


_HOME_FEATURED_REGION_KEYWORD_ALIASES: tuple[tuple[tuple[str, ...], tuple[str, ...]], ...] = (
    (("東京", "东京"), ("東京都", "东京都")),
    (("大阪",), ("大阪", "大阪府")),
    (("京都",), ("京都", "京都府")),
    (("福岡", "福冈"), ("福岡", "福冈", "福岡県")),
    (("北海道",), ("北海道", "札幌")),
    (("沖縄", "沖繩", "冲绳"), ("沖縄", "沖繩", "冲绳", "沖縄県")),
    (("名古屋",), ("名古屋", "愛知", "爱知", "愛知県")),
    (("橫濱", "横滨"), ("横浜", "橫濱", "横滨", "神奈川")),
    (("札幌",), ("札幌", "北海道")),
    (("神戶", "神户"), ("神戸", "神戶", "神户", "兵庫", "兵库")),
)


def _home_featured_keyword_region_terms(value: str) -> tuple[str, ...]:
    raw = _home_featured_to_hans(str(value or "").strip())
    compact = re.sub(r"\s+", "", raw).lower()
    out: list[str] = []
    seen: set[str] = set()
    for needles, terms in _HOME_FEATURED_REGION_KEYWORD_ALIASES:
        if not any(n.lower() in compact for n in needles):
            continue
        for term in terms:
            if term and term not in seen:
                seen.add(term)
                out.append(term)
    return tuple(out)


def _home_featured_keyword_search_terms(value: str) -> tuple[str, ...]:
    """Expand title-bar human keywords into terms that exist in listing rows."""
    raw = _home_featured_to_hans(str(value or "").strip())
    if not raw:
        return ()
    compact = re.sub(r"\s+", "", raw).lower()
    compact = (
        compact.replace("不动产", "")
        .replace("房地产", "")
        .replace("房产", "")
        .replace("房源", "")
        .replace("物件", "")
        .replace("找房", "")
        .replace("查询", "")
        .replace("搜尋", "")
        .replace("搜索", "")
        .replace("日本", "")
    )
    groups: list[tuple[str, ...]] = []
    for needles, terms in _HOME_FEATURED_REGION_KEYWORD_ALIASES:
        if any(n.lower() in compact for n in needles):
            groups.append(terms)
    if any(x in compact for x in ("投资", "投資", "收租", "出租", "租")):
        groups.append(("投資", "投资", "収益", "收租", "賃貸", "出租"))
    if any(x in compact for x in ("自住", "自用", "生活")):
        groups.append(("住宅", "住居", "マンション", "一戸建"))
    if any(x in compact for x in ("新建", "新築", "新房")):
        groups.append(("新築", "新建", "新築マンション", "新築一戸建て"))
    if any(x in compact for x in ("中古", "二手")):
        groups.append(("中古", "中古マンション", "中古一戸建て"))
    if any(x in compact for x in ("一户建", "一戶建", "透天", "别墅", "別墅")):
        groups.append(("一戸建", "戸建", "一戶建", "一户建", "透天", "別墅", "别墅"))
    if any(x in compact for x in ("公寓", "大楼", "大樓", "华厦", "華廈")):
        groups.append(("マンション", "公寓", "アパート", "mansion"))
    if any(x in compact for x in ("车站", "車站", "站", "徒步", "步行", "周边", "周邊")):
        groups.append(("駅", "站", "徒歩", "步行", "交通"))
    if any(x in compact for x in ("价格", "價格", "预算", "預算", "筛选", "篩選")):
        groups.append(("万円", "万日圆", "価格", "价格", "價格"))
    if any(x in compact for x in ("远端", "遠端", "看房", "比较", "比較")):
        groups.append(("マンション", "一戸建", "住宅", "公寓"))
    cleaned = compact.strip()
    if cleaned and len(cleaned) >= 2:
        groups.append((cleaned,))
    seen: set[str] = set()
    out: list[str] = []
    for group in groups:
        for term in group:
            t = str(term or "").strip()
            if not t or t in seen:
                continue
            seen.add(t)
            out.append(t)
    return tuple(out[:18])


def _home_featured_case_public_row(row: dict[str, Any], *, sync_static: bool = True) -> dict[str, Any]:
    meta = infer_case_metadata(row)
    try:
        fields = _extract_listing_fields(row, meta=meta)
    except Exception:
        fields = {}
    base = _home_intro_case_public_row(row, include_script=False)
    _hero, imgs, _vids = _home_intro_case_media(row)
    primary_imgs = _row_primary_image_url_lines(row, limit=12)
    raw_gallery_candidates = [
        *imgs,
        *primary_imgs,
        str(base.get("thumb_url") or "").strip(),
    ]
    rep_context = _case_representative_context_text(row)
    rep_profile = _case_representative_profile(row, context=rep_context)
    if sync_static:
        stored_gallery = _case_stored_representative_media(row, raw_gallery_candidates, limit=4)
        gallery = stored_gallery[:]
        if not gallery:
            gallery = _home_featured_fast_cached_gallery_urls(
                [*raw_gallery_candidates, *imgs],
                limit=8,
                context=rep_context,
                profile=rep_profile,
            )
    else:
        gallery = _home_featured_fast_cached_gallery_urls(
            [*raw_gallery_candidates, *imgs],
            limit=8,
            context=rep_context,
            profile=rep_profile,
        )
    thumb = str(base.get("thumb_url") or "").strip()
    if gallery:
        thumb = gallery[0]
    image_count = max(int(base.get("image_count") or 0), len(gallery))
    price_hint = _home_featured_price_label(base.get("price_hint") or "")
    summary = _home_featured_case_summary(row, meta, price_hint, image_count)
    tags = _home_featured_case_tags(row, meta, image_count, price_hint)
    property_hits = sorted(_home_featured_property_type_hits(row))
    region = _home_featured_region_label(base.get("region") or "")
    title = _home_featured_display_title(row, str(base.get("title") or ""), region)
    title = _home_featured_specific_title(
        row,
        fields,
        current_title=title,
        region=region,
        price_hint=price_hint,
        property_hits=property_hits,
    )
    transit = _home_featured_transit_label(base.get("transit") or "")
    source_name = _home_featured_source_label(
        " ".join(
            str(x or "")
            for x in (base.get("source_name"), row.get("source_name"), row.get("item_url"), row.get("title_original"))
        )
    )
    sid = int(base.get("source_item_id") or row.get("source_item_id") or 0)
    return {
        **base,
        "source_item_id": sid,
        "title": title,
        "title_zh_hant": title,
        "title_zh_hans": title,
        # Public card payloads must not expose the crawler's raw Japanese
        # title.  Keep that source field in the database only.
        "title_original": title,
        "source_name": source_name,
        "region": region,
        "jp_region_display_zh": region,
        "transit": transit,
        "transit_line_zh": transit,
        "address_hint_zh": _home_featured_clean_listing_text(
            fields.get("address_hint_zh")
            or fields.get("address_line_hant")
            or fields.get("address_line_jp")
            or row.get("address_hint_zh")
            or "",
            fallback=region,
            max_len=160,
        ),
        "address_line_jp": _home_featured_clean_listing_text(
            fields.get("address_line_jp") or row.get("address_line_jp") or "",
            fallback=region,
            max_len=160,
        ),
        "price_hint": price_hint,
        "price_text_hant": price_hint,
        "area_text_hant": str(fields.get("area_text_hant") or row.get("area_text_hant") or "").strip()[:80],
        "exclusive_area_jp": str(fields.get("exclusive_area_jp") or row.get("exclusive_area_jp") or "").strip()[:120],
        "other_area_jp": str(fields.get("other_area_jp") or row.get("other_area_jp") or "").strip()[:120],
        "building_area_jp": str(fields.get("building_area_jp") or row.get("building_area_jp") or "").strip()[:80],
        "land_area_jp": str(fields.get("land_area_jp") or row.get("land_area_jp") or "").strip()[:80],
        "layout_text_hant": str(fields.get("layout_text_hant") or row.get("layout_text_hant") or "").strip()[:80],
        "thumb_url": thumb,
        "hero_media_url": thumb,
        "gallery_urls": gallery[:8],
        "image_count": image_count,
        "case_path": _standard_case_path(sid),
        "article_path": str(base.get("article_path") or ""),
        "article_url": str(base.get("article_path") or ""),
        "item_url": str(row.get("item_url") or ""),
        "summary": summary,
        "theme_tags": tags,
        "property_type_hits": property_hits,
    }


def _home_featured_case_public_row_fast(
    row: dict[str, Any],
    *,
    sync_static: bool = True,
    fast_cached_media: bool = True,
) -> dict[str, Any]:
    try:
        meta = infer_case_metadata(row)
    except Exception:
        meta = {}
    try:
        fields = _extract_listing_fields(row, meta=meta)
    except Exception:
        fields = {}
    imgs, _vids = extract_media_urls_from_row(row)
    primary_imgs = _row_primary_image_url_lines(row, limit=12)
    raw_gallery_candidates = [
        *imgs,
        *primary_imgs,
        str(row.get("hero_image_url") or "").strip(),
        str(row.get("thumbnail_url") or "").strip(),
    ]
    rep_context = _case_representative_context_text(row)
    rep_profile = _case_representative_profile(row, context=rep_context)
    if sync_static:
        stored_gallery = _case_stored_representative_media(row, raw_gallery_candidates, limit=4)
        gallery = stored_gallery[:]
        if not gallery:
            gallery = _home_featured_fast_cached_gallery_urls(
                [*raw_gallery_candidates, *imgs],
                limit=8,
                context=rep_context,
                profile=rep_profile,
            )
    elif fast_cached_media:
        gallery = _home_featured_fast_cached_gallery_urls(
            [*raw_gallery_candidates, *imgs],
            limit=8,
            context=rep_context,
            profile=rep_profile,
        )
    else:
        gallery = []
    hero = gallery[0] if gallery else ""
    sid = int(row.get("source_item_id") or 0)
    slug = str(row.get("seo_slug") or "").strip()
    image_count = len(gallery)
    price_hint = _home_featured_price_label(_home_intro_case_price_hint(row))
    property_hits = sorted(_home_featured_property_type_hits(row))
    region = _home_featured_region_from_row(row)
    title = _home_featured_specific_title(
        row,
        {},
        current_title=_home_featured_display_title(row, str(row.get("seo_title") or ""), region),
        region=region,
        price_hint=price_hint,
        property_hits=property_hits,
    )
    transit = _home_featured_transit_label(row.get("case_transit_override") or "")
    source_name = _home_featured_source_label(
        " ".join(str(x or "") for x in (row.get("source_name"), row.get("item_url"), row.get("title_original")))
    )
    summary = _home_featured_case_summary(row, fields, price_hint, image_count)
    tags = _home_featured_case_tags(row, fields, image_count, price_hint)
    return {
        "content_id": int(row.get("content_id") or 0),
        "source_item_id": sid,
        "title": title,
        "title_zh_hant": title,
        "title_zh_hans": title,
        "title_original": title,
        "source_name": source_name,
        "region": region,
        "jp_region_display_zh": region,
        "transit": transit,
        "transit_line_zh": transit,
        "address_hint_zh": _home_featured_clean_listing_text(
            fields.get("address_hint_zh")
            or fields.get("address_line_hant")
            or fields.get("address_line_jp")
            or "",
            fallback=region,
            max_len=160,
        ),
        "address_line_jp": _home_featured_clean_listing_text(
            fields.get("address_line_jp") or "",
            fallback=region,
            max_len=160,
        ),
        "price_hint": price_hint,
        "price_text_hant": price_hint,
        "area_text_hant": str(fields.get("area_text_hant") or "").strip()[:80],
        "exclusive_area_jp": str(fields.get("exclusive_area_jp") or "").strip()[:120],
        "other_area_jp": str(fields.get("other_area_jp") or "").strip()[:120],
        "building_area_jp": str(fields.get("building_area_jp") or "").strip()[:80],
        "land_area_jp": str(fields.get("land_area_jp") or "").strip()[:80],
        "layout_text_hant": str(fields.get("layout_text_hant") or row.get("layout_text_hant") or "").strip()[:80],
        "building_type_zh": str(fields.get("building_type_zh") or "").strip()[:80],
        "thumb_url": hero,
        "hero_media_url": hero,
        "gallery_urls": gallery,
        "image_count": image_count,
        "case_path": _standard_case_path(sid),
        "article_path": _standard_article_path(slug, sid),
        "article_url": _standard_article_path(slug, sid),
        "item_url": str(row.get("item_url") or ""),
        "summary": summary,
        "theme_tags": tags,
        "property_type_hits": property_hits,
    }


_HOME_FEATURED_INVALID_PRICE_RE = re.compile(
    r"(?:价格|價格|価格).{0,4}(?:未定|待确认|待確認|未公布|未公开|未公開|未披露)|待确认|待確認|價格待確認|价格待确认",
    re.I,
)


def _home_featured_has_display_image(item: dict[str, Any]) -> bool:
    thumb = str(item.get("thumb_url") or item.get("hero_media_url") or "").strip()
    if thumb.startswith("/static/cache/case-images/") and not _home_featured_static_cache_image_url(thumb):
        return False
    gallery = item.get("gallery_urls") or []
    if isinstance(gallery, str):
        gallery = [gallery]
    gallery_count = 0
    if isinstance(gallery, (list, tuple)):
        gallery_count = len(
            [
                url
                for url in gallery
                if str(url or "").strip()
                and (
                    not str(url or "").strip().startswith("/static/cache/case-images/")
                    or _home_featured_static_cache_image_url(url)
                )
            ]
        )
    return bool(thumb) and max(int(item.get("image_count") or 0), gallery_count) > 0


_HOME_FEATURED_IMAGE_UNSUITABLE_CACHE: dict[str, str] = {}
_HOME_FEATURED_IMAGE_UNSUITABLE_CACHE_MAX = 3000


def _home_featured_image_unsuitable_reason(item: dict[str, Any]) -> str:
    thumb = str(item.get("thumb_url") or item.get("hero_media_url") or "").strip()
    if thumb in _HOME_FEATURED_IMAGE_UNSUITABLE_CACHE:
        return str(_HOME_FEATURED_IMAGE_UNSUITABLE_CACHE.get(thumb) or "")
    path = _url_to_local_static_path(thumb)
    if not path or not path.is_file():
        return ""
    local_issue = _case_gallery_local_quality_issue(thumb)
    if local_issue:
        reason = f"local-quality:{local_issue.get('category') or 'issue'}"
        if len(_HOME_FEATURED_IMAGE_UNSUITABLE_CACHE) >= _HOME_FEATURED_IMAGE_UNSUITABLE_CACHE_MAX:
            _HOME_FEATURED_IMAGE_UNSUITABLE_CACHE.clear()
        _HOME_FEATURED_IMAGE_UNSUITABLE_CACHE[thumb] = reason
        return reason
    try:
        from PIL import Image  # type: ignore
    except ImportError:
        return ""
    try:
        with Image.open(path) as im0:
            sample = im0.convert("RGB").resize((96, 96))
            pixels = list(sample.getdata())
    except Exception:
        return ""
    total = max(1, len(pixels))
    min_x = 96
    min_y = 96
    max_x = -1
    max_y = -1
    content_hits = 0
    for idx, (r, g, b) in enumerate(pixels):
        spread = max(r, g, b) - min(r, g, b)
        blank = (r >= 232 and g >= 232 and b >= 232 and spread <= 26) or (
            r >= 218 and g >= 218 and b >= 218 and spread <= 24
        )
        if blank:
            continue
        x = idx % 96
        y = idx // 96
        content_hits += 1
        min_x = min(min_x, x)
        min_y = min(min_y, y)
        max_x = max(max_x, x)
        max_y = max(max_y, y)
    if content_hits and max_x >= min_x and max_y >= min_y:
        content_ratio = content_hits / total
        box_area = ((max_x - min_x + 1) / 96) * ((max_y - min_y + 1) / 96)
        if box_area <= 0.36 and content_ratio <= 0.34:
            reason = "sparse-main-image"
            if len(_HOME_FEATURED_IMAGE_UNSUITABLE_CACHE) >= _HOME_FEATURED_IMAGE_UNSUITABLE_CACHE_MAX:
                _HOME_FEATURED_IMAGE_UNSUITABLE_CACHE.clear()
            _HOME_FEATURED_IMAGE_UNSUITABLE_CACHE[thumb] = reason
            return reason
    red_ratio = (
        sum(
            1
            for r, g, b in pixels
            if r >= 135 and r > g * 1.35 and r > b * 1.35 and g < 145 and b < 145
        )
        / total
    )
    reason = "facility-or-vending-main-image" if red_ratio >= 0.12 else ""
    if len(_HOME_FEATURED_IMAGE_UNSUITABLE_CACHE) >= _HOME_FEATURED_IMAGE_UNSUITABLE_CACHE_MAX:
        _HOME_FEATURED_IMAGE_UNSUITABLE_CACHE.clear()
    _HOME_FEATURED_IMAGE_UNSUITABLE_CACHE[thumb] = reason
    return reason


def _home_featured_has_display_price(item: dict[str, Any]) -> bool:
    price = str(item.get("price_hint") or item.get("price_text_hant") or "").strip()
    return bool(price) and not _HOME_FEATURED_INVALID_PRICE_RE.search(price)


def _home_featured_supporting_info_score(item: dict[str, Any]) -> int:
    def has_text(*keys: str) -> bool:
        return any(str(item.get(key) or "").strip() not in {"", "—", "-"} for key in keys)

    score = 0
    if has_text("region", "jp_region_display_zh", "address_hint_zh", "address_line_jp"):
        score += 1
    if has_text("transit", "transit_line_zh"):
        score += 1
    if has_text("area_text_hant", "exclusive_area_jp", "building_area_jp", "land_area_jp", "other_area_jp"):
        score += 1
    if has_text("layout_text_hant"):
        score += 1
    if has_text("building_type_zh") or bool(item.get("property_type_hits") or []):
        score += 1
    title = str(item.get("title") or item.get("title_zh_hans") or item.get("title_zh_hant") or "").strip()
    if title and not re.search(r"^(?:日本房源|日本房產|日本房产|日本精选|精选房源|日本優選|日本优选)", title, re.I):
        score += 1
    return score


def _home_featured_item_homepage_eligible(item: dict[str, Any]) -> bool:
    return (
        _home_featured_has_display_image(item)
        and _home_featured_has_display_price(item)
        and not _home_featured_image_unsuitable_reason(item)
        and _home_featured_supporting_info_score(item) >= 2
    )


def _home_featured_items_homepage_eligible(items: Any, *, excluded_ids: set[int] | None = None) -> list[dict[str, Any]]:
    if not isinstance(items, list):
        return []
    excluded = excluded_ids or set()
    out: list[dict[str, Any]] = []
    seen: set[int | str] = set()
    for item in items:
        if not isinstance(item, dict):
            continue
        sid = int(item.get("source_item_id") or 0)
        if sid and sid in excluded:
            continue
        key: int | str = sid or str(item.get("case_path") or item.get("title") or item.get("thumb_url") or "").strip()
        if not key or key in seen:
            continue
        if not _home_featured_item_homepage_eligible(item):
            continue
        seen.add(key)
        out.append(item)
    return out


# Homepage recommendation batches are intentionally stable for a whole day.
# A manual "change batch" request only selects another already-cached offset.
_HOME_FEATURED_CASES_CACHE_TTL_SECONDS = 24 * 60 * 60.0
_HOME_FEATURED_CASES_CACHE_MAX = 80
_HOME_FEATURED_CASES_CACHE_LOCK = threading.RLock()
_HOME_FEATURED_CASES_CACHE: dict[str, tuple[float, dict[str, Any]]] = {}
