def _home_featured_cases_cache_key(
    *,
    limit: int,
    offset: int,
    category: str,
    property_type: str = "",
    region: str = "",
    q: str = "",
    exclude_source_item_ids: tuple[int, ...] = (),
) -> str:
    return json.dumps(
        {
            "media_policy": "representative-v7-yahoo-clean-cover",
            "text_policy": "jp-display-clean-v1",
            "limit": int(limit),
            "offset": int(offset),
            "category": str(category or "hot"),
            "property_type": str(property_type or "").strip(),
            "region": str(region or "").strip(),
            "q": str(q or "").strip(),
            "exclude_source_item_ids": list(exclude_source_item_ids or ()),
        },
        ensure_ascii=False,
        sort_keys=True,
    )


def _home_featured_cases_cache_get(key: str) -> dict[str, Any] | None:
    now = time.time()
    with _HOME_FEATURED_CASES_CACHE_LOCK:
        cached = _HOME_FEATURED_CASES_CACHE.get(key)
        if not cached:
            return None
        ts, payload = cached
        if now - ts > _HOME_FEATURED_CASES_CACHE_TTL_SECONDS:
            _HOME_FEATURED_CASES_CACHE.pop(key, None)
            return None
        return dict(payload, cached=True)


def _home_featured_cases_cache_set(key: str, payload: dict[str, Any]) -> None:
    with _HOME_FEATURED_CASES_CACHE_LOCK:
        if len(_HOME_FEATURED_CASES_CACHE) >= _HOME_FEATURED_CASES_CACHE_MAX:
            oldest_key = min(_HOME_FEATURED_CASES_CACHE.items(), key=lambda item: item[1][0])[0]
            _HOME_FEATURED_CASES_CACHE.pop(oldest_key, None)
        _HOME_FEATURED_CASES_CACHE[key] = (time.time(), dict(payload, cached=False))


def _prewarm_home_titlebar_case_search_cache() -> None:
    for kw in _HOME_TITLEBAR_CASE_KEYWORDS:
        try:
            _home_featured_cases_payload(limit=6, offset=0, category="hot", q=kw)
        except Exception as exc:
            print(f"SCLAW: titlebar keyword prewarm failed kw={kw}: {type(exc).__name__}: {exc}", flush=True)


def _prewarm_home_featured_api_cache() -> None:
    """Warm the public homepage recommendation API after deploy/restart."""
    try:
        bundle = _home_featured_index_preload_bundle_cached_only() or {}
        hot_items = list(((bundle.get("home_featured_preload") or {}).get("items") or []))
        excluded_ids = [
            int(item.get("source_item_id") or 0)
            for item in hot_items[:12]
            if isinstance(item, dict) and int(item.get("source_item_id") or 0) > 0
        ]
        offsets = (0, 12, 24, 36, 48, 60, 72)
        for off in offsets:
            _home_featured_cases_payload_merged(limit=12, offset=off, category="hot", max_rounds=10)
        if excluded_ids:
            _home_featured_cases_payload_merged(
                limit=12,
                offset=0,
                category="hot",
                max_rounds=10,
                exclude_source_item_ids=excluded_ids,
            )
        print("SCLAW: 首頁綜合推薦 API 快取預熱完成", flush=True)
    except Exception as exc:
        _log_backend_error("home-featured-api-prewarm", exc)


def _home_featured_cases_payload(
    *,
    limit: int = 12,
    offset: int = 0,
    category: str = "hot",
    property_type: str = "",
    region: str = "",
    q: str = "",
    exclude_source_item_ids: Iterable[int] | None = None,
) -> dict[str, Any]:
    lim = max(1, min(24, int(limit or 12)))
    off = max(0, min(50000, int(offset or 0)))
    query_region = str(region or "").strip()
    query_property_type = str(property_type or "").strip()
    query_text = str(q or "").strip()
    query_category = str(category or "hot").strip().lower()
    excluded_source_item_ids = tuple(
        sorted({int(sid) for sid in (exclude_source_item_ids or []) if int(sid or 0) > 0})
    )[:96]
    if query_category not in {"hot", "price", "transit", "image_quality", "investment", "self_use"}:
        query_category = "hot"
    cache_key = _home_featured_cases_cache_key(
        limit=lim,
        offset=off,
        category=query_category,
        property_type=query_property_type,
        region=query_region,
        q=query_text,
        exclude_source_item_ids=excluded_source_item_ids,
    )
    cached = _home_featured_cases_cache_get(cache_key)
    if cached is not None and (cached.get("items") or not cached.get("has_more")):
        return cached
    params: list[Any] = []
    region_sql = ""
    if query_region:
        like = f"%{query_region}%"
        region_sql = """
          AND (
            c.case_jp_region_override LIKE ?
            OR c.seo_title LIKE ?
            OR c.title_zh_hant LIKE ?
            OR s.title_original LIKE ?
          )
        """
        params.extend([like, like, like, like])
    query_sql = ""
    if query_text:
        query_terms = _home_featured_keyword_region_terms(query_text) or _home_featured_keyword_search_terms(query_text) or (query_text,)
        searchable_cols = (
            "c.case_jp_region_override",
            "c.case_transit_override",
            "c.title_zh_hant",
            "c.title_zh_hans",
            "c.seo_description",
        )
        query_clauses: list[str] = []
        for term in query_terms:
            like = f"%{term}%"
            for col in searchable_cols:
                query_clauses.append(f"COALESCE({col}, '') LIKE ?")
                params.append(like)
        if query_clauses:
            query_sql = f" AND ({' OR '.join(query_clauses)}) "
    type_terms = _home_featured_property_type_search_terms(query_property_type)
    type_sql = ""
    if type_terms:
        searchable_cols: tuple[str, ...] = (
            "c.case_transaction_override",
            "c.seo_title",
            "c.title_zh_hant",
            "c.title_zh_hans",
            "c.seo_description",
            "s.title_original",
            "s.item_url",
        )
        if "套房" in _normalize_smart_property_types([query_property_type]):
            searchable_cols = (
                *searchable_cols,
                "c.body_zh_hant",
                "c.body_zh_hans",
                "s.body_original",
            )
        type_clauses: list[str] = []
        for term in type_terms:
            term_like = f"%{term}%"
            for col in searchable_cols:
                type_clauses.append(f"COALESCE({col}, '') LIKE ?")
                params.append(term_like)
        type_sql = f" AND ({' OR '.join(type_clauses)}) "
    exclude_sql = ""
    if excluded_source_item_ids:
        exclude_sql = " AND c.source_item_id NOT IN ({}) ".format(",".join("?" for _ in excluded_source_item_ids))
        params.extend(excluded_source_item_ids)
    if query_text:
        sql_limit = min(220, max(lim * 24, lim + 72))
    else:
        # Static representative images do not help if every refresh still scans
        # hundreds or thousands of listings. Keep cold-path batches bounded; the
        # homepage API now serves common first pages from the preload file when
        # available and falls back here only for sparse/missing ranges.
        sql_limit = min(420 if query_property_type else 360, max(lim * (32 if query_property_type else 24), lim + 96))
    with get_conn() as conn:
        rows = conn.execute(
            f"""
            SELECT
                c.id AS content_id,
                c.source_item_id,
                c.seo_slug,
                c.seo_title,
                c.seo_description,
                c.title_zh_hant,
                c.title_zh_hans,
                substr(COALESCE(c.body_zh_hant, ''), 1, 520) AS body_zh_hant,
                substr(COALESCE(c.body_zh_hans, ''), 1, 520) AS body_zh_hans,
                c.region_code,
                c.keyword_type,
                c.topic_category,
                c.updated_at,
                COALESCE(c.case_transaction_override, '') AS case_transaction_override,
                COALESCE(c.case_jp_region_override, '') AS case_jp_region_override,
                COALESCE(c.case_transit_override, '') AS case_transit_override,
                COALESCE(c.jp_station_id, 0) AS jp_station_id,
                COALESCE(c.walk_min, 0) AS walk_min,
                COALESCE(c.listing_media_json, '[]') AS listing_media_json,
                s.source_name,
                s.item_url,
                s.image_urls,
                substr(COALESCE(s.body_original, ''), 1, 520) AS body_original,
                s.title_original,
                COALESCE(s.thumbnail_url, '') AS thumbnail_url,
                COALESCE(s.hero_image_url, '') AS hero_image_url,
                COALESCE(NULLIF(TRIM(s.content_kind), ''), '') AS content_kind,
                0 AS featured_score
            FROM content_items c
            JOIN source_items s ON s.id = c.source_item_id
            WHERE COALESCE(s.content_kind, '') = 'jp_listing'
              AND TRIM(COALESCE(c.seo_slug, '')) <> ''
              AND (
                TRIM(COALESCE(s.hero_image_url, '')) <> ''
                OR TRIM(COALESCE(s.thumbnail_url, '')) <> ''
                OR TRIM(COALESCE(s.image_urls, '')) <> ''
                OR TRIM(COALESCE(c.listing_media_json, '')) NOT IN ('', '[]')
              )
              {region_sql}
              {query_sql}
              {type_sql}
              {exclude_sql}
            ORDER BY c.updated_at DESC, c.id DESC
            LIMIT ? OFFSET ?
            """,
            [*params, sql_limit, off],
        ).fetchall()
    _case_schedule_representative_selection([dict(row) for row in rows[: min(len(rows), max(lim, 6))]], limit=min(6, lim))
    items: list[dict[str, Any]] = []
    for row in rows:
        row_dict = dict(row)
        title_candidates = [
            str(row_dict.get(k) or "").strip()
            for k in ("seo_title", "title_zh_hant", "title_zh_hans", "title_original")
            if str(row_dict.get(k) or "").strip()
        ]
        bad_title_re = re.compile(
            r"^(?:javascript\s*(?:is disabled|被禁用|已禁用)|需要\s*javascript|浏览器.{0,8}不支持)(?:\s*[｜|-].*)?$",
            re.I,
        )
        if title_candidates and all(bad_title_re.search(t) for t in title_candidates):
            continue
        if query_property_type and not _home_featured_matches_property_type(row_dict, query_property_type):
            continue
        fast_keyword_search = bool(query_text)
        item = _home_featured_case_public_row_fast(
            row_dict,
            sync_static=not fast_keyword_search,
            fast_cached_media=not fast_keyword_search,
        )
        item_title = str(item.get("title") or item.get("title_original") or "").strip()
        if not item_title or re.search(
            r"(?:認證|认证|整理|更新).{0,8}(?:進行中|进行中|待確認|待确认)|javascript\s*(?:is disabled|被禁用|已禁用)|需要\s*javascript|浏览器.{0,8}不支持",
            item_title,
            re.I,
        ):
            continue
        if not _home_featured_item_homepage_eligible(item):
            continue
        items.append(item)
        if len(items) >= lim:
            break
    payload = {
        "ok": True,
        "items": items,
        "limit": lim,
        "offset": off,
        "next_offset": off + len(rows),
        "has_more": len(rows) >= sql_limit,
        "category": query_category,
        "property_type": query_property_type,
        "region": query_region,
        "q": query_text,
        "excluded_source_item_ids": list(excluded_source_item_ids),
        "cached": False,
    }
    _home_featured_cases_cache_set(cache_key, payload)
    return payload


def _home_featured_cases_payload_merged(
    *,
    limit: int = 12,
    offset: int = 0,
    category: str = "hot",
    property_type: str = "",
    region: str = "",
    q: str = "",
    max_rounds: int = 6,
    exclude_source_item_ids: Iterable[int] | None = None,
) -> dict[str, Any]:
    """Backfill sparse featured batches so homepage sections do not render half-empty."""
    target = max(1, min(24, int(limit or 12)))
    next_offset = max(0, int(offset or 0))
    merged: list[dict[str, Any]] = []
    seen: set[int | str] = set()
    last_payload: dict[str, Any] | None = None
    last_offset = -1
    for _ in range(max(1, min(12, int(max_rounds or 1)))):
        if len(merged) >= target or next_offset == last_offset:
            break
        last_offset = next_offset
        payload = _home_featured_cases_payload(
            limit=target,
            offset=next_offset,
            category=category,
            property_type=property_type,
            region=region,
            q=q,
            exclude_source_item_ids=exclude_source_item_ids,
        )
        last_payload = payload
        items = list(payload.get("items") or [])
        for item in items:
            key: int | str = int(item.get("source_item_id") or 0) or str(item.get("case_path") or item.get("title") or "")
            if not key or key in seen:
                continue
            seen.add(key)
            merged.append(item)
            if len(merged) >= target:
                break
        candidate_offset = int(payload.get("next_offset") or 0)
        next_offset = candidate_offset if candidate_offset > next_offset else next_offset + max(target, len(items), 1)
        if payload.get("has_more") is False:
            break
    return {
        **(last_payload or {}),
        "ok": True,
        "items": merged[:target],
        "limit": target,
        "offset": max(0, int(offset or 0)),
        "next_offset": next_offset,
        "has_more": bool(last_payload and last_payload.get("has_more") is not False),
        "property_type": property_type,
        "region": region,
        "q": q,
    }


