def _start_phone_login_followup_recovery_worker() -> None:
    def _worker() -> None:
        time.sleep(2.0)
        while True:
            try:
                _recover_pending_phone_login_followups_once(limit=12)
            except Exception as exc:
                _log_backend_error("phone-login-followup-recovery", exc)
            time.sleep(45.0)

    try:
        threading.Thread(target=_worker, daemon=True, name="phone-login-followup-recovery").start()
    except Exception as exc:
        _log_backend_error("phone-login-followup-recovery-start", exc)


@app.on_event("startup")
def startup_event() -> None:
    init_db()
    _seed_offline_support_scenarios_if_empty()
    _seed_support_qa_training_if_empty()
    _start_phone_login_followup_recovery_worker()
    _start_cache_maintenance_worker()
    # 重要：多進程（例如 uvicorn --workers / WEB_CONCURRENCY）下，startup 會在每個 worker 執行一次。
    # 站內的排程型背景工作（FAQ refresh / smart-nav intel）若不加控管，會造成重複執行、額外寫入與鎖表等待，
    # 影響「搜尋穩定」與 DB 壓力。正式環境建議改由外部排程（scripts/run_daily.ps1 等）運行。
    bg = (os.getenv("SCLAW_ENABLE_BACKGROUND_WORKERS") or "").strip().lower()
    bg_enabled = bg in ("1", "true", "yes", "on")
    if bg_enabled:
        _start_faq_refresh_worker()
        _start_smart_nav_intel_worker()
        _start_portal_image_backfill_worker()
    else:
        print("SCLAW: 背景排程工作已停用（設 SCLAW_ENABLE_BACKGROUND_WORKERS=1 可啟用）", flush=True)
    try:
        _app_file = Path(__file__).resolve()
    except Exception:
        _app_file = Path("app.py")
    print(
        f"SCLAW: FastAPI 已啟動（載入檔案：{_app_file}）。請確認 GET /api/health 或 GET /sclaw-ping 回傳 ok。",
        flush=True,
    )
    if bg_enabled:
        try:
            if start_case_auto_refresh_worker(invalidate_caches=_invalidate_case_data_caches):
                print("SCLAW: 案件自動更新已啟動（啟動後背景抓取最新案件與原站高清圖文）", flush=True)
        except Exception as exc:
            print(f"SCLAW: 案件自動更新啟動失敗：{type(exc).__name__}: {exc}", flush=True)
        try:
            if start_case_quality_batch_worker(invalidate_caches=_invalidate_case_data_caches):
                st = case_quality_batch_status()
                print(
                    "SCLAW: 每日案件品質批次已啟動"
                    f"（台北時間下一次：{st.get('next_run_at_taipei') or '排程中'}）",
                    flush=True,
                )
        except Exception as exc:
            print(f"SCLAW: 每日案件品質批次啟動失敗：{type(exc).__name__}: {exc}", flush=True)
    else:
        print("SCLAW: 案件自動更新與品質批次已停用（由外部排程按需執行）", flush=True)
    try:
        if (os.getenv("SCLAW_COVERAGE_MATRIX_PREWARM") or "0").strip().lower() not in (
            "0",
            "false",
            "no",
            "off",
        ):
            threading.Thread(target=_prewarm_coverage_matrix_cache, daemon=True).start()
        if (os.getenv("SCLAW_INVENTORY_STATS_PREWARM") or "0").strip().lower() not in (
            "0",
            "false",
            "no",
            "off",
        ):
            threading.Thread(target=_prewarm_inventory_stats_cache, daemon=True).start()
        if (os.getenv("SCLAW_PORTAL_TYPE_SEARCH_PREWARM") or "0").strip().lower() not in (
            "0",
            "false",
            "no",
            "off",
        ):
            threading.Thread(
                target=_prewarm_portal_type_case_search_cache,
                daemon=True,
                name="portal-type-case-prewarm",
            ).start()
        if (os.getenv("SCLAW_PORTAL_SEARCH_PREWARM") or "0").strip().lower() not in (
            "0",
            "false",
            "no",
            "off",
        ):
            threading.Thread(target=_prewarm_portal_case_search_cache, daemon=True).start()
            if (os.getenv("SCLAW_PORTAL_SEARCH_PREWARM_LOOP") or "0").strip().lower() not in (
                "0",
                "false",
                "no",
                "off",
            ):
                threading.Thread(target=_portal_case_search_cache_prewarm_loop, daemon=True).start()
        if (os.getenv("SCLAW_HOME_STARTUP_PREWARM") or "0").strip().lower() in (
            "1",
            "true",
            "yes",
            "on",
        ):
            threading.Thread(target=_prewarm_home_titlebar_case_search_cache, daemon=True, name="titlebar-case-prewarm").start()
            threading.Thread(target=_prewarm_home_featured_api_cache, daemon=True, name="home-featured-api-prewarm").start()
            _start_home_featured_thumbnail_prewarm()
            _start_home_featured_detail_prewarm()
    except Exception:
        pass


def _push_backend_error_log(method: str, path: str, status_code: int, message: str, elapsed_ms: int = 0) -> None:
    row = {
        "ts": datetime.utcnow().replace(microsecond=0).isoformat() + "Z",
        "method": str(method or ""),
        "path": str(path or ""),
        "status_code": int(status_code or 0),
        "message": str(message or "")[:400],
        "elapsed_ms": int(elapsed_ms or 0),
    }
    with _backend_log_lock:
        _backend_error_logs.appendleft(row)


def _log_backend_error(scope: str, exc: BaseException | str) -> None:
    """Record non-request background failures without crashing cleanup/fallback paths."""
    if isinstance(exc, BaseException):
        message = f"{type(exc).__name__}: {str(exc)[:360]}"
    else:
        message = str(exc or "")[:400]
    _push_backend_error_log(
        method="BG",
        path=str(scope or "background"),
        status_code=500,
        message=message,
        elapsed_ms=0,
    )


_VISITOR_TRACKING_EXCLUDED_PREFIXES = (
    "/api/",
    "/admin",
    "/static/",
    "/assets/",
    "/favicon",
    "/sclaw-ping",
    "/openapi.json",
    "/docs",
    "/redoc",
)
_VISITOR_TRACKING_EXCLUDED_SUFFIXES = (
    ".css",
    ".js",
    ".map",
    ".png",
    ".jpg",
    ".jpeg",
    ".webp",
    ".gif",
    ".svg",
    ".ico",
    ".mp4",
    ".webm",
    ".mov",
    ".m4v",
    ".mp3",
    ".wav",
    ".woff",
    ".woff2",
    ".ttf",
)
_VISITOR_TZ = timezone(timedelta(hours=8))
KV_VISITOR_TRACKING_URL = "visitor_tracking_url"
KV_VISITOR_MAX_PAGES = "visitor_record_max_pages"


def _normalize_visitor_tracking_path(raw: Any) -> str:
    text = str(raw or "").strip()
    if not text:
        return "/"
    if text.startswith("#"):
        return "/"
    if text.startswith("//"):
        text = "https:" + text
    if re.match(r"^[a-z][a-z0-9+.-]*://", text, re.I):
        parsed = urlparse(text)
        path = unquote(parsed.path or "/")
    else:
        parsed = urlparse(text)
        path = unquote(parsed.path or text)
    path = path.split("#", 1)[0].split("?", 1)[0].strip()
    if not path.startswith("/"):
        path = "/" + path
    path = re.sub(r"/{2,}", "/", path)
    if len(path) > 1:
        path = path.rstrip("/")
    return path[:240] or "/"


def _visitor_tracking_url_raw() -> str:
    return str(get_kv(KV_VISITOR_TRACKING_URL, "/") or "/").strip() or "/"


def _visitor_tracking_path() -> str:
    return _normalize_visitor_tracking_path(_visitor_tracking_url_raw())


def _visitor_max_pages() -> int:
    try:
        value = int(get_kv(KV_VISITOR_MAX_PAGES, "50") or 50)
    except (TypeError, ValueError):
        value = 50
    return max(1, min(500, value))


def _visitor_path_matches(path: Any, tracking_path: str | None = None) -> bool:
    target = _normalize_visitor_tracking_path(tracking_path or _visitor_tracking_path()).lower()
    current = _normalize_visitor_tracking_path(path).lower()
    if target == "/":
        return True
    return current == target or current.startswith(target + "/")


def _visitor_path_where_clause(prefix: str = "") -> tuple[str, list[str]]:
    tracking_path = _visitor_tracking_path()
    column = f"{prefix}.path" if prefix else "path"
    if tracking_path == "/":
        return "", []
    return f" AND ({column} = ? OR {column} LIKE ?)", [tracking_path, tracking_path + "/%"]


def _visitor_human_event_where_clause(prefix: str = "") -> str:
    column = f"{prefix}.device_type" if prefix else "device_type"
    return f" AND COALESCE({column}, 'desktop') != 'bot'"


def _visitor_client_ip(request: Request) -> str:
    for header in ("cf-connecting-ip", "x-real-ip", "x-forwarded-for"):
        raw = str(request.headers.get(header) or "").strip()
        if not raw:
            continue
        first = raw.split(",")[0].strip()
        if first:
            return first[:120]
    return str(getattr(request.client, "host", "") or "").strip()[:120] or "unknown"


def _visitor_ip_hash(ip: str) -> str:
    salt = (os.getenv("SCLAW_VISITOR_HASH_SALT") or SITE_NAME or "sclaw").encode("utf-8", "ignore")
    return hmac.new(salt, str(ip or "unknown").encode("utf-8", "ignore"), hashlib.sha256).hexdigest()


def _visitor_ip_label(ip: str) -> str:
    text = str(ip or "unknown").strip()
    if not text or text == "unknown":
        return "unknown"
    if ":" in text:
        parts = [p for p in text.split(":") if p]
        return ":".join(parts[:3]) + ":*"
    parts = text.split(".")
    if len(parts) == 4:
        return ".".join(parts[:3] + ["*"])
    return text[:24]


_VISITOR_CONFIRMED_BOT_UA_PARTS = (
    "googlebot",
    "adsbot-google",
    "mediapartners-google",
    "bingbot",
    "bingpreview",
    "slurp",
    "duckduckbot",
    "baiduspider",
    "yandexbot",
    "sogou spider",
    "applebot",
    "facebookexternalhit",
    "twitterbot",
    "linkedinbot",
    "pinterestbot",
    "telegrambot",
    "ahrefsbot",
    "semrushbot",
    "mj12bot",
    "dotbot",
    "petalbot",
    "bytespider",
    "ccbot",
    "gptbot",
    "claudebot",
    "perplexitybot",
    "amazonbot",
)
_VISITOR_CONFIRMED_BOT_UA_RE = re.compile(r"(?:crawler|spider|slurp|bingpreview)", re.I)


def _visitor_is_confirmed_bot_user_agent(user_agent: str) -> bool:
    ua = str(user_agent or "").strip().lower()
    if not ua:
        return False
    if any(part in ua for part in _VISITOR_CONFIRMED_BOT_UA_PARTS):
        return True
    return bool(_VISITOR_CONFIRMED_BOT_UA_RE.search(ua))


def _visitor_device_type(user_agent: str) -> str:
    ua = str(user_agent or "").lower()
    if _visitor_is_confirmed_bot_user_agent(ua):
        return "bot"
    if any(x in ua for x in ("ipad", "tablet")):
        return "tablet"
    if any(x in ua for x in ("mobi", "iphone", "android", "phone")):
        return "mobile"
    return "desktop"


def _visitor_query_group(request: Request) -> str:
    # Visitor counting only cares that a frontend page was entered.
    # Query parameters are intentionally ignored to keep the dashboard simple.
    return ""


def _visitor_retention_cutoff(today: date) -> str:
    return (today - timedelta(days=364)).isoformat()


def _visitor_kind(request: Request) -> str:
    form_flag = str(request.cookies.get("sclaw_form_filled") or "").strip().lower()
    if form_flag in {"1", "true", "yes", "form_filled"}:
        return "form_filled"
    flag = str(request.cookies.get("sclaw_phone_logged_in") or "").strip().lower()
    if flag in {"1", "true", "yes", "phone_login"}:
        return "form_filled"
    return "guest"


def _mark_form_filled_response(resp: JSONResponse) -> JSONResponse:
    """Keep frontend visitor statistics aligned after the user submits an intake form."""
    resp.set_cookie(
        "sclaw_form_filled",
        "1",
        max_age=60 * 60 * 24 * 365,
        httponly=False,
        samesite="lax",
    )
    resp.delete_cookie("sclaw_phone_logged_in")
    return resp


def _should_track_visitor_request(request: Request, status_code: int) -> bool:
    method = str(request.method or "").upper()
    if method not in {"GET", "HEAD"}:
        return False
    path = str(request.url.path or "/")
    lowered = path.lower()
    if status_code >= 500:
        return False
    if any(lowered.startswith(prefix) for prefix in _VISITOR_TRACKING_EXCLUDED_PREFIXES):
        return False
    if any(lowered.endswith(suffix) for suffix in _VISITOR_TRACKING_EXCLUDED_SUFFIXES):
        return False
    if not _visitor_path_matches(path):
        return False
    if _visitor_is_confirmed_bot_user_agent(str(request.headers.get("user-agent") or "")):
        return False
    return True


def _record_visitor_event(request: Request, status_code: int, elapsed_ms: int) -> None:
    if not _should_track_visitor_request(request, status_code):
        return
    try:
        ip = _visitor_client_ip(request)
        now = datetime.now(_VISITOR_TZ)
        today = now.date()
        path = _normalize_visitor_tracking_path(request.url.path or "/")
        user_agent = str(request.headers.get("user-agent") or "")[:420]
        referrer = str(request.headers.get("referer") or "")[:420]
        with get_conn() as conn:
            conn.execute("DELETE FROM site_visitor_events WHERE event_date < ?", (_visitor_retention_cutoff(today),))
            conn.execute(
                """
                INSERT INTO site_visitor_events (
                    event_time, event_date, ip_hash, ip_label, method, path, query_group,
                    status_code, elapsed_ms, referrer, user_agent, device_type, visitor_kind
                )
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                (
                    now.isoformat(timespec="seconds"),
                    today.isoformat(),
                    _visitor_ip_hash(ip),
                    _visitor_ip_label(ip),
                    str(request.method or "GET").upper()[:12],
                    path,
                    _visitor_query_group(request),
                    int(status_code or 0),
                    max(0, int(elapsed_ms or 0)),
                    referrer,
                    user_agent,
                    _visitor_device_type(user_agent),
                    _visitor_kind(request),
                ),
            )
            conn.commit()
    except Exception as exc:
        _push_backend_error_log(
            method="BG",
            path="visitor-tracking",
            status_code=500,
            message=f"Visitor tracking failed: {type(exc).__name__}: {str(exc)[:220]}",
            elapsed_ms=0,
        )


@app.middleware("http")
async def backend_error_log_middleware(request: Request, call_next):
    started = time.time()
    try:
        response = await call_next(request)
    except Exception as exc:
        elapsed = int((time.time() - started) * 1000)
        _push_backend_error_log(
            method=request.method,
            path=request.url.path,
            status_code=500,
            message=f"Unhandled exception: {type(exc).__name__}: {exc}",
            elapsed_ms=elapsed,
        )
        raise
    if response.status_code >= 400:
        elapsed = int((time.time() - started) * 1000)
        _push_backend_error_log(
            method=request.method,
            path=request.url.path,
            status_code=int(response.status_code),
            message="HTTP error response",
            elapsed_ms=elapsed,
        )
    _record_visitor_event(request, int(response.status_code), int((time.time() - started) * 1000))
    return response


def _faq_refresh_loop() -> None:
    while True:
        try:
            seed_suumo_faq_knowledge(limit=50)
        except Exception:
            pass
        time.sleep(2 * 60 * 60)


def _start_faq_refresh_worker() -> None:
    global _faq_worker_started
    with _faq_worker_lock:
        if _faq_worker_started:
            return
        t = threading.Thread(target=_faq_refresh_loop, daemon=True, name="suumo-faq-refresh")
        t.start()
        _faq_worker_started = True


def _seconds_until_next_taipei_slot(*, hours: tuple[int, ...] = (3, 12)) -> float:
    """下一個台北時間（UTC+8）排程點；預設每日 03:00 與 12:00。"""
    tw = timezone(timedelta(hours=8))
    now = datetime.now(tw)
    candidates: list[datetime] = []
    for h in hours:
        hh = int(h)
        t = now.replace(hour=hh, minute=0, second=0, microsecond=0)
        if t <= now:
            t += timedelta(days=1)
        candidates.append(t)
    nxt = min(candidates)
    return max(30.0, (nxt - now).total_seconds())


def _smart_nav_google_intel_loop() -> None:
    """每日兩輪：以智慧導航種子輪播 Google CSE +（可選）AI 閱讀清單，累積熱門關鍵字。"""
    while True:
        time.sleep(min(_seconds_until_next_taipei_slot(), 86400.0))
        if not is_google_cse_configured():
            print("SCLAW: 智慧關鍵字導航排程略過（未設定 GOOGLE_CSE_API_KEY / GOOGLE_CSE_CX）", flush=True)
            continue
        queries = pick_rotating_seed_queries(max_n=8)
        if not queries:
            print("SCLAW: 智慧關鍵字導航排程略過（無種子關鍵字）", flush=True)
            continue
        try:
            out = run_google_finance_property_intel(
                max_seed_queries=len(queries),
                results_per_query=8,
                ingest_seed_queries=True,
                run_gemini=True,
                persona_region="tw",
                gemini_model="",
                llm_provider="",
                custom_queries=queries,
                include_default_queries=False,
            )
            ok = bool(out.get("ok"))
            print(
                "SCLAW: 智慧導航排程 Google+AI 完成 "
                f"ok={ok} hits={out.get('google_hits_count')} keywords_ingested={out.get('keywords_ingested')}",
                flush=True,
            )
        except Exception as exc:  # noqa: BLE001
            print(f"SCLAW: 智慧導航排程失敗: {type(exc).__name__}: {exc}", flush=True)


def _start_smart_nav_intel_worker() -> None:
    global _smart_nav_worker_started
    with _smart_nav_worker_lock:
        if _smart_nav_worker_started:
            return
        t = threading.Thread(
            target=_smart_nav_google_intel_loop,
            daemon=True,
            name="smart-nav-google-intel",
        )
        t.start()
        _smart_nav_worker_started = True


def _parse_host_filter_csv(raw: str) -> frozenset[str] | None:
    s = str(raw or "").strip()
    if not s:
        return None
    out: set[str] = set()
    for chunk in s.split(","):
        h = chunk.strip().lower()
        if h:
            out.add(h)
    return frozenset(out) if out else None


def _portal_image_backfill_loop() -> None:
    from src.thumb_backfill_service import run_empty_image_backfill

    while True:
        interval = 30.0
        try:
            raw_hosts = os.getenv("SCLAW_PORTAL_IMAGE_BACKFILL_HOSTS", "suumo.jp")
            host_filter = _parse_host_filter_csv(raw_hosts)
            limit = int(os.getenv("SCLAW_PORTAL_IMAGE_BACKFILL_LIMIT", "18") or 18)
            sleep_s = float(os.getenv("SCLAW_PORTAL_IMAGE_BACKFILL_SLEEP", "0.35") or 0.35)
            interval = float(os.getenv("SCLAW_PORTAL_IMAGE_BACKFILL_INTERVAL_SEC", "900") or 900.0)
            limit = max(1, min(limit, 250))
            sleep_s = max(0.0, min(sleep_s, 5.0))
            interval = max(60.0, min(interval, 12 * 60 * 60.0))

            out = run_empty_image_backfill(
                host_filter=host_filter,
                limit=limit,
                sleep_s=sleep_s,
                dry_run=False,
                force=False,
            )
            processed = int(out.get("processed_rows") or 0)
            ok = int(out.get("ok") or 0)
            err = int(out.get("err") or 0)
            skip = int(out.get("skip") or 0)
            if processed > 0:
                print(
                    f"SCLAW: portal image backfill processed={processed} ok={ok} err={err} skip={skip}",
                    flush=True,
                )
            if processed <= 0:
                # no rows matched; back off longer
                time.sleep(max(interval, 45 * 60.0))
                continue
        except Exception as exc:  # noqa: BLE001
            print(f"SCLAW: portal image backfill error: {type(exc).__name__}: {exc}", flush=True)
            interval = max(interval, 15 * 60.0)
        time.sleep(interval)


def _start_portal_image_backfill_worker() -> None:
    global _portal_image_backfill_worker_started
    with _portal_image_backfill_worker_lock:
        if _portal_image_backfill_worker_started:
            return
        t = threading.Thread(
            target=_portal_image_backfill_loop,
            daemon=True,
            name="portal-image-backfill",
        )
        t.start()
        _portal_image_backfill_worker_started = True


def _extract_portal_faq_entries(source_key: str, limit: int = 20) -> dict:
    selected_source = str(source_key or "athome").strip().lower()
    cfg = PORTAL_FAQ_SOURCES.get(selected_source) or PORTAL_FAQ_SOURCES["athome"]
    source = selected_source if selected_source in PORTAL_FAQ_SOURCES else "athome"
    source_name = str(cfg.get("name") or "")
    source_url = str(cfg.get("url") or "")
    max_items = min(100, max(5, int(limit)))
    source_host = urlparse(source_url).netloc.lower()
    tokens = ("?", "？", "faq", "q&a", "怎麼", "如何", "費用", "流程", "注意", "手順", "流れ", "ポイント")
    fallback_map = {
        "athome": ["AtHome 賃貸 FAQ 怎麼找房？", "AtHome 租屋費用有哪些？", "AtHome 看房流程要注意什麼？"],
        "suumo": ["SUUMO 租屋 Q&A 如何開始？", "SUUMO 申請租屋流程為何？", "SUUMO 看屋前要準備什麼？"],
        "homes": ["HOMES 租屋 FAQ 怎麼比較物件？", "HOMES 租屋費用怎麼估算？", "HOMES 簽約前注意事項有哪些？"],
    }

    def _build_fallback() -> dict:
        labels = fallback_map.get(source) or fallback_map["athome"]
        rows = [{"question": q, "item_url": source_url, "source_name": source_name} for q in labels[:3]]
        return {
            "ok": False,
            "source": source,
            "source_name": source_name,
            "source_url": source_url,
            "count": len(rows),
            "items": rows,
        }

    try:
        headers = dict(BROWSER_HEADERS)
        if "User-Agent" not in headers:
            headers["User-Agent"] = (
                "Mozilla/5.0 (Windows NT 10.0; Win64; x64) "
                "AppleWebKit/537.36 (KHTML, like Gecko) Chrome/124.0 Safari/537.36"
            )
        with httpx.Client(timeout=25, follow_redirects=True, headers=headers) as client:
            resp = client.get(source_url)
            resp.raise_for_status()
        soup = soup_from_html(resp.text)
    except Exception:
        return _build_fallback()

    seen: set[str] = set()
    rows: list[dict[str, str]] = []
    for anchor in soup.select("a[href]"):
        title = re.sub(r"\s+", " ", anchor.get_text(" ", strip=True)).strip()
        if len(title) < 8 or len(title) > 80:
            continue
        title_lc = title.lower()
        if title_lc in seen:
            continue

        href = str(anchor.get("href") or "").strip()
        if not href:
            continue
        item_url = urljoin(source_url, href)
        parsed_url = urlparse(item_url)
        if parsed_url.scheme not in ("http", "https"):
            continue
        if parsed_url.netloc.lower() != source_host:
            continue

        parent_text = ""
        if anchor.parent is not None:
            parent_text = re.sub(r"\s+", " ", anchor.parent.get_text(" ", strip=True)).strip()
        is_likely_faq = any(token in title_lc for token in tokens) or len(parent_text) >= 40
        if not is_likely_faq:
            continue

        seen.add(title_lc)
        rows.append({"question": title, "item_url": item_url, "source_name": source_name})
        if len(rows) >= max_items:
            break

    return {
        "ok": True,
        "source": source,
        "source_name": source_name,
        "source_url": source_url,
        "count": len(rows),
        "items": rows,
    }


