def _case_detail_strip_original_noise(value: Any) -> str:
    s = str(value or "").replace("\ufffd", "").strip()
    if not s:
        return ""
    s = re.sub(r"(?im)^\s*原文\s*[:：].*$", "", s)
    s = re.sub(r"(?im)^\s*(?:來源原文|来源原文|日語原文|日语原文)\s*[:：].*$", "", s)
    s = re.sub(r"\s*原文\s*[:：]\s*", " ", s)
    s = re.sub(r"(?:\n\s*){3,}", "\n\n", s)
    return s.strip()


def _case_detail_to_zh_display(value: Any, *, max_len: int = 260) -> str:
    s = _case_detail_strip_original_noise(value)
    if not s:
        return ""
    s = unicodedata.normalize("NFKC", s)
    if len(s) > 120 and re.search(r"(?:お電話|お気軽|物件詳細|この会社|撮影風景|掲載開始日)", s):
        return ""
    s = s.replace("㎡", "m²")
    for old, new in _CASE_DETAIL_JP_PHRASE_MAP:
        s = s.replace(old, new)
    s = re.sub(r"([0-9]+)\s*分", r"\1分钟", s)
    s = re.sub(r"([0-9]+)\s*階", r"\1层", s)
    s = re.sub(r"([0-9]+)\s*戸", r"\1户", s)
    s = re.sub(r"([0-9]+)\s*年\s*([0-9]+)\s*月", r"\1年\2月", s)
    if re.search(r"[ぁ-んァ-ヶ]", s):
        s = re.sub(r"[ぁ-んァ-ヶー]+", "", s)
    s = s.replace("新高日圓寺", "新高圆寺").replace("高日圓寺", "高圆寺")
    s = s.replace("新高円寺", "新高圆寺").replace("高円寺", "高圆寺")
    s = re.sub(r"\s*/\s*", " / ", s)
    s = re.sub(r"\s+", " ", s).strip(" ：:-　")
    if not s or s in {"—", "-", "－"}:
        return ""
    return s[: max(20, int(max_len or 260))]


def _case_detail_first_zh(*values: Any, max_len: int = 260) -> str:
    seen: set[str] = set()
    for value in values:
        s = _case_detail_to_zh_display(value, max_len=max_len)
        key = re.sub(r"\s+", "", s).casefold()
        if s and key not in seen:
            return s
        if key:
            seen.add(key)
    return ""


def _case_detail_compact_access_line(value: Any, *, max_items: int = 2, max_len: int = 150) -> str:
    s = unicodedata.normalize("NFKC", str(value or ""))
    s = re.sub(r"\s+", " ", s).strip(" ：:-　")
    if not s:
        return ""

    pieces: list[str] = []
    numbered = re.split(r"\s*(?=(?:\(\d+\)|（\d+）|\d+[.．、]))", s)
    if len([p for p in numbered if p.strip()]) > 1:
        pieces = numbered
    elif "/" in s or "／" in s:
        pieces = re.split(r"\s*[／/]\s*", s)
    elif len(s) > max_len and len(re.findall(r"(?:站|駅)\s*(?:步行|徒歩|歩|巴士|バス)\s*\d{1,3}\s*(?:分钟|分)", s)) > 1:
        marked = re.sub(
            r"((?:分钟|分))\s+(?=[A-Za-z0-9\u4e00-\u9fffＪＲJR].{0,24}(?:線|线|鐵|铁|JR|ＪＲ))",
            r"\1||",
            s,
        )
        pieces = marked.split("||")

    clean_parts: list[str] = []
    seen: set[str] = set()
    for part in pieces:
        p = re.sub(r"^\s*(?:\(\d+\)|（\d+）|\d+[.．、])\s*", "", str(part or "")).strip(" 、，,;；/")
        p = re.sub(r"\s+", " ", p).strip()
        if not p:
            continue
        key = re.sub(r"\s+", "", p).casefold()
        if key in seen:
            continue
        seen.add(key)
        clean_parts.append(p)

    if len(clean_parts) > max_items:
        summary = " / ".join(clean_parts[:max(1, int(max_items or 2))]).strip()
        return f"{summary} 等多條路線"[:max_len].rstrip()
    if clean_parts:
        s = " / ".join(clean_parts)
    if len(s) > max_len:
        return s[: max(20, int(max_len or 150))].rstrip(" 、，,;；/") + "…"
    return s


_INDEX_HTML_CACHE_TTL_SECONDS = int(os.getenv("SCLAW_INDEX_HTML_CACHE_TTL", "86400") or "86400")
_INDEX_HTML_CACHE_LOCK = threading.RLock()
_INDEX_HTML_CACHE: tuple[float, bytes] | None = None
_INDEX_HTML_CACHE_REFRESHING = False


def _should_use_index_html_cache(request: Request) -> bool:
    return (
        _INDEX_HTML_CACHE_TTL_SECONDS > 0
        and request.method.upper() == "GET"
        and request.url.path == "/"
        and not request.url.query
    )


def _render_index_html(request: Request, *, admin_standalone: bool = False) -> str:
    context = _index_template_context(request, admin_standalone=admin_standalone)
    return templates.env.get_template("index.html").render(context)


def _refresh_index_html_cache_in_background(request: Request) -> None:
    """Refresh expired homepage HTML without making a visitor wait for it."""
    global _INDEX_HTML_CACHE, _INDEX_HTML_CACHE_REFRESHING
    try:
        body = _render_index_html(request).encode("utf-8")
        with _INDEX_HTML_CACHE_LOCK:
            _INDEX_HTML_CACHE = (time.time(), body)
    except Exception as exc:
        _log_backend_error("index-html-cache-refresh", exc)
    finally:
        with _INDEX_HTML_CACHE_LOCK:
            _INDEX_HTML_CACHE_REFRESHING = False


@app.get("/")
def index(request: Request):
    global _INDEX_HTML_CACHE, _INDEX_HTML_CACHE_REFRESHING
    if _should_use_index_html_cache(request):
        now = time.time()
        with _INDEX_HTML_CACHE_LOCK:
            if _INDEX_HTML_CACHE:
                cached_at, cached_body = _INDEX_HTML_CACHE
                if now - cached_at <= _INDEX_HTML_CACHE_TTL_SECONDS:
                    return Response(
                        content=cached_body,
                        media_type="text/html; charset=utf-8",
                        headers={"Cache-Control": "public, max-age=60, stale-while-revalidate=120", "X-SCLAW-Index-Cache": "hit"},
                    )
                if not _INDEX_HTML_CACHE_REFRESHING:
                    _INDEX_HTML_CACHE_REFRESHING = True
                    threading.Thread(
                        target=_refresh_index_html_cache_in_background,
                        args=(request,),
                        daemon=True,
                        name="index-html-cache-refresh",
                    ).start()
                return Response(
                    content=cached_body,
                    media_type="text/html; charset=utf-8",
                    headers={"Cache-Control": "public, max-age=60, stale-while-revalidate=120", "X-SCLAW-Index-Cache": "stale"},
                )
        body = _render_index_html(request).encode("utf-8")
        with _INDEX_HTML_CACHE_LOCK:
            _INDEX_HTML_CACHE = (now, body)
        return Response(
            content=body,
            media_type="text/html; charset=utf-8",
            headers={"Cache-Control": "public, max-age=60, stale-while-revalidate=120", "X-SCLAW-Index-Cache": "miss"},
        )
    return templates.TemplateResponse(
        request=request,
        name="index.html",
        context=_index_template_context(request),
    )


