def _case_gallery_caption_category_hints(row: dict[str, Any], *, limit: int) -> list[str]:
    """Infer source-site photo groups from HOMES/portal detail text when media JSON has no captions."""
    text = "\n".join(
        str((row or {}).get(k) or "")
        for k in ("body_original", "body_zh_hant", "body_zh_hans", "title_original", "title_zh_hant")
    )
    if not text.strip():
        return []
    marker_positions = [
        p for p in (
            text.find("[HOMES 明細補圖]"),
            text.find("掲載画像"),
            text.find("案件圖片"),
        )
        if p >= 0
    ]
    if marker_positions:
        text = text[min(marker_positions) :]
    patterns: list[tuple[str, str]] = [
        ("floorplan", r"間取(?:り)?|平面図|図面|圖面|户型|戶型|madori|floor[ _-]?plan"),
        ("toilet", r"トイレ|toire|toilet|便所|WC|廁所|厕所"),
        ("kitchen", r"キッチン|台所|kitchen|廚房|厨房"),
        ("bath", r"浴室|風呂|バス|洗面|脱衣|洗濯機|bath|powder|sanitary"),
        ("facility_detail", r"設備|設備写真|設備画像|自販機|自動販売機|販売機|飲料|ドリンク|宅配ボックス|インターホン|setsubi|facility|equipment|vending|vendingmachine|jihanki|drink|beverage|coca[ -]?cola"),
        ("balcony_view", r"バルコニー|ベランダ|テラス|眺望|陽台|阳台|景觀|景观"),
        ("interior", r"LDK|リビング|ダイニング|洋室|和室|寝室|居室|室内|室內|内装|內裝|収納|フローリング"),
        ("exterior", r"外観|外觀|建物|外壁|エントランス|現地|玄関|入口|facade|exterior"),
        ("environment", r"周辺|周邊|道路|公園|駐車|駐輪|バイク置場|宅配ボックス|インターホン|案内図|環境"),
    ]
    hits: list[tuple[int, str]] = []
    for cat, pat in patterns:
        for m in re.finditer(pat, text, flags=re.I):
            hits.append((int(m.start()), cat))
    hits.sort(key=lambda x: x[0])
    out: list[str] = []
    for _, cat in hits:
        if len(out) >= limit:
            break
        if not out or out[-1] != cat:
            out.append(cat)
        elif cat in {"interior", "environment"}:
            out.append(cat)
    return out[:limit]


def _case_gallery_url_matches_source_site(image_url: str, item_url: str) -> bool:
    img = str(image_url or "").strip()
    src = str(item_url or "").strip()
    if not img or not src:
        return bool(img)
    try:
        img_host = (urlparse(img).netloc or "").lower()
        src_host = (urlparse(src).netloc or "").lower()
    except Exception:
        return True
    if not img_host or not src_host:
        return True
    src_root = src_host[4:] if src_host.startswith("www.") else src_host
    if "suumo.jp" in src_host:
        return "suumo." in img_host
    if "athome.co.jp" in src_host:
        return img_host.endswith("athome.co.jp")
    if "homes.co.jp" in src_host or "homes.jp" in src_host:
        return (
            img_host.endswith("homes.co.jp")
            or img_host.endswith("homes.jp")
            or "ielove-cloud" in img_host
        )
    if "realestate.yahoo.co.jp" in src_host:
        return "yahoo.co.jp" in img_host or "yimg.jp" in img_host
    return img_host == src_root or img_host.endswith("." + src_root)


def _case_extract_area_sqm(text: Any) -> float | None:
    s = _to_half_width_num(str(text or "")).replace(",", "")
    for pat, multiplier in (
        (r"([0-9]+(?:\.[0-9]+)?)\s*(?:㎡|m²|m2|平米)", 1.0),
        (r"([0-9]+(?:\.[0-9]+)?)\s*(?:坪|tsubo)", 3.305785),
    ):
        m = re.search(pat, s, flags=re.I)
        if not m:
            continue
        try:
            area = float(m.group(1)) * multiplier
        except Exception:
            continue
        if 8 <= area <= 500:
            return area
    return None


def _case_extract_layout_key(text: Any) -> str:
    s = _to_half_width_num(str(text or "")).upper()
    s = s.replace("ワンルーム", "1R").replace("ONE ROOM", "1R")
    m = re.search(r"\b([1-6])\s*(SLDK|LDK|SDK|DK|K|R)\b", s)
    if m:
        return f"{m.group(1)}{m.group(2)}"
    return ""


def _case_monthly_rent_man_from_text(text: Any, *, allow_unlabeled_price: bool = False) -> float | None:
    s = _to_half_width_num(str(text or "")).replace(",", "")
    rent_label = r"(?:家賃|賃料|月額賃料|月額家賃|月租金|租金|rent)"
    for pat, div in (
        (rf"{rent_label}[^0-9]{{0,28}}([0-9]+(?:\.[0-9]+)?)\s*(?:万円|萬円|万|萬)", 1.0),
        (rf"{rent_label}[^0-9]{{0,28}}([0-9]{{4,}})\s*(?:円|日圓|日元)", 10000.0),
    ):
        m = re.search(pat, s, flags=re.I)
        if m:
            try:
                val = float(m.group(1)) / div
            except Exception:
                continue
            if 1 <= val <= 300:
                return val
    if allow_unlabeled_price:
        m = re.search(r"([0-9]+(?:\.[0-9]+)?)\s*(?:万円|萬円|万|萬)", s)
        if m:
            try:
                val = float(m.group(1))
            except Exception:
                return None
            if 1 <= val <= 300:
                return val
    return None


def _case_location_tokens_for_rent_estimate(text: Any) -> list[str]:
    s = re.sub(r"\s+", "", str(text or ""))
    out: list[str] = []
    pref = re.search(r"(北海道|東京都|京都府|大阪府|.{2,3}県)", s)
    if pref:
        out.append(pref.group(1))
    city = re.search(r"(?:北海道|東京都|京都府|大阪府|.{2,3}県)?([^0-9０-９]{1,14}?[市区町村])", s)
    if city:
        token = city.group(1)
        if 2 <= len(token) <= 14 and token not in out:
            out.append(token)
    ward = re.search(r"([^0-9０-９]{1,12}区)", s)
    if ward:
        token = ward.group(1)
        if 2 <= len(token) <= 12 and token not in out:
            out.append(token)
    return out[:3]


_CASE_MARKET_RENT_ESTIMATE_CACHE: dict[str, dict[str, Any]] = {}
_CASE_SOURCE_PRICE_FETCH_CACHE: dict[str, tuple[float, float | None]] = {}


def _case_price_man_from_text(text: Any) -> float | None:
    s = _to_half_width_num(str(text or "")).replace(",", "")
    for pat, div in (
        (r"(?:価格|總價|总价|售價|售价|販売価格)?[^0-9]{0,18}([0-9]+(?:\.[0-9]+)?)\s*(?:萬|万)", 1.0),
        (r"(?:価格|總價|总价|售價|售价|販売価格)?[^0-9]{0,18}([0-9]{5,})\s*(?:日圓|円|日元)", 10000.0),
    ):
        m = re.search(pat, s, flags=re.I)
        if not m:
            continue
        try:
            val = float(m.group(1)) / div
        except Exception:
            continue
        if 10 <= val <= 1000000:
            return val
    return None


def _case_source_live_price_man(row: dict[str, Any]) -> float | None:
    url = str((row or {}).get("item_url") or "").strip()
    if not url or not re.match(r"^https?://", url, flags=re.I):
        return None
    cached = _CASE_SOURCE_PRICE_FETCH_CACHE.get(url)
    now = time.time()
    if cached and now - float(cached[0] or 0) < 6 * 3600:
        return cached[1]
    price: float | None = None
    try:
        with httpx.Client(timeout=httpx.Timeout(5.5, connect=2.0), follow_redirects=True, headers=BROWSER_HEADERS) as client:
            res = client.get(url)
        if res.status_code < 400 and res.text:
            text = soup_from_html(res.text).get_text(" ", strip=True)
            price = _case_price_man_from_text(text[:50000])
    except Exception:
        price = None
    _CASE_SOURCE_PRICE_FETCH_CACHE[url] = (now, price)
    return price


_CASE_PUBLIC_RENT_MARKET_ROWS: list[dict[str, Any]] = [
    {
        "match": ("福岡市西区", "福岡県福岡市西区"),
        "layout_monthly_man": {"1LDK": 7.4, "2LDK": 11.33, "3LDK": 13.4},
        "source_label": "LIFULL HOME'S 家賃相場（福岡市西区）",
        "source_url": "https://www.homes.co.jp/chintai/fukuoka/fukuoka_nishi-city/price/",
        "updated_hint": "公開家租相場頁，站內按格局與面積做保守估算",
    },
]


def _case_layout_market_key(layout: str) -> str:
    raw = _to_half_width_num(str(layout or ""))
    m_rooms = re.search(r"([1-6])\s*房", raw)
    if m_rooms:
        rooms = int(m_rooms.group(1))
        if rooms <= 1:
            return "1LDK"
        if rooms == 2:
            return "2LDK"
        if rooms == 3:
            return "3LDK"
        return "4LDK"
    s = _case_extract_layout_key(raw)
    if not s:
        return ""
    if s.startswith("1"):
        return "1LDK"
    if s.startswith("2"):
        return "2LDK"
    if s.startswith("3"):
        return "3LDK"
    if s.startswith("4") or s.startswith("5") or s.startswith("6"):
        return "4LDK"
    return s


def _case_public_market_rent_estimate(row: dict[str, Any], fields: dict[str, Any], price_man: float | None) -> dict[str, Any]:
    target_blob = "\n".join(
        str(x or "")
        for x in (
            (fields or {}).get("address_line_original_jp"),
            (fields or {}).get("address_line_jp"),
            (fields or {}).get("address_line_hant"),
            (fields or {}).get("access_line_original_jp"),
            (fields or {}).get("layout_text_hant"),
            (fields or {}).get("area_text_hant"),
            (row or {}).get("title_original"),
            (row or {}).get("body_original"),
            (row or {}).get("body_zh_hant"),
        )
    )
    if not target_blob.strip():
        return {}
    target_area = _case_extract_area_sqm((fields or {}).get("area_text_hant")) or _case_extract_area_sqm(target_blob)
    layout_key = _case_layout_market_key(str((fields or {}).get("layout_text_hant") or target_blob))
    if not layout_key:
        return {}
    row_match = None
    for market in _CASE_PUBLIC_RENT_MARKET_ROWS:
        if any(str(token or "") and str(token) in target_blob for token in market.get("match") or ()):
            row_match = market
            break
    if not row_match:
        return {}
    monthly_map = dict(row_match.get("layout_monthly_man") or {})
    monthly_man = monthly_map.get(layout_key)
    if monthly_man is None and layout_key == "4LDK":
        monthly_man = monthly_map.get("3LDK")
        if monthly_man is not None:
            monthly_man = float(monthly_man) * 1.12
    if monthly_man is None:
        return {}
    monthly_man = float(monthly_man)
    nominal_area = {"1LDK": 42.0, "2LDK": 60.0, "3LDK": 72.0, "4LDK": 88.0}.get(layout_key)
    if target_area and nominal_area:
        area_factor = max(0.86, min(1.16, 0.72 + 0.28 * (float(target_area) / nominal_area)))
        monthly_man *= area_factor
    if not (1 <= monthly_man <= 300):
        return {}
    annual_man = monthly_man * 12
    out: dict[str, Any] = {
        "monthly_man": monthly_man,
        "annual_man": annual_man,
        "source_label": str(row_match.get("source_label") or "公開家租相場"),
        "source_url": str(row_match.get("source_url") or ""),
        "updated_hint": str(row_match.get("updated_hint") or ""),
        "layout_key": layout_key,
    }
    if price_man:
        yield_pct = annual_man / price_man * 100
        if 0.5 <= yield_pct <= 18:
            out["yield_pct"] = yield_pct
    return out


def _case_market_rent_estimate(row: dict[str, Any], fields: dict[str, Any], price_man: float | None) -> dict[str, Any]:
    if not price_man:
        return {}
    target_blob = "\n".join(
        str(x or "")
        for x in (
            (fields or {}).get("address_line_original_jp"),
            (fields or {}).get("address_line_jp"),
            (fields or {}).get("address_line_hant"),
            (fields or {}).get("access_line_original_jp"),
            (fields or {}).get("layout_text_hant"),
            (fields or {}).get("area_text_hant"),
            (row or {}).get("title_original"),
            (row or {}).get("body_original"),
        )
    )
    target_area = _case_extract_area_sqm((fields or {}).get("area_text_hant")) or _case_extract_area_sqm(target_blob)
    target_layout = _case_extract_layout_key((fields or {}).get("layout_text_hant")) or _case_extract_layout_key(target_blob)
    tokens = _case_location_tokens_for_rent_estimate(target_blob)
    if not tokens and not target_layout and not target_area:
        return {}
    cache_key = "|".join(
        str(x or "")
        for x in (
            (row or {}).get("id") or (row or {}).get("source_item_id"),
            price_man,
            target_area,
            target_layout,
            ",".join(tokens),
        )
    )
    cached = _CASE_MARKET_RENT_ESTIMATE_CACHE.get(cache_key)
    if cached is not None:
        return dict(cached)

    rent_where = (
        "(s.item_url LIKE '%/chintai/%' OR s.item_url LIKE '%賃貸%' OR "
        "s.title_original LIKE '%賃貸%' OR s.title_original LIKE '%家賃%' OR s.title_original LIKE '%賃料%' OR "
        "s.body_original LIKE '%家賃%' OR s.body_original LIKE '%賃料%' OR c.body_zh_hant LIKE '%租金%')"
    )
    token_params: list[str] = []
    token_clause = ""
    query_tokens = [t for t in tokens if t and not re.search(r"(?:都|道|府|県)$", t)] or tokens
    if query_tokens:
        token_bits: list[str] = []
        for t in query_tokens:
            like = f"%{t}%"
            token_params.extend([like, like, like])
            token_bits.append("(s.title_original LIKE ? OR s.body_original LIKE ? OR c.body_zh_hant LIKE ?)")
        token_clause = " AND (" + " OR ".join(token_bits) + ")"

    try:
        with get_conn() as conn:
            rows = conn.execute(
                f"""
                SELECT
                    s.id, s.source_name, s.item_url, s.title_original, s.body_original,
                    s.image_urls, COALESCE(s.content_kind, '') AS content_kind,
                    COALESCE(c.title_zh_hant, '') AS title_zh_hant,
                    COALESCE(c.body_zh_hant, '') AS body_zh_hant,
                    COALESCE(c.body_zh_hans, '') AS body_zh_hans,
                    COALESCE(c.case_transaction_override, '') AS case_transaction_override,
                    COALESCE(c.case_jp_region_override, '') AS case_jp_region_override,
                    COALESCE(c.case_transit_override, '') AS case_transit_override,
                    COALESCE(c.listing_media_json, '[]') AS listing_media_json
                FROM source_items s
                LEFT JOIN content_items c ON c.source_item_id = s.id
                WHERE {rent_where}{token_clause}
                ORDER BY s.id DESC
                LIMIT 180
                """,
                tuple(token_params),
            ).fetchall()
    except Exception:
        return {}

    comps: list[dict[str, Any]] = []
    current_id = str((row or {}).get("id") or (row or {}).get("source_item_id") or "")
    for raw in rows:
        d = dict(raw)
        if current_id and str(d.get("id") or "") == current_id:
            continue
        blob = "\n".join(
            str(d.get(k) or "")
            for k in ("title_original", "body_original", "body_zh_hant", "body_zh_hans")
        )
        if not re.search(r"(賃貸|家賃|賃料|月租金|租金|/chintai/)", blob + "\n" + str(d.get("item_url") or ""), flags=re.I):
            continue
        try:
            meta = infer_case_metadata(d)
            cand_fields = _extract_listing_fields(d, meta=meta)
        except Exception:
            cand_fields = {}
        cand_blob = "\n".join(
            str(x or "")
            for x in (
                cand_fields.get("price_text_hant"),
                cand_fields.get("area_text_hant"),
                cand_fields.get("layout_text_hant"),
                cand_fields.get("address_line_jp"),
                d.get("title_original"),
                d.get("body_original"),
                d.get("body_zh_hant"),
            )
        )
        monthly = _case_monthly_rent_man_from_text(cand_blob)
        if monthly is None or not (1 <= monthly <= 300):
            continue
        cand_area = _case_extract_area_sqm(cand_fields.get("area_text_hant")) or _case_extract_area_sqm(cand_blob)
        cand_layout = _case_extract_layout_key(cand_fields.get("layout_text_hant")) or _case_extract_layout_key(cand_blob)
        score = 0
        location_hits = [t for t in tokens if t and t in cand_blob]
        strong_location_hit = any(t and not re.search(r"(?:都|道|府|県)$", t) for t in location_hits)
        if tokens and not strong_location_hit:
            continue
        if location_hits:
            score += 2 + min(2, len(location_hits))
        if target_layout and cand_layout == target_layout:
            score += 2
        if target_area and cand_area:
            ratio = abs(cand_area - target_area) / max(target_area, 1.0)
            if ratio <= 0.18:
                score += 2
            elif ratio <= 0.35:
                score += 1
        elif not target_area:
            score += 1
        if score < 4:
            continue
        comps.append({"monthly": monthly, "area": cand_area, "layout": cand_layout, "score": score})

    if not comps:
        _CASE_MARKET_RENT_ESTIMATE_CACHE[cache_key] = {}
        return {}
    comps.sort(key=lambda c: (-int(c.get("score") or 0), abs(float(c.get("area") or target_area or 0) - float(target_area or c.get("area") or 0))))
    picked = comps[: min(12, max(3, len(comps)))]
    if target_area:
        per_sqm = [float(c["monthly"]) / float(c["area"]) for c in picked if c.get("area")]
        if per_sqm:
            vals = sorted(per_sqm)
            mid = len(vals) // 2
            median_per_sqm = vals[mid] if len(vals) % 2 else (vals[mid - 1] + vals[mid]) / 2
            monthly_man = median_per_sqm * target_area
        else:
            vals = sorted(float(c["monthly"]) for c in picked)
            mid = len(vals) // 2
            monthly_man = vals[mid] if len(vals) % 2 else (vals[mid - 1] + vals[mid]) / 2
    else:
        vals = sorted(float(c["monthly"]) for c in picked)
        mid = len(vals) // 2
        monthly_man = vals[mid] if len(vals) % 2 else (vals[mid - 1] + vals[mid]) / 2
    if not (1 <= monthly_man <= 300):
        _CASE_MARKET_RENT_ESTIMATE_CACHE[cache_key] = {}
        return {}
    annual_man = monthly_man * 12
    yield_pct = annual_man / price_man * 100
    if not (0.5 <= yield_pct <= 12):
        _CASE_MARKET_RENT_ESTIMATE_CACHE[cache_key] = {}
        return {}
    result = {
        "monthly_man": monthly_man,
        "annual_man": annual_man,
        "yield_pct": yield_pct,
        "sample_count": len(picked),
        "total_candidates": len(comps),
    }
    _CASE_MARKET_RENT_ESTIMATE_CACHE[cache_key] = dict(result)
    return result


def _case_investment_metrics_from_cache(source_item_id: Any) -> dict[str, Any] | None:
    try:
        sid = int(source_item_id or 0)
    except Exception:
        sid = 0
    if sid <= 0:
        return None
    try:
        with get_conn() as conn:
            rec = conn.execute(
                "SELECT metrics_json FROM case_investment_metrics WHERE source_item_id = ?",
                (sid,),
            ).fetchone()
    except Exception:
        return None
    if not rec:
        return None
    try:
        payload = json.loads(str(rec["metrics_json"] or "{}"))
    except Exception:
        return None
    if not isinstance(payload, dict) or not isinstance(payload.get("rows"), list):
        return None
    return payload


def _case_investment_metrics_quality(metrics: dict[str, Any]) -> str:
    if not isinstance(metrics, dict):
        return "missing"
    if not bool(metrics.get("has_income_data")):
        return "missing"
    if not bool(metrics.get("estimated")):
        return "actual_source"
    note = str(metrics.get("note") or "")
    if str(metrics.get("source_url") or "").strip():
        return "public_market_estimate"
    if "租賃樣本" in note:
        return "db_rent_sample_estimate"
    return "estimate"


def _case_investment_metrics_for_display(metrics: dict[str, Any]) -> dict[str, Any]:
    out = dict(metrics or {})
    clean_rows: list[dict[str, str]] = []
    label_map = {
        "滿租租售比": "满租投资回报率",
        "現行租售比": "满租投资回报率",
        "收益率": "满租投资回报率",
        "年收入": "年收入（满租时）",
        "年收入（滿租時）": "年收入（满租时）",
        "年收入（現行）": "年收入（满租时）",
        "回收参考": "回本参考",
    }
    for raw in out.get("rows") or []:
        if not isinstance(raw, dict):
            continue
        label = str(raw.get("label") or "")
        value = str(raw.get("value") or "")
        if value.strip() == "—" and label in {"現行租售比", "年收入（現行）"}:
            continue
        label = label_map.get(label, label)
        value = re.sub(r"（(?:多站均值估|租賃樣本估|市況估|估|原站補抓)）", "", value)
        clean_rows.append({"label": label, "value": value})
    row_values = {str(r.get("label") or ""): str(r.get("value") or "") for r in clean_rows}

    def _num_from_value(value: Any) -> float | None:
        m = re.search(r"([0-9]+(?:\.[0-9]+)?)", str(value or ""))
        if not m:
            return None
        try:
            return float(m.group(1))
        except Exception:
            return None

    def _num_from_row(label: str) -> float | None:
        return _num_from_value(row_values.get(label))

    sale_rows: list[dict[str, str]] = []
    rental_rows: list[dict[str, str]] = []
    if out.get("kind") != "rental":
        existing_labels = {r.get("label") for r in clean_rows}
        annual_man = _num_from_row("年收入（满租时）")
        yield_pct = _num_from_row("满租投资回报率")
        if annual_man and "月租参考" not in existing_labels:
            monthly_row = {
                "label": "月租参考",
                "value": f"約 {_fmt_number_zh(annual_man / 12.0, max_decimals=1)} 萬日圓",
            }
            clean_rows.append(monthly_row)
            row_values[monthly_row["label"]] = monthly_row["value"]
            existing_labels.add("月租参考")
        if yield_pct and yield_pct > 0 and "回本参考" not in existing_labels:
            payback_row = {
                "label": "回本参考",
                "value": f"約 {_fmt_number_zh(100.0 / yield_pct, max_decimals=1)} 年",
            }
            clean_rows.append(payback_row)
            row_values[payback_row["label"]] = payback_row["value"]
        for label in ("總價（含稅）", "满租投资回报率", "年收入（满租时）", "回本参考"):
            value = row_values.get(label)
            if value and value != "—":
                sale_rows.append({"label": label, "value": value})
        monthly_value = row_values.get("月租参考")
        annual_value = row_values.get("年收入（满租时）")
        yield_value = row_values.get("满租投资回报率")
        if monthly_value and monthly_value != "—":
            rental_rows.append({"label": "月租参考", "value": monthly_value})
        if annual_value and annual_value != "—":
            rental_rows.append({"label": "年租参考", "value": annual_value})
    else:
        rental_rows = [dict(r) for r in clean_rows if str(r.get("value") or "") != "—"]
    out["rows"] = clean_rows
    if out.get("kind") != "rental":
        out["kind"] = "sale"
    out["sale_rows"] = sale_rows
    out["rental_rows"] = rental_rows
    out["has_sale_data"] = bool(sale_rows)
    out["has_rental_data"] = bool(rental_rows)
    if out.get("kind") == "rental":
        out["note"] = "租賃房源"
    elif bool(out.get("has_income_data")):
        out["note"] = "收益資料僅供參考，實際條件請以顧問確認為準。"
    else:
        out["note"] = "暫無可用收益資料。"
    out["source_url"] = ""
    return out


def _case_investment_metrics(
    row: dict[str, Any],
    fields: dict[str, Any],
    *,
    use_cache: bool = True,
    allow_live_price: bool = False,
    allow_estimates: bool = True,
) -> dict[str, Any]:
    item_url = str((row or {}).get("item_url") or "")
    transaction_hint = str(
        (fields or {}).get("transaction_text_hant")
        or (fields or {}).get("transaction_text_original")
        or (row or {}).get("case_transaction_override")
        or ""
    )
    if "/chintai/" in item_url or re.search(r"(賃貸|出租|租賃|月租)", transaction_hint):
        rows = [
            {"label": "月租", "value": str((fields or {}).get("price_text_hant") or "—")},
            {"label": "格局", "value": str((fields or {}).get("layout_text_hant") or "—")},
            {"label": "面積", "value": str((fields or {}).get("area_text_hant") or "—")},
        ]
        return _case_investment_metrics_for_display({
            "kind": "rental",
            "rows": rows,
            "has_income_data": False,
            "estimated": False,
            "note": "本案為租賃房源，已標注為租賃。",
            "source_url": "",
            "data_quality": "missing",
        })

    if use_cache:
        cached = _case_investment_metrics_from_cache((row or {}).get("id") or (row or {}).get("source_item_id"))
        if cached:
            return _case_investment_metrics_for_display(cached)

    def _clean(text: Any) -> str:
        return re.sub(r"\s+", " ", str(text or "")).strip()

    blob = _clean(
        "\n".join(
            str((row or {}).get(k) or "")
            for k in ("title_original", "body_original", "body_zh_hant", "body_zh_hans", "seo_title", "seo_description")
        )
    )
    blob_hw = _to_half_width_num(blob).replace(",", "")
    price_text = _clean((fields or {}).get("price_text_hant"))

    price_man = _case_price_man_from_text(price_text)
    if price_man is None:
        price_man = _case_price_man_from_text(blob_hw)
    if price_man is None and allow_live_price:
        price_man = _case_source_live_price_man(row)
        if price_man and not price_text:
            price_text = f"約 {_fmt_number_zh(price_man, max_decimals=0)} 萬日圓（原站補抓）"

    def _yield_value(*tokens: str) -> str:
        if not blob_hw:
            return ""
        label = "|".join(re.escape(t) for t in tokens if t)
        if not label:
            return ""
        for pat in (
            rf"(?:{label})[^0-9%％]{{0,28}}([0-9]+(?:\.[0-9]+)?)\s*[%％]",
            rf"([0-9]+(?:\.[0-9]+)?)\s*[%％][^\\n。]{{0,24}}(?:{label})",
        ):
            m = re.search(pat, blob_hw, flags=re.I)
            if m:
                return f"{m.group(1)} %"
        return ""

    gross_yield = _yield_value("満室投資利回り", "満室利回り", "滿租投資報酬率", "滿租租售比", "想定利回り", "表面利回り", "利回り")
    current_yield = _yield_value("現行投資利回り", "現行利回り", "現行投資報酬率", "現行租售比")

    def _annual_income(*tokens: str) -> tuple[float | None, str]:
        label = "|".join(re.escape(t) for t in tokens if t)
        if label:
            m = re.search(rf"(?:{label})[^0-9]{{0,28}}([0-9]+(?:\.[0-9]+)?)\s*(?:萬|万)", blob_hw, flags=re.I)
            if m:
                val = float(m.group(1))
                return val, f"{_fmt_number_zh(val, max_decimals=1)} 萬日圓"
            m_yen = re.search(rf"(?:{label})[^0-9]{{0,28}}([0-9]{{5,}})\s*(?:円|日圓|日元)", blob_hw, flags=re.I)
            if m_yen:
                val = float(m_yen.group(1)) / 10000.0
                return val, f"{_fmt_number_zh(val, max_decimals=1)} 萬日圓"
        return None, ""

    annual_full_man, annual_full = _annual_income("年収(満室時)", "年收入(滿租時)", "滿租年收入", "満室年収", "想定年間収入", "年間賃料収入", "年収", "年收入")
    annual_current_man, annual_current = _annual_income("年収(現行)", "年收入(現行)", "現行年收入", "現行年収")

    if not annual_full:
        m_month = re.search(r"(?:家賃|賃料|月額賃料|月租金)[^0-9]{0,24}([0-9]{4,})\s*(?:円|日圓|日元)", blob_hw, flags=re.I)
        if m_month:
            annual_full_man = float(m_month.group(1)) * 12 / 10000.0
            annual_full = f"{_fmt_number_zh(annual_full_man, max_decimals=1)} 萬日圓"

    def _yield_from_annual(annual_man: float | None) -> str:
        if annual_man and price_man:
            return f"{annual_man / price_man * 100:.2f} %"
        return ""

    if not gross_yield:
        gross_yield = _yield_from_annual(annual_full_man)
    if not current_yield:
        current_yield = _yield_from_annual(annual_current_man)

    note = ""
    estimated = False
    source_url = ""
    if allow_estimates and price_man and (not gross_yield or not annual_full):
        est = _case_market_rent_estimate(row, fields, price_man)
        if est:
            estimated = True
            if not annual_full:
                annual_full_man = float(est["annual_man"])
                annual_full = f"約 {_fmt_number_zh(annual_full_man, max_decimals=1)} 萬日圓"
            if not gross_yield:
                gross_yield = f"約 {float(est['yield_pct']):.2f} %"
            note = "收益資料僅供參考，實際條件請以顧問確認為準。"

    if allow_estimates and (not annual_full or not gross_yield):
        market_est = _case_public_market_rent_estimate(row, fields, price_man)
        if market_est:
            estimated = True
            annual_market_man = float(market_est["annual_man"])
            annual_market = f"約 {_fmt_number_zh(annual_market_man, max_decimals=1)} 萬日圓"
            yield_market = ""
            if market_est.get("yield_pct") is not None:
                yield_market = f"約 {float(market_est['yield_pct']):.2f} %"
            if not annual_full:
                annual_full_man = annual_market_man
                annual_full = annual_market
            if not gross_yield and yield_market:
                gross_yield = yield_market
            source_label = str(market_est.get("source_label") or "公開家租相場")
            source_url = str(market_est.get("source_url") or "")
            note = "收益資料僅供參考，實際條件請以顧問確認為準。"
            if not yield_market and not price_man:
                note = "暫無可用收益資料。"

    rows = [
        {"label": "總價（含稅）", "value": price_text or "—"},
        {"label": "满租投资回报率", "value": gross_yield or current_yield or "—"},
        {"label": "年收入（满租时）", "value": annual_full or annual_current or "—"},
    ]
    has_income_data = any(r["value"] != "—" for r in rows[1:])
    if not note and not has_income_data:
        note = "暫無可用收益資料。"
    out = {"rows": rows, "has_income_data": has_income_data, "estimated": estimated, "note": note, "source_url": source_url}
    out["data_quality"] = _case_investment_metrics_quality(out)
    return _case_investment_metrics_for_display(out)


def _build_case_gallery_sections(row: dict[str, Any], *, property_urls: list[str], aux_urls: list[str], agent_urls: list[str]) -> list[dict[str, Any]]:
    context_by_key = _case_gallery_context_by_url(row)
    audit_by_key = _case_gallery_audit_by_source_item(int((row or {}).get("source_item_id") or (row or {}).get("id") or 0))
    item_url = str((row or {}).get("item_url") or "")
    yahoo_path_token = _case_yahoo_listing_image_path_token(item_url)
    homes_structured_media = bool(context_by_key) and ("homes.co.jp" in item_url.lower() or "homes.jp" in item_url.lower())
    raw_sources: list[str] = []
    for group in (
        property_urls,
        [x.strip() for x in str((row or {}).get("image_urls") or "").splitlines() if x.strip()],
        _extract_image_urls_from_plain_blob(str((row or {}).get("listing_media_json") or ""), limit=96),
    ):
        for raw in group:
            s = str(raw or "").strip()
            if s:
                raw_sources.append(s)
    categories: dict[str, list[str]] = {
        "floorplan": [],
        "interior": [],
        "kitchen": [],
        "bath": [],
        "toilet": [],
        "kitchen_bath": [],
        "exterior": [],
        "balcony_view": [],
        "land_site": [],
        "parking": [],
        "shop": [],
        "office": [],
        "warehouse": [],
        "factory": [],
        "facility_detail": [],
        "environment": [],
        "other": [],
    }
    accepted_index = 0
    seen: set[str] = set()
    agent_keys = {
        _case_gallery_url_identity_key(
            _normalize_listing_image_url_for_display(u, suumo_w=_SOURCE_IMAGE_HIGH_RES_W, suumo_h=_SOURCE_IMAGE_HIGH_RES_H)
        )
        or str(u or "").strip()
        for u in agent_urls
        if str(u or "").strip()
    }
    for raw in raw_sources:
        u = _normalize_listing_image_url_for_display(raw, suumo_w=_SOURCE_IMAGE_HIGH_RES_W, suumo_h=_SOURCE_IMAGE_HIGH_RES_H)
        if not u or not _row_image_url_is_usable(u):
            continue
        if not _case_gallery_url_matches_source_site(u, item_url):
            continue
        if yahoo_path_token and _is_yahoo_listing_image_url(u):
            try:
                y_path = urlparse(u).path.lower()
            except Exception:
                y_path = str(u or "").lower()
            if yahoo_path_token not in unquote(y_path):
                continue
        key = _case_gallery_url_identity_key(u) or u
        if key in seen:
            continue
        if homes_structured_media and key not in context_by_key:
            continue
        context = context_by_key.get(key, "")
        audit = audit_by_key.get(key) or {}
        if bool(audit.get("is_polluted")):
            continue
        if _case_gallery_context_is_non_property_media(u, context):
            continue
        cached_static = _case_image_cached_static_url(u)
        if cached_static and _case_gallery_local_display_issue(cached_static):
            continue
        seen.add(key)
        if key in agent_keys or is_likely_agent_portrait_image_url(u):
            continue
        if not _is_case_property_gallery_image_url(u) and _case_gallery_category_for_url(u, context) != "floorplan":
            continue
        cat = _case_gallery_category_for_url(u, context)
        audit_cat = _case_gallery_normalize_ai_category(audit.get("category"))
        if audit_cat and audit_cat not in {"unknown", "other"}:
            if audit_cat in {"land_frontage", "farmland", "forest_land"}:
                audit_cat = "land_site"
            elif audit_cat in {"shop_front", "shop_interior", "street_front"}:
                audit_cat = "shop"
            elif audit_cat in {"office_interior", "office_building"}:
                audit_cat = "office"
            elif audit_cat in {"warehouse_interior", "warehouse_exterior"}:
                audit_cat = "warehouse"
            elif audit_cat in {"factory_interior", "factory_exterior"}:
                audit_cat = "factory"
            cat = audit_cat
        accepted_index += 1
        categories.setdefault(cat, []).append(u)

    order = [
        ("interior", "室內圖", "客廳、臥室、LDK 與主要室內照片"),
        ("kitchen", "廚房", "廚房、流理台與料理空間"),
        ("bath", "浴室", "浴室、洗面與衛浴設備"),
        ("toilet", "廁所", "廁所與獨立 WC"),
        ("kitchen_bath", "廚衛圖", "廚房、浴室、洗面與廁所"),
        ("floorplan", "房型圖", "格局圖、平面圖與房型配置"),
        ("exterior", "室外圖", "建物外觀、入口與外部立面"),
        ("balcony_view", "景觀圖", "陽台、露台與窗外視野"),
        ("land_site", "土地現況", "土地、臨路、農地、山林與基地現況"),
        ("parking", "車位／停車", "車位、車庫、停車場與出入口"),
        ("shop", "店面", "店面門面、臨街面、招牌與店內空間"),
        ("office", "辦公", "辦公室內、辦公樓與入口空間"),
        ("warehouse", "倉庫", "倉庫內部、外觀、裝卸口與物流空間"),
        ("factory", "廠房", "廠房外觀、作業空間與工業用途照片"),
        ("facility_detail", "設備細節", "設備、局部與輔助設施"),
        ("environment", "環境圖", "道路、停車、周邊設施與環境照片"),
        ("other", "未分類", "來源相簿中未標註類型的本案圖片"),
    ]
    typed_sections: list[dict[str, Any]] = []
    all_urls: list[str] = []
    for key, label, hint in order:
        urls = categories.get(key) or []
        if not urls:
            continue
        all_urls.extend(urls)
        typed_sections.append({"key": key, "label": label, "hint": hint, "urls": urls, "count": len(urls), "is_all": False})
    sections: list[dict[str, Any]] = []
    if all_urls:
        sections.append(
            {
                "key": "all",
                "label": "全部圖片",
                "hint": "已依圖片類型排序；輪播會先播完同一類型，再接續下一類型。",
                "urls": all_urls,
                "count": len(all_urls),
                "is_all": True,
            }
        )
    sections.extend(typed_sections)
    return sections


def _load_support_session_interest_cases(session_id: str, *, limit: int = 16) -> list[dict[str, Any]]:
    sid = _normalize_support_session_id(session_id)
    if not sid:
        return []
    lim = max(1, min(60, int(limit)))
    with get_conn() as conn:
        _ensure_support_case_interest_table(conn)
        rows = conn.execute(
            """
            SELECT
              case_key, source_item_id, content_id, title, source_name,
              item_url, article_url, transaction_label_zh, jp_region_display_zh,
              transit_line_zh, address_hint_zh, price_text_hant, layout_text_hant, area_text_hant, building_type_zh,
              thumb_url,
              updated_at
            FROM support_session_case_interest
            WHERE session_id = ?
            ORDER BY updated_at DESC, id DESC
            LIMIT ?
            """,
            (sid[:120], lim),
        ).fetchall()
    return [_interest_case_row_with_derived_article_url(dict(r)) for r in rows]


def _support_selected_case_enrich_one(conn: sqlite3.Connection, raw: dict[str, Any]) -> dict[str, Any] | None:
    if not isinstance(raw, dict):
        return None
    source_item_id = max(0, _safe_int(raw.get("source_item_id")))
    content_id = max(0, _safe_int(raw.get("content_id")))
    item_url = _normalize_case_interest_url(raw.get("item_url"))
    title = re.sub(r"\s+", " ", str(raw.get("title") or "").strip())
    params: tuple[Any, ...]
    where = ""
    if source_item_id > 0:
        where = "s.id = ?"
        params = (source_item_id,)
    elif content_id > 0:
        where = "c.id = ?"
        params = (content_id,)
    elif item_url:
        where = "s.item_url = ?"
        params = (item_url,)
    elif title:
        title_like = f"%{title[:80]}%"
        where = "(COALESCE(c.title_zh_hant,'') LIKE ? OR COALESCE(s.title_original,'') LIKE ? OR COALESCE(c.seo_title,'') LIKE ?)"
        params = (title_like, title_like, title_like)
    else:
        return None
    row = conn.execute(
        f"""
        SELECT
            s.id AS source_item_id,
            s.source_name,
            s.item_url,
            s.title_original,
            s.body_original,
            s.published_at,
            s.crawled_at,
            s.image_urls,
            s.content_kind,
            COALESCE(c.id, 0) AS content_id,
            COALESCE(c.seo_slug, '') AS seo_slug,
            COALESCE(c.seo_title, '') AS seo_title,
            COALESCE(c.title_zh_hant, '') AS title_zh_hant,
            COALESCE(c.title_zh_hans, '') AS title_zh_hans,
            COALESCE(c.body_zh_hant, '') AS body_zh_hant,
            COALESCE(c.body_zh_hans, '') AS body_zh_hans,
            COALESCE(c.case_transaction_override, '') AS case_transaction_override,
            COALESCE(c.case_jp_region_override, '') AS case_jp_region_override,
            COALESCE(c.case_transit_override, '') AS case_transit_override,
            COALESCE(c.jp_station_id, 0) AS jp_station_id,
            COALESCE(c.walk_min, 0) AS walk_min,
            COALESCE(c.listing_media_json, '[]') AS listing_media_json,
            COALESCE(c.updated_at, '') AS updated_at
        FROM source_items s
        LEFT JOIN content_items c ON c.source_item_id = s.id
        WHERE {where}
        ORDER BY c.updated_at DESC, s.id DESC
        LIMIT 1
        """,
        params,
    ).fetchone()
    if not row:
        return None
    d = dict(row)
    try:
        from src.case_metadata import infer_case_metadata
        from src.portal_case_search import _extract_listing_fields

        meta = infer_case_metadata(d)
        fields = _extract_listing_fields(d, meta=meta)
    except Exception:
        meta = {}
        fields = {}
    price = str(fields.get("price_text_hant") or "").strip()
    if not price:
        price = _home_intro_case_price_hint(d)
    gallery_urls, floorplan_urls = _support_compare_gallery_payload(d, limit=12)
    if not gallery_urls:
        gallery_urls = _case_verified_property_gallery_urls(d, limit=12)
    thumb = gallery_urls[0] if gallery_urls else ""
    nearby_summary = _support_compare_nearby_summary(d, fields, limit=6)
    nearby_2km_summary = _support_compare_nearby_radius_payload(d, fields, radius_m=2000, limit=8)
    orientation_summary = _support_compare_orientation_summary(d, fields)
    decoration_summary = _support_compare_decoration_summary(d, fields)
    property_rights = _support_compare_labeled_value(d, fields, ("権利", "權利", "權利形態", "権利形態", "敷地権利", "土地権利", "产权", "產權"))
    land_rights = _support_compare_labeled_value(d, fields, ("土地権利", "土地權利", "敷地権利", "土地權屬"))
    house_use = _support_compare_labeled_value(d, fields, ("用途", "房屋用途", "建物用途", "物件用途", "種別", "種類"))
    title_age = _support_compare_labeled_value(d, fields, ("房本年限", "土地権利", "権利", "權利", "所有権"))
    layout_structure = _support_compare_labeled_value(d, fields, ("間取り詳細", "間取り内訳", "户型结构", "戶型結構", "間取内訳", "間取り備考"))
    elevator_ratio = _support_compare_labeled_value(d, fields, ("梯户比例", "梯戶比例", "エレベーター", "EV", "エレベータ"))
    elevator = _support_compare_labeled_value(d, fields, ("エレベーター", "EV", "電梯", "电梯"))
    heating = _support_compare_labeled_value(d, fields, ("供暖方式", "暖房", "暖房方式", "給湯", "供暖"))
    mortgage = _support_compare_labeled_value(d, fields, ("抵押信息", "抵押資訊", "抵当権", "抵押", "住宅ローン"))
    community_info = _support_compare_labeled_value(d, fields, ("小区名称", "小區名稱", "マンション名", "物件名", "建物名", "販売名"), max_len=120)
    building_area = _support_compare_labeled_value(d, fields, ("建物面積", "建築面積", "建筑面积"), max_len=80)
    land_area = _support_compare_labeled_value(d, fields, ("土地面積", "土地面积"), max_len=80)
    management_company = _support_compare_labeled_value(d, fields, ("管理会社", "管理公司", "物業公司", "物业公司"), max_len=120)
    management_form = _support_compare_labeled_value(d, fields, ("管理形態", "管理方式", "管理形式"), max_len=100)
    use_district = _support_compare_labeled_value(d, fields, ("用途地域", "用途區域", "用途区域"), max_len=100)
    urban_planning = _support_compare_labeled_value(d, fields, ("都市計画", "都市計畫"), max_len=100)
    land_category = _support_compare_labeled_value(d, fields, ("地目", "土地地目"), max_len=80)
