@app.get("/api/admin/visitor-records")
def api_admin_visitor_records(
    request: Request,
    days: int = Query(default=14, ge=1, le=365),
    page: int = Query(default=1, ge=1),
    page_size: int = Query(default=20, ge=10, le=100),
    kind: str = Query(default="all", max_length=20),
):
    _require_admin_password(request)
    range_days = _visitor_dashboard_days(days)
    max_pages = _visitor_max_pages()
    today = datetime.now(_VISITOR_TZ).date()
    start_date = today - timedelta(days=range_days - 1)
    start_text = start_date.isoformat()
    path_sql, path_params = _visitor_path_where_clause()
    human_sql = _visitor_human_event_where_clause()
    kind_norm = str(kind or "all").strip().lower()
    if kind_norm in {"normal", "ordinary"}:
        kind_norm = "guest"
    if kind_norm in {"form", "phone", "phone_login"}:
        kind_norm = "form_filled"
    kind_clause = ""
    if kind_norm == "guest":
        kind_clause = " AND COALESCE(visitor_kind, 'guest') NOT IN ('form_filled', 'phone_login')"
    elif kind_norm == "form_filled":
        kind_clause = " AND COALESCE(visitor_kind, 'guest') IN ('form_filled', 'phone_login')"
    else:
        kind_norm = "all"
    with get_conn() as conn:
        conn.execute("DELETE FROM site_visitor_events WHERE event_date < ?", (_visitor_retention_cutoff(today),))
        conn.commit()
        total_row = conn.execute(
            f"""
            SELECT COUNT(*) AS total
            FROM (
              SELECT
                event_date,
                ip_hash,
                CASE
                  WHEN COALESCE(visitor_kind, 'guest') IN ('form_filled', 'phone_login') THEN 'form_filled'
                  ELSE 'guest'
                END AS visitor_kind
              FROM site_visitor_events
              WHERE event_date >= ?{path_sql}{human_sql}{kind_clause}
              GROUP BY
                event_date,
                ip_hash,
                CASE
                  WHEN COALESCE(visitor_kind, 'guest') IN ('form_filled', 'phone_login') THEN 'form_filled'
                  ELSE 'guest'
                END
            )
            """,
            (start_text, *path_params),
        ).fetchone()
        total_records = int(total_row["total"] or 0) if total_row else 0
        raw_total_pages = (total_records + page_size - 1) // page_size if total_records else 0
        total_pages = min(max_pages, raw_total_pages) if raw_total_pages else 0
        current_page = max(1, min(int(page or 1), total_pages or 1))
        offset = (current_page - 1) * page_size
        rows = conn.execute(
            f"""
            SELECT
              MIN(event_time) AS first_enter_at,
              MAX(event_time) AS last_enter_at,
              event_date,
              ip_label,
              CASE
                WHEN COALESCE(visitor_kind, 'guest') IN ('form_filled', 'phone_login') THEN 'form_filled'
                ELSE 'guest'
              END AS visitor_kind,
              MAX(device_type) AS device_type,
              COUNT(*) AS entry_count,
              GROUP_CONCAT(DISTINCT path) AS paths
            FROM site_visitor_events
            WHERE event_date >= ?{path_sql}{human_sql}{kind_clause}
            GROUP BY
              event_date,
              ip_hash,
              CASE
                WHEN COALESCE(visitor_kind, 'guest') IN ('form_filled', 'phone_login') THEN 'form_filled'
                ELSE 'guest'
              END
            ORDER BY last_enter_at DESC, first_enter_at DESC
            LIMIT ? OFFSET ?
            """,
            (start_text, *path_params, page_size, offset),
        ).fetchall()

    items: list[dict[str, Any]] = []
    for row in rows:
        raw_paths = [p for p in str(row["paths"] or "").split(",") if p]
        items.append(
            {
                "first_enter_at": str(row["first_enter_at"] or ""),
                "last_enter_at": str(row["last_enter_at"] or ""),
                "event_date": str(row["event_date"] or ""),
                "ip_label": str(row["ip_label"] or ""),
                "visitor_kind": str(row["visitor_kind"] or "guest"),
                "device_type": str(row["device_type"] or "desktop"),
                "entry_count": int(row["entry_count"] or 0),
                "paths": raw_paths[:6],
            }
        )
    return JSONResponse(
        {
            "ok": True,
            "range": {"days": range_days, "start_date": start_text, "end_date": today.isoformat()},
            "settings": {
                "tracking_url": _visitor_tracking_url_raw(),
                "tracking_path": _visitor_tracking_path(),
                "max_pages": max_pages,
            },
            "pagination": {
                "page": current_page,
                "page_size": page_size,
                "total_records": total_records,
                "total_pages": total_pages,
                "raw_total_pages": raw_total_pages,
                "max_pages": max_pages,
                "has_more_beyond_limit": raw_total_pages > max_pages,
                "kind": kind_norm,
            },
            "items": items,
        }
    )


@app.post("/api/admin/change-password")
def api_admin_change_password(request: Request, payload: AdminChangePasswordBody):
    """變更後台密碼：寫入 data/admin_panel_password.txt（優先於環境變數預設值）。"""
    _require_admin_password(request)
    global ADMIN_PANEL_PASSWORD
    new_p = payload.new_password.strip()
    if len(new_p) < 4:
        raise HTTPException(status_code=400, detail="新密碼過短")
    try:
        DATA_DIR.mkdir(parents=True, exist_ok=True)
        _ADMIN_PASSWORD_FILE.write_text(new_p + "\n", encoding="utf-8")
    except OSError as exc:
        raise HTTPException(status_code=500, detail=f"無法寫入密碼檔：{exc}") from exc
    ADMIN_PANEL_PASSWORD = new_p
    return JSONResponse({"ok": True, "message": "密碼已更新"})


