    return JSONResponse(
        {
            "ok": True,
            "session_id": sid,
            "delivery_mode": str(sent.get("_delivery_mode") or "direct_customer_chat"),
            "delivery_note": str(sent.get("_delivery_note") or ""),
            "sendMessage": sent.get("result"),
        }
    )


