@app.get("/api/admin/telegram-webhook-info")
def api_admin_telegram_webhook_info(
    request: Request,
    account_id: str = Query(default=""),
):
    _require_admin_password(request)
    aid_opt = str(account_id or "").strip() or None
    token, _ch = _telegram_credentials_for_optional_account(aid_opt)
    token = _normalize_telegram_bot_token(token)
    if not token or not _telegram_bot_token_format_ok(token):
        raise HTTPException(status_code=400, detail="請先儲存有效的 Bot Token（或選對顧問帳號）")
    try:
        with httpx.Client(timeout=18.0) as client:
            r = client.get(f"https://api.telegram.org/bot{token}/getWebhookInfo")
        tg = r.json()
    except Exception as exc:
        raise HTTPException(status_code=502, detail=str(exc)[:200]) from exc
    base = (get_effective_site_url() or "").strip().rstrip("/")
    secret = get_kv("telegram_webhook_secret", "").strip()
    acc_slug = ""
    if aid_opt:
        acc_slug = "/" + _sanitize_telegram_account_id(aid_opt)
    elif base:
        acc_slug = "/" + _telegram_get_active_account_id()
    return JSONResponse(
        {
            "ok": True,
            "site_url": base,
            "account_id": _sanitize_telegram_account_id(aid_opt) if aid_opt else _telegram_get_active_account_id(),
            "webhook_url_suggested": f"{base}/api/telegram/webhook{acc_slug}" if base else "",
            "webhook_url_legacy": f"{base}/api/telegram/webhook" if base else "",
            "webhook_secret_configured": bool(secret),
            "telegram": tg,
        }
    )


@app.post("/api/admin/telegram-register-webhook")
def api_admin_telegram_register_webhook(payload: TelegramWebhookRegisterBody, request: Request):
    """向 Telegram 註冊 HTTPS Webhook，並產生／沿用 secret_token（寫入 app_kv）。"""
    _require_admin_password(request)
    aid_opt = str(payload.account_id or "").strip() or None
    token, _c = _telegram_credentials_for_optional_account(aid_opt)
    token = _normalize_telegram_bot_token(token)
    if not token or not _telegram_bot_token_format_ok(token):
        raise HTTPException(status_code=400, detail="請先儲存有效的 Bot Token（或選對顧問帳號）")
    base = (payload.public_base_url or get_effective_site_url() or "").strip().rstrip("/")
    if not base.startswith("https://"):
        raise HTTPException(
            status_code=400,
            detail="需公開 HTTPS 網址（例：https://your-domain.com）。本機請用內網穿透取得 HTTPS 後再註冊。",
        )
    secret = get_kv("telegram_webhook_secret", "").strip()
    if not secret or len(secret) < 12:
        secret = uuid4().hex + uuid4().hex
        set_kv("telegram_webhook_secret", secret[:256])
        secret = get_kv("telegram_webhook_secret", "").strip()
    acc_part = ""
    if aid_opt:
        acc_part = "/" + _sanitize_telegram_account_id(aid_opt)
    else:
        acc_part = "/" + _telegram_get_active_account_id()
    wh_url = f"{base}/api/telegram/webhook{acc_part}"
    try:
        with httpx.Client(timeout=28.0) as client:
            r = client.post(
                f"https://api.telegram.org/bot{token}/setWebhook",
                data={"url": wh_url, "secret_token": secret[:256]},
            )
        info = r.json()
    except Exception as exc:
        raise HTTPException(status_code=502, detail=str(exc)[:300]) from exc
    if not isinstance(info, dict) or not info.get("ok"):
        desc = ""
        if isinstance(info, dict):
            desc = str(info.get("description") or info)[:500]
        raise HTTPException(status_code=400, detail=desc or "setWebhook 失敗")
    return JSONResponse(
        {
            "ok": True,
            "webhook_url": wh_url,
            "account_id": _sanitize_telegram_account_id(aid_opt) if aid_opt else _telegram_get_active_account_id(),
            "secret_token_length": len(secret[:256]),
            "telegram_response": info,
        }
    )


_INTEREST_PICK_MARKER = "【留單勾選諮詢案件】"


def _interest_pick_line_count_from_note(note: str | None) -> int:
    """When `support_session_case_interest` has no rows, infer count from merged留單 note text."""
    text = (note or "").strip()
    if _INTEREST_PICK_MARKER not in text:
        return 0
    tail = text.split(_INTEREST_PICK_MARKER, 1)[1].strip()
    m = re.search(r"(?m)^【", tail)
    if m:
        tail = tail[: m.start()]
    return len([ln for ln in tail.splitlines() if ln.strip()])


def _effective_handoff_interest_count(note: str | None, db_count: int) -> int:
    return max(int(db_count or 0), _interest_pick_line_count_from_note(note))


@app.get("/api/admin/handoff-requests")
def api_admin_handoff_requests(
    request: Request,
    q: str = Query(default="", description="模糊查詢：姓名/電話/信箱/備註/Session/動作/場景/對話/AI整理"),
    page: int = Query(default=1, ge=1),
    page_size: int = Query(default=25, ge=5, le=100),
):
    _require_admin_password(request)
    page_size = min(100, max(5, int(page_size)))
    page = max(1, int(page))
    offset = (page - 1) * page_size
    with get_conn() as conn:
        qc = (q or "").strip()
        where_sql = "1=1"
        params: list[Any] = []
        if qc:
            like = f"%{qc}%"
            where_sql = (
                "("
                + " OR ".join(
                    [
                        "name LIKE ?",
                        "phone LIKE ?",
                        "email LIKE ?",
                        "note LIKE ?",
                        "action_id LIKE ?",
                        "session_id LIKE ?",
                        "matched_scene_label LIKE ?",
                        "matched_scene_id LIKE ?",
                        "context_message LIKE ?",
                        "opinion LIKE ?",
                        "ai_handoff_summary LIKE ?",
                        "conversation_json LIKE ?",
                    ]
                )
                + ")"
            )
            params.extend([like] * 12)

        total = int(
            conn.execute(f"SELECT COUNT(1) AS c FROM human_handoff_requests WHERE {where_sql}", params).fetchone()["c"]
        )
        rows = conn.execute(
            f"""
            SELECT
              id, name, phone, email, note, user_agent,
              action_id, session_id, matched_scene_id, matched_scene_label,
              (
                SELECT COUNT(1)
                FROM support_session_case_interest i
                WHERE i.session_id = human_handoff_requests.session_id
              ) AS interested_case_count,
              COALESCE(LENGTH(conversation_json), 0) AS conversation_chars,
              created_at
            FROM human_handoff_requests
            WHERE {where_sql}
            ORDER BY created_at DESC, id DESC
            LIMIT ? OFFSET ?
            """,
            (*params, page_size, offset),
        ).fetchall()
    items = []
    for r in rows:
        d = dict(r)
        full_note = d.get("note") or ""
        db_ic = int(d.get("interested_case_count") or 0)
        items.append(
            {
                "id": d.get("id"),
                "name": (d.get("name") or "")[:80],
                "phone": (d.get("phone") or "")[:40],
                "email": (d.get("email") or "")[:80],
                "note": full_note[:120],
                "action_id": d.get("action_id") or "",
                "session_id": d.get("session_id") or "",
                "matched_scene_label": d.get("matched_scene_label") or "",
                "matched_scene_id": d.get("matched_scene_id") or "",
                "interested_case_count": _effective_handoff_interest_count(full_note, db_ic),
                "conversation_chars": int(d.get("conversation_chars") or 0),
                "created_at": d.get("created_at") or "",
            }
        )
    return JSONResponse({"ok": True, "total": total, "page": page, "page_size": page_size, "items": items})


@app.get("/api/admin/handoff-requests/{handoff_id}")
def api_admin_handoff_request_detail(handoff_id: int, request: Request):
    _require_admin_password(request)
    hid = int(handoff_id)
    case_rows: list[dict[str, Any]] = []
    staff_rows: list[dict[str, Any]] = []
    _ensure_support_channel_tables()
    with get_conn() as conn:
        row = conn.execute(
            """
            SELECT
              id, name, phone, email, note, user_agent,
              action_id, session_id, matched_scene_id, matched_scene_label,
              context_message, opinion, questionnaire_json, conversation_json,
              scenario_weights_json, ai_handoff_summary, created_at
            FROM human_handoff_requests
            WHERE id = ?
            LIMIT 1
            """,
            (hid,),
        ).fetchone()
        if row:
            sid = str(row["session_id"] or "").strip()[:120]
            if sid:
                _ensure_support_case_interest_table(conn)
                case_rows = [
                    _interest_case_row_with_derived_article_url(dict(r))
                    for r in conn.execute(
                        """
                        SELECT
                          case_key, source_item_id, content_id, title, source_name,
                          item_url, article_url, transaction_label_zh, jp_region_display_zh,
                          transit_line_zh, price_text_hant, layout_text_hant, area_text_hant, building_type_zh,
                        updated_at
                      FROM support_session_case_interest
                      WHERE session_id = ?
                      ORDER BY updated_at DESC, id DESC
                      LIMIT 30
                      """,
                      (sid,),
                  ).fetchall()
                ]
                try:
                    staff_rows = [
                        dict(r)
                        for r in conn.execute(
                            """
                            SELECT id, body, source_channel, source_from_id, created_at
                            FROM support_staff_inbox
                            WHERE session_id = ?
                            ORDER BY id DESC
                            LIMIT 80
                            """,
                            (sid,),
                        ).fetchall()
                    ]
                except Exception:
                    staff_rows = []
    if not row:
        raise HTTPException(status_code=404, detail="handoff not found")
    d = dict(row)
    conv: list = []
    raw_c = str(d.get("conversation_json") or "").strip()
    if raw_c:
        try:
            conv = json.loads(raw_c)
            if not isinstance(conv, list):
                conv = []
        except Exception:
            conv = []
    d.pop("conversation_json", None)
    d["conversation"] = conv
    sw_raw = str(d.pop("scenario_weights_json", "") or "").strip()
    sw: list = []
    if sw_raw:
        try:
            sw = json.loads(sw_raw)
            if not isinstance(sw, list):
                sw = []
        except Exception:
            sw = []
    d["scenario_weights"] = sw
    q_raw = str(d.pop("questionnaire_json", "") or "").strip()
    q_obj: dict[str, Any] = {}
    if q_raw:
        try:
            q_obj = json.loads(q_raw)
            if not isinstance(q_obj, dict):
                q_obj = {}
        except Exception:
            q_obj = {}
    d["questionnaire"] = q_obj
    d["interested_cases"] = case_rows
    d["staff_inbox"] = list(reversed(staff_rows))
    sid = _normalize_support_session_id(str(d.get("session_id") or ""))
    d["thread_channels"] = {
        "telegram": bool(sid and _support_session_has_telegram_thread(sid)),
        "line": bool(sid and _support_session_has_line_thread(sid)),
        "web": bool(sid),
    }
    d["staff_reply_count"] = len(staff_rows)
    return JSONResponse({"ok": True, "item": d})


@app.put("/api/admin/handoff-requests/{handoff_id}")
def api_admin_handoff_request_update(handoff_id: int, payload: AdminHandoffUpdateRequest, request: Request):
    _require_admin_password(request)
    hid = int(handoff_id)
    fields = {
        "name": (payload.name or "").strip()[:120],
        "phone": (payload.phone or "").strip()[:80],
        "email": (payload.email or "").strip()[:160],
        "note": (payload.note or "").strip()[:2000],
        "action_id": (payload.action_id or "").strip()[:80],
        "matched_scene_id": (payload.matched_scene_id or "").strip()[:80],
        "matched_scene_label": (payload.matched_scene_label or "").strip()[:160],
        "context_message": (payload.context_message or "").strip()[:2000],
        "opinion": (payload.opinion or "").strip()[:2000],
    }
    with get_conn() as conn:
        exists = conn.execute("SELECT id FROM human_handoff_requests WHERE id = ? LIMIT 1", (hid,)).fetchone()
        if not exists:
            raise HTTPException(status_code=404, detail="handoff not found")
        conn.execute(
            """
            UPDATE human_handoff_requests
            SET name = ?, phone = ?, email = ?, note = ?, action_id = ?,
                matched_scene_id = ?, matched_scene_label = ?, context_message = ?, opinion = ?
            WHERE id = ?
            """,
            (
                fields["name"],
                fields["phone"],
                fields["email"],
                fields["note"],
                fields["action_id"],
                fields["matched_scene_id"],
                fields["matched_scene_label"],
                fields["context_message"],
                fields["opinion"],
                hid,
            ),
        )
        conn.commit()
    return JSONResponse({"ok": True, "id": hid, "item": fields})


def _admin_send_handoff_reply(
    *,
    session_id: str,
    message: str,
    preferred_channel: str = "auto",
    sender_name: str = "人工客服",
) -> dict[str, Any]:
    sid = _normalize_support_session_id(session_id)
    if not sid:
        raise RuntimeError("missing session_id")
    text = sanitize_support_chat_visible_reply(str(message or "").strip())[:4000].strip()
    if not text:
        raise RuntimeError("missing message")
    channel = str(preferred_channel or "auto").strip().lower()
    if channel not in {"auto", "web", "telegram", "line"}:
        channel = "auto"
    line_ready = _support_session_has_line_thread(sid)
    telegram_ready = _support_session_has_telegram_thread(sid)
    attempts: list[dict[str, str]] = []

    def _send_web() -> dict[str, Any]:
        ok = _insert_support_staff_inbox_message(
            sid,
            text,
            source_channel="admin",
            source_from_id=(sender_name or "admin_console")[:120],
        )
        if not ok:
            raise RuntimeError("write support_staff_inbox failed")
        return {
            "delivery_mode": "web_chat",
            "delivery_note": "written_to_support_staff_inbox",
            "channel_used": "web",
        }

    def _record_external_reply(channel_name: str) -> None:
        ok = _insert_support_staff_inbox_message(
            sid,
            text,
            source_channel=channel_name,
            source_from_id=(sender_name or "admin_console")[:120],
        )
        if not ok:
            raise RuntimeError("write support_staff_inbox failed after external send")

    send_order: list[str]
    if channel == "line":
        send_order = ["line", "web"]
    elif channel == "telegram":
        send_order = ["telegram", "web"]
    elif channel == "web":
        send_order = ["web"]
    else:
        send_order = []
        if line_ready:
            send_order.append("line")
        if telegram_ready and "telegram" not in send_order:
            send_order.append("telegram")
        send_order.append("web")

    for target in send_order:
        try:
            if target == "line":
                sent = _line_send_by_session(sid, text)
                if str(sent.get("_delivery_mode") or "") == "direct_customer_line":
                    _record_external_reply("line")
                return {
                    "channel_used": "line",
                    "delivery_mode": str(sent.get("_delivery_mode") or "direct_customer_line"),
                    "delivery_note": str(sent.get("_delivery_note") or ""),
                }
            if target == "telegram":
                sent = _telegram_send_by_session(sid, text)
                if str(sent.get("_delivery_mode") or "") == "direct_customer_chat":
                    _record_external_reply("telegram")
                return {
                    "channel_used": "telegram",
                    "delivery_mode": str(sent.get("_delivery_mode") or "direct_customer_chat"),
                    "delivery_note": str(sent.get("_delivery_note") or ""),
                }
            return _send_web()
        except Exception as exc:
            attempts.append({"channel": target, "error": str(exc)[:300]})
            continue

    detail = "；".join(f"{row['channel']}：{row['error']}" for row in attempts if row.get("error"))
    raise RuntimeError(detail or "reply failed")


@app.post("/api/admin/handoff-requests/{handoff_id}/reply")
def api_admin_handoff_request_reply(handoff_id: int, payload: AdminHandoffReplyRequest, request: Request):
    _require_admin_password(request)
    hid = int(handoff_id)
    with get_conn() as conn:
        row = conn.execute(
            """
            SELECT id, session_id
            FROM human_handoff_requests
            WHERE id = ?
            LIMIT 1
            """,
            (hid,),
        ).fetchone()
    if not row:
        raise HTTPException(status_code=404, detail="handoff not found")
    sid = _normalize_support_session_id(str(row["session_id"] or ""))
    if not sid:
        raise HTTPException(status_code=400, detail="handoff session missing")
    try:
        sent = _admin_send_handoff_reply(
            session_id=sid,
            message=payload.message,
            preferred_channel=payload.channel,
            sender_name=payload.sender_name or "人工客服",
        )
    except Exception as exc:
        raise HTTPException(status_code=400, detail=str(exc)[:400]) from exc
    return JSONResponse({"ok": True, "handoff_id": hid, "session_id": sid, "reply": sent})


@app.delete("/api/admin/handoff-requests/{handoff_id}")
def api_admin_handoff_request_delete(handoff_id: int, request: Request):
    _require_admin_password(request)
    hid = int(handoff_id)
    session_id = ""
    deleted_interest_case_count = 0
    with get_conn() as conn:
        row = conn.execute(
            """
            SELECT id, session_id
            FROM human_handoff_requests
            WHERE id = ?
            LIMIT 1
            """,
            (hid,),
        ).fetchone()
        if not row:
            raise HTTPException(status_code=404, detail="handoff not found")
        session_id = str(row["session_id"] or "").strip()[:120]
        cur = conn.execute("DELETE FROM human_handoff_requests WHERE id = ?", (hid,))
        if cur.rowcount == 0:
            raise HTTPException(status_code=404, detail="handoff not found")
        if session_id:
            remain = int(
                conn.execute(
                    "SELECT COUNT(1) AS c FROM human_handoff_requests WHERE session_id = ?",
                    (session_id,),
                ).fetchone()["c"]
            )
            if remain <= 0:
                _ensure_support_case_interest_table(conn)
                deleted_interest_case_count = int(
                    conn.execute(
                        "DELETE FROM support_session_case_interest WHERE session_id = ?",
                        (session_id,),
                    ).rowcount
                    or 0
                )
        conn.commit()
    return JSONResponse(
        {
            "ok": True,
            "deleted_id": hid,
            "session_id": session_id,
            "deleted_interest_case_count": deleted_interest_case_count,
        }
    )


def _admin_cases_where_params(
    *,
    q: str,
    transaction: str,
    region_code: str,
    jp_area: str,
    jp_line_id: int = 0,
    jp_station_id: int = 0,
    walk_max: int = 0,
) -> tuple[str, list[Any]]:
    parts: list[str] = ["1=1"]
    params: list[Any] = []
    tx_sql, tx_params = _admin_cases_transaction_sql_clause(transaction)
    parts.append(f"({tx_sql})")
    params.extend(tx_params)
    rc = (region_code or "").strip()
    if rc:
        parts.append("c.region_code = ?")
        params.append(rc)
    ja = (jp_area or "").strip()
    if ja:
        region_keys = _admin_cases_region_index_keys(ja)
        if region_keys:
            placeholders = ",".join("?" for _ in region_keys)
            parts.append(
                "c.source_item_id IN ("
                "SELECT source_item_id FROM jp_listing_region_index "
                f"WHERE region_key IN ({placeholders})"
                ")"
            )
            params.extend(region_keys)
        else:
            like = f"%{ja}%"
            parts.append(
                "("
                "c.title_zh_hant LIKE ? OR c.title_zh_hans LIKE ? OR c.body_zh_hant LIKE ? OR "
                "c.body_zh_hans LIKE ? OR s.title_original LIKE ?"
                ")"
            )
            params.extend([like, like, like, like, like])
    sid = max(0, int(jp_station_id or 0))
    if sid > 0:
        parts.append("c.jp_station_id = ?")
        params.append(sid)
    lid = max(0, int(jp_line_id or 0))
    if lid > 0 and sid <= 0:
        parts.append("c.jp_station_id IN (SELECT station_id FROM jp_trans_station WHERE line_id = ?)")
        params.append(lid)
    wmax = max(0, int(walk_max or 0))
    if wmax > 0:
        parts.append("(COALESCE(c.walk_min,0) = 0 OR COALESCE(c.walk_min,0) <= ?)")
        params.append(wmax)
    qc = (q or "").strip()
    if qc:
        fts_q = _admin_cases_fts_match_query(qc)
        if fts_q:
            parts.append(
                "("
                "c.id IN (SELECT rowid FROM content_fts WHERE content_fts MATCH ?) OR "
                "c.source_item_id IN (SELECT rowid FROM source_fts WHERE source_fts MATCH ?)"
                ")"
            )
            params.extend([fts_q, fts_q])
        else:
            like = f"%{qc}%"
            parts.append(
                "("
                "c.title_zh_hant LIKE ? OR c.title_zh_hans LIKE ? OR s.title_original LIKE ? OR s.item_url LIKE ?"
                ")"
            )
            params.extend([like, like, like, like])
    return " AND ".join(parts), params


def _admin_cases_fts_match_query(raw: str) -> str:
    tokens = re.findall(r"[A-Za-z0-9_@./:+-]+|[\u3040-\u30ff\u3400-\u9fff]+", str(raw or ""))
    out: list[str] = []
    for tok in tokens[:8]:
        t = tok.strip().replace('"', '""')
        if t and t not in out:
            out.append(f'"{t}"')
    return " OR ".join(out)


def _admin_cases_transaction_sql_clause(side: str) -> tuple[str, list[Any]]:
    s = (side or "").strip().lower()
    if s == "buy":
        return (
            "s.content_kind = 'jp_listing' "
            "AND instr(lower(COALESCE(s.item_url,'')), ?) = 0 "
            "AND instr(lower(COALESCE(s.item_url,'')), ?) = 0",
            ["chintai", "/chintai"],
        )
    if s == "rent":
        return (
            "s.content_kind = 'jp_listing' "
            "AND (instr(lower(COALESCE(s.item_url,'')), ?) > 0 "
            "OR instr(lower(COALESCE(s.item_url,'')), ?) > 0)",
            ["chintai", "/chintai"],
        )
    return transaction_sql_clause(side)


def _admin_cases_region_index_keys(raw: str) -> list[str]:
    s = str(raw or "").strip()
    if not s:
        return []
    candidates = [s]
    if any(sep in s for sep in ("・", "/", "／", "、", ",")):
        candidates.extend(x.strip() for x in re.split(r"[・/／、,]+", s) if x.strip())
    if s in ("甲信越・北陸", "甲信越/北陸", "甲信越／北陸"):
        candidates.extend(["甲信越", "北陸"])
    out: list[str] = []
    for cand in candidates:
        key = normalize_region_index_search_key(cand)
        if key in REGION_INDEX_SEARCH_KEYS and key not in out:
            out.append(key)
    return out


def _admin_cases_filter_needs_source_join(
    *,
    q: str,
    transaction: str,
    jp_area: str,
) -> bool:
    """Whether the admin case filter references source_items columns."""
    if (q or "").strip() and not _admin_cases_fts_match_query(q):
        return True
    if (jp_area or "").strip() and not _admin_cases_region_index_keys(jp_area):
        return True
    return (transaction or "").strip().lower() in ("buy", "rent")


