@app.post("/api/admin/cases/audit-gallery-images")
def api_admin_cases_audit_gallery_images(payload: AdminGalleryImageAuditPost, request: Request):
    """Classify listing gallery images and flag polluted/unrelated images."""
    _require_admin_password(request)
    lim = max(1, min(80, int(payload.limit or 24)))
    off = max(0, min(500000, int(payload.offset or 0)))
    sql_extra = ""
    force_reaudit = bool(payload.force_reaudit)
    remove_low_quality = bool(payload.remove_low_quality)
    if bool(payload.only_missing) and not force_reaudit:
        sql_extra = "AND a.source_item_id IS NULL"
    with get_conn() as conn:
        rows = conn.execute(
            f"""
            SELECT
                c.id AS content_id,
                c.source_item_id,
                c.seo_title,
                c.title_zh_hant,
                c.title_zh_hans,
                c.case_jp_region_override,
                c.listing_media_json,
                c.topic_category,
                s.id,
                s.source_name,
                s.source_category,
                s.item_url,
                s.title_original,
                substr(COALESCE(s.body_original, ''), 1, 50000) AS body_original,
                s.image_urls,
                s.thumbnail_url,
                s.hero_image_url,
                s.last_checked_at
            FROM content_items c
            JOIN source_items s ON s.id = c.source_item_id
            LEFT JOIN (
                SELECT source_item_id, COUNT(1) AS audit_count
                FROM case_gallery_image_audit
                GROUP BY source_item_id
            ) a ON a.source_item_id = s.id
            WHERE COALESCE(s.content_kind, '') = 'jp_listing'
              AND (
                TRIM(COALESCE(s.hero_image_url, '')) <> ''
                OR TRIM(COALESCE(s.thumbnail_url, '')) <> ''
                OR TRIM(COALESCE(s.image_urls, '')) <> ''
                OR TRIM(COALESCE(c.listing_media_json, '')) NOT IN ('', '[]')
              )
              {sql_extra}
            ORDER BY c.updated_at DESC, c.id DESC
            LIMIT ? OFFSET ?
            """,
            (lim, off),
        ).fetchall()
    results: list[dict[str, Any]] = []
    ok_count = 0
    polluted_count = 0
    low_quality_count = 0
    removed_count = 0
    for row in rows:
        d = dict(row)
        try:
            res = _case_audit_gallery_images_for_row(
                d,
                limit=80,
                remove_low_quality=remove_low_quality,
            )
        except Exception as exc:
            _log_backend_error("case-gallery-audit-batch", exc)
            res = {
                "ok": False,
                "source_item_id": int(d.get("source_item_id") or d.get("id") or 0),
                "reason": f"{type(exc).__name__}: {str(exc)[:180]}",
            }
        if bool(res.get("ok")):
            ok_count += 1
            polluted_count += int(res.get("polluted") or 0)
            low_quality_count += int(res.get("low_quality") or 0)
            removed_count += int(res.get("removed") or 0)
        results.append(res)
    if removed_count > 0:
        with _HOME_FEATURED_CASES_CACHE_LOCK:
            _HOME_FEATURED_CASES_CACHE.clear()
        _portal_case_search_cache_clear()
    return JSONResponse(
        {
            "ok": True,
            "processed": len(results),
            "classified_cases": ok_count,
            "polluted_images": polluted_count,
            "low_quality_images": low_quality_count,
            "removed_images": removed_count,
            "offset": off,
            "limit": lim,
            "only_missing": bool(payload.only_missing) and not force_reaudit,
            "force_reaudit": force_reaudit,
            "remove_low_quality": remove_low_quality,
            "gemini_configured": is_gemini_configured(),
            "results": results,
        }
    )


@app.post("/api/admin/cases/{content_id}/representative-image")
def api_admin_case_set_representative_image(content_id: int, payload: AdminRepresentativeImageManualPost, request: Request):
    """Manually bind a case card representative image from the listing's existing gallery."""
    _require_admin_password(request)
    cid = int(content_id)
    selected = str(payload.image_url or "").strip()
    with get_conn() as conn:
        row = conn.execute(
            """
            SELECT
              c.id AS content_id,
              c.source_item_id,
              c.seo_title,
              c.seo_description,
              c.title_zh_hant,
              c.title_zh_hans,
              c.body_zh_hant,
              c.body_zh_hans,
              c.topic_category,
              COALESCE(c.listing_media_json, '[]') AS listing_media_json,
              s.id,
              s.source_name,
              s.source_category,
              s.item_url,
              s.title_original,
              s.body_original,
              s.image_urls,
              s.thumbnail_url,
              s.hero_image_url,
              s.last_checked_at
            FROM content_items c
            JOIN source_items s ON s.id = c.source_item_id
            WHERE c.id = ?
            LIMIT 1
            """,
            (cid,),
        ).fetchone()
    if not row:
        raise HTTPException(status_code=404, detail="case not found")
    d = dict(row)
    sid = int(d.get("source_item_id") or d.get("id") or 0)
    candidates = _case_admin_representative_candidate_urls(d, limit=160)
    if not _case_representative_url_matches_candidate(selected, candidates):
        raise HTTPException(status_code=400, detail="image_url must be one of this case's existing gallery images")
    static_url = _case_static_url_for_manual_representative(selected)
    if not static_url or not _url_to_local_static_path(static_url):
        raise HTTPException(status_code=400, detail="selected image could not be cached locally")
    reject_reason = _case_image_visual_reject_reason(static_url)
    if reject_reason:
        raise HTTPException(status_code=400, detail=f"selected image failed visual validation: {reject_reason}")
    backup_urls: list[str] = []
    backup_static_urls: list[str] = []
    selected_norm = _normalize_listing_image_url_for_display(selected) if selected.lower().startswith(("http://", "https://")) else selected
    for cand in candidates:
        if cand == selected or cand == selected_norm:
            continue
        cand_static = _case_static_url_for_manual_representative(cand) if cand.startswith("/static/") else _case_image_cached_static_url(cand)
        if not cand_static or not _url_to_local_static_path(cand_static):
            continue
        if _case_image_visual_reject_reason(cand_static):
            continue
        backup_urls.append(cand)
        backup_static_urls.append(cand_static)
        if len(backup_static_urls) >= 3:
            break
    _case_store_representative_image(
        source_item_id=sid,
        representative_url=selected,
        representative_static_url=static_url,
        backup_urls=backup_urls,
        backup_static_urls=backup_static_urls,
        image_signature=_case_representative_image_signature(candidates),
        provider="manual",
        model="admin",
        status="manual",
        score=100,
        reason="Manual representative image selected by admin from existing gallery.",
        source_last_checked_at=str(d.get("last_checked_at") or ""),
    )
    with _HOME_FEATURED_CASES_CACHE_LOCK:
        _HOME_FEATURED_CASES_CACHE.clear()
    _portal_case_search_cache_clear()
    return JSONResponse(
        {
            "ok": True,
            "content_id": cid,
            "source_item_id": sid,
            "representative_url": selected,
            "representative_static_url": static_url,
            "backup_count": len(backup_static_urls),
            "status": "manual",
        }
    )


_BLOCKED_SOURCE_SQL = """
(
  COALESCE(s.title_original,'') LIKE '%認証中%'
  OR COALESCE(s.title_original,'') LIKE '%認證中%'
  OR COALESCE(s.title_original,'') LIKE '%认证中%'
  OR COALESCE(s.body_original,'') LIKE '%Click to verify%'
  OR COALESCE(s.body_original,'') LIKE '%click to verify%'
  OR COALESCE(s.body_original,'') LIKE '%captcha%'
  OR COALESCE(s.body_original,'') LIKE '%human verification%'
  OR COALESCE(s.body_original,'') LIKE '%awswaf%'
  OR COALESCE(s.body_original,'') LIKE '%通常のサイト閲覧を超える速度%'
)
"""


def _admin_cleanup_invalid_source_cache(payload: AdminCleanupInvalidSourcePost) -> dict[str, Any]:
    lim = max(1, min(5000, int(payload.limit or 500)))
    host_filter = _parse_host_filter_csv(str(payload.hosts or ""))
    host_sql = ""
    params: list[Any] = []
    if host_filter:
        clauses: list[str] = []
        for host in sorted(host_filter):
            clauses.append("lower(s.item_url) LIKE ?")
            params.append(f"%{host.lower()}%")
        host_sql = " AND (" + " OR ".join(clauses) + ")"
    select_sql = f"""
        SELECT s.id, s.source_name, s.item_url, s.title_original,
               length(COALESCE(s.image_urls,'')) AS image_len,
               COALESCE(s.access_status,'public') AS access_status,
               c.id AS content_id
        FROM source_items s
        LEFT JOIN content_items c ON c.source_item_id = s.id
        WHERE {_BLOCKED_SOURCE_SQL}
          {host_sql}
        ORDER BY s.last_checked_at DESC, s.id DESC
        LIMIT ?
    """
    with get_conn() as conn:
        rows = [dict(r) for r in conn.execute(select_sql, (*params, lim)).fetchall()]
        total_row = conn.execute(
            f"""
            SELECT COUNT(1) AS c
            FROM source_items s
            WHERE {_BLOCKED_SOURCE_SQL}
              {host_sql}
            """,
            params,
        ).fetchone()
        total = int(total_row["c"] if total_row else 0)
        if not payload.dry_run and rows:
            now = datetime.now(timezone.utc).isoformat()
            source_ids = [int(r["id"]) for r in rows if int(r.get("id") or 0) > 0]
            for sid in source_ids:
                conn.execute(
                    """
                    UPDATE source_items
                    SET title_original = ?,
                        body_original = '',
                        access_status = 'restricted',
                        access_note = ?,
                        last_checked_at = ?
                    WHERE id = ?
                    """,
                    (
                        f"原站資料待重新抓取（source #{sid}）",
                        "原站曾回傳驗證／認證頁，已清理失效快取；請執行原站補抓後再公開展示。",
                        now,
                        sid,
                    ),
                )
                conn.execute(
                    """
                    UPDATE content_items
                    SET title_zh_hant = CASE
                            WHEN title_zh_hant LIKE '%認証中%' OR title_zh_hant LIKE '%認證中%' OR title_zh_hant LIKE '%认证中%'
                            THEN '原站資料待重新抓取'
                            ELSE title_zh_hant
                        END,
                        title_zh_hans = CASE
                            WHEN title_zh_hans LIKE '%認証中%' OR title_zh_hans LIKE '%認證中%' OR title_zh_hans LIKE '%认证中%'
                            THEN '原站资料待重新抓取'
                            ELSE title_zh_hans
                        END,
                        body_zh_hant = CASE
                            WHEN body_zh_hant LIKE '%認証中%' OR body_zh_hant LIKE '%Click to verify%' OR body_zh_hant LIKE '%通常のサイト閲覧を超える速度%'
                            THEN '原站曾回傳驗證／認證頁，這筆資料已清理並標記為待重新抓取。請在後台執行原站補抓，成功取得真實詳情後再公開展示。'
                            ELSE body_zh_hant
                        END,
                        body_zh_hans = CASE
                            WHEN body_zh_hans LIKE '%認証中%' OR body_zh_hans LIKE '%Click to verify%' OR body_zh_hans LIKE '%通常のサイト閲覧を超える速度%'
                            THEN '原站曾返回验证／认证页，这笔资料已清理并标记为待重新抓取。请在后台执行原站补抓，成功取得真实详情后再公开展示。'
                            ELSE body_zh_hans
                        END,
                        listing_media_json = CASE
                            WHEN listing_media_json LIKE '%認証中%' OR listing_media_json LIKE '%Click to verify%'
                            THEN '[]'
                            ELSE listing_media_json
                        END,
                        updated_at = ?
                    WHERE source_item_id = ?
                    """,
                    (now, sid),
                )
            conn.commit()
    return {
        "ok": True,
        "dry_run": bool(payload.dry_run),
        "total_matched": total,
        "processed_rows": len(rows),
        "updated_rows": 0 if payload.dry_run else len(rows),
        "hosts": sorted(host_filter) if host_filter else None,
        "sample": rows[:12],
        "message": "dry-run only" if payload.dry_run else "invalid source cache cleaned",
    }


