@app.post("/api/admin/cases/enrich-from-source")
def api_admin_case_enrich_from_source(payload: AdminCaseEnrichFromSourcePost, request: Request):
    """依 source_item_id 向原站重抓並合併 image_urls／body／title（七大門戶等 live_enrich 白名單）。"""
    _require_admin_password(request)
    from src.thumb_backfill_service import enrich_single_source_item_by_id

    out = enrich_single_source_item_by_id(
        int(payload.source_item_id),
        force=bool(payload.force),
        dry_run=bool(payload.dry_run),
    )
    if not out.get("ok"):
        raise HTTPException(status_code=400, detail=str(out.get("error") or "enrich failed"))
    media_fix: dict[str, Any] = {}
    text_fix: dict[str, Any] = {}
    if not bool(payload.dry_run):
        try:
            media_fix = _sync_case_listing_media_from_source_item_id(
                int(payload.source_item_id),
                force=True,
                dry_run=False,
            )
        except Exception as exc:
            media_fix = {"ok": False, "error": f"{type(exc).__name__}: {exc}"}
        try:
            text_fix = _repair_case_text_fields_from_source_item_id(int(payload.source_item_id), dry_run=False)
        except Exception as exc:
            text_fix = {"ok": False, "error": f"{type(exc).__name__}: {exc}"}
    bot_eval = _build_data_completion_bot_eval(
        age_days=180,
        threshold_per_cell=15,
        source_item_id=int(payload.source_item_id),
        media_fix=media_fix,
        text_fix=text_fix,
    )
    try:
        _save_data_completion_bot_eval(
            run_label="case_enrich_from_source",
            source_item_id=int(payload.source_item_id),
            bot_eval=bot_eval,
        )
    except Exception:
        pass
    return JSONResponse({**out, "media_fix": media_fix, "text_fix": text_fix, "data_completion_bot": bot_eval})


@app.post("/api/cases/enrich-from-source")
def api_cases_enrich_from_source_no_admin(payload: AdminCaseEnrichFromSourcePost, request: Request):
    """與 POST /api/admin/cases/enrich-from-source 相同。"""
    return api_admin_case_enrich_from_source(payload, request)


@app.post("/api/cases-dashboard/enrich-from-source")
def api_cases_dashboard_enrich_from_source_alias(payload: AdminCaseEnrichFromSourcePost, request: Request):
    return api_admin_case_enrich_from_source(payload, request)


def _norm_case_tx_override(val: str | None) -> str | None:
    if val is None:
        return None
    s = str(val).strip().lower()
    if s in ("", "buy", "sell", "rent"):
        return s
    raise HTTPException(
        status_code=400,
        detail="case_transaction_override must be one of: buy, sell, rent, or empty string",
    )


@app.get("/api/admin/cases")
def api_admin_cases(
    request: Request,
    page: int = Query(default=1, ge=1),
    page_size: int = Query(default=20, ge=5, le=200),
    q: str = Query(default="", description="關鍵字（標題／內文／原文／網址）"),
    transaction: str = Query(
        default="",
        description="買賣租篩選：buy=買賣購屋、sell=賣出、rent=租賃、留空=全部",
    ),
    region_code: str = Query(default="", description="讀者地區代碼，如 tw"),
    jp_area: str = Query(default="", description="日本區域／地名關鍵字，如 甲信越、関東"),
    jp_line_id: int = Query(default=0, ge=0, description="jp_trans_line.line_id；與 jp_station_id 擇一或併用"),
    jp_station_id: int = Query(default=0, ge=0, description="jp_trans_station.station_id"),
    walk_max: int = Query(default=0, ge=0, le=240, description="徒步分鐘上限；0=不篩"),
):
    _require_admin_password(request)
    page_size = min(200, max(5, int(page_size)))
    page = max(1, int(page))
    offset = (page - 1) * page_size
    where_sql, base_params = _admin_cases_where_params(
        q=q,
        transaction=transaction,
        region_code=region_code,
        jp_area=jp_area,
        jp_line_id=jp_line_id,
        jp_station_id=jp_station_id,
        walk_max=walk_max,
    )
    needs_source_join = _admin_cases_filter_needs_source_join(q=q, transaction=transaction, jp_area=jp_area)
    fast_region_keys = _admin_cases_region_index_keys(jp_area)
    tx_side = (transaction or "").strip().lower()
    no_extra_admin_filters = not (q or "").strip() and not (region_code or "").strip() and int(jp_line_id or 0) <= 0 and int(jp_station_id or 0) <= 0 and int(walk_max or 0) <= 0
    use_region_index_page = bool(fast_region_keys) and no_extra_admin_filters and not tx_side
    use_source_tx_page = tx_side in ("buy", "rent") and no_extra_admin_filters and not (jp_area or "").strip()
    with get_conn() as conn:
        count_from_sql = (
            "content_items c JOIN source_items s ON s.id = c.source_item_id"
            if needs_source_join
            else "content_items c"
        )
        if use_region_index_page:
            placeholders = ",".join("?" for _ in fast_region_keys)
            total = int(
                conn.execute(
                    f"SELECT COUNT(DISTINCT source_item_id) AS c FROM jp_listing_region_index WHERE region_key IN ({placeholders})",
                    fast_region_keys,
                ).fetchone()["c"]
                or 0
            )
        else:
            total = int(
                conn.execute(
                    f"SELECT COUNT(1) AS c FROM {count_from_sql} WHERE {where_sql}",
                    base_params,
                ).fetchone()["c"]
            )
        admin_case_select_sql = """
            SELECT
              c.id AS content_id,
              c.source_item_id,
              c.seo_slug,
              c.title_zh_hant,
              c.title_zh_hans,
              c.seo_title,
              c.region_code,
              c.keyword_type,
              c.topic_category,
              substr(COALESCE(c.body_zh_hant,''),1,3200) AS body_zh_hant,
              substr(COALESCE(c.body_zh_hans,''),1,2000) AS body_zh_hans,
              c.updated_at,
              COALESCE(c.case_transaction_override, '') AS case_transaction_override,
              COALESCE(c.case_jp_region_override, '') AS case_jp_region_override,
              COALESCE(c.case_transit_override, '') AS case_transit_override,
              COALESCE(c.jp_station_id, 0) AS jp_station_id,
              COALESCE(c.walk_min, 0) AS walk_min,
              COALESCE(jst.station_name, '') AS jp_bind_station_name,
              COALESCE(jln.line_name, '') AS jp_bind_line_name,
              COALESCE(c.featured_weight, 0) AS featured_weight,
              COALESCE(c.listing_media_json, '[]') AS listing_media_json,
              s.id AS source_item_id,
              s.source_name,
              s.item_url,
              s.image_urls,
              substr(COALESCE(s.body_original,''),1,2000) AS body_original,
              s.title_original,
              COALESCE(NULLIF(TRIM(s.content_kind), ''), '') AS content_kind,
              COALESCE(r.representative_static_url, '') AS representative_static_url,
              COALESCE(r.status, '') AS representative_status,
              COALESCE(r.provider, '') AS representative_provider,
              COALESCE(r.score, 0) AS representative_score,
              COALESCE(r.reason, '') AS representative_reason,
              COALESCE(r.backup_static_urls_json, '[]') AS representative_backup_static_urls_json,
              COALESCE(ga.polluted_count, 0) AS gallery_polluted_count,
              COALESCE(ga.failed_polluted_count, 0) AS gallery_failed_polluted_count,
              COALESCE(ga.audit_count, 0) AS gallery_audit_count
        """
        admin_case_tail_sql = """
            LEFT JOIN jp_trans_station jst ON jst.station_id = c.jp_station_id
            LEFT JOIN jp_trans_line jln ON jln.line_id = jst.line_id
            LEFT JOIN case_representative_images r ON r.source_item_id = s.id
            LEFT JOIN (
                SELECT source_item_id,
                       COUNT(1) AS audit_count,
                       SUM(CASE WHEN is_polluted THEN 1 ELSE 0 END) AS polluted_count,
                       SUM(CASE WHEN is_polluted AND cleanup_attempts >= 3 THEN 1 ELSE 0 END) AS failed_polluted_count
                FROM case_gallery_image_audit
                GROUP BY source_item_id
            ) ga ON ga.source_item_id = s.id
        """
        if use_region_index_page:
            placeholders = ",".join("?" for _ in fast_region_keys)
            rows = conn.execute(
                f"""
                {admin_case_select_sql}
                FROM jp_listing_region_index rix INDEXED BY idx_jp_listing_region_sort
                JOIN content_items c ON c.source_item_id = rix.source_item_id
                JOIN source_items s ON s.id = rix.source_item_id
                {admin_case_tail_sql}
                WHERE rix.region_key IN ({placeholders})
                ORDER BY rix.sort_time DESC, rix.source_item_id DESC
                LIMIT ? OFFSET ?
                """,
                [*fast_region_keys, page_size, offset],
            ).fetchall()
        elif use_source_tx_page:
            tx_sql, tx_params = _admin_cases_transaction_sql_clause(tx_side)
            rows = conn.execute(
                f"""
                {admin_case_select_sql}
                FROM source_items s INDEXED BY idx_source_items_content_kind_last_checked
                JOIN content_items c ON c.source_item_id = s.id
                {admin_case_tail_sql}
                WHERE ({tx_sql})
                ORDER BY s.last_checked_at DESC, s.id DESC
                LIMIT ? OFFSET ?
                """,
                [*tx_params, page_size, offset],
            ).fetchall()
        else:
            rows = conn.execute(
                f"""
                {admin_case_select_sql}
                FROM content_items c
                JOIN source_items s ON s.id = c.source_item_id
                {admin_case_tail_sql}
                WHERE {where_sql}
                ORDER BY c.updated_at DESC, c.id DESC
                LIMIT ? OFFSET ?
                """,
                [*base_params, page_size, offset],
            ).fetchall()
    items: list[dict] = []
    for r in rows:
        d = dict(r)
        imgs, vids = extract_media_urls_from_row(d)
        meta = infer_case_metadata(d)
        lm = _parse_listing_media_field(d.get("listing_media_json"))
        thumb_candidates: list[str] = []

        def _append_thumb_candidate(u: str) -> None:
            s = str(u or "").strip()
            if not s or s in thumb_candidates:
                return
            if _row_image_url_is_usable(s):
                thumb_candidates.append(s)

        for u in imgs:
            _append_thumb_candidate(str(u))
        if lm:
            for m in lm:
                if not isinstance(m, dict):
                    continue
                u = str(m.get("url") or "").strip()
                if u.startswith("http"):
                    _append_thumb_candidate(u)
        thumb = thumb_candidates[0] if thumb_candidates else ""
        stored_thumb = _case_stored_representative_static_url(d, thumb_candidates)
        if stored_thumb:
            thumb = stored_thumb
            thumb_candidates = [stored_thumb, *[u for u in thumb_candidates if u != stored_thumb]]
        rep_status = str(d.get("representative_status") or "").strip()
        rep_provider = str(d.get("representative_provider") or "").strip()
        rep_reason = str(d.get("representative_reason") or "").strip()
        rep_static = str(d.get("representative_static_url") or "").strip()
        try:
            rep_backups = json.loads(str(d.get("representative_backup_static_urls_json") or "[]"))
        except Exception:
            rep_backups = []
        if not isinstance(rep_backups, list):
            rep_backups = []
        rep_backup_count = len([x for x in rep_backups if str(x or "").strip()])
        polluted_count = int(d.get("gallery_polluted_count") or 0)
        failed_polluted_count = int(d.get("gallery_failed_polluted_count") or 0)
        audit_count = int(d.get("gallery_audit_count") or 0)
        media_review_reasons: list[str] = []
        media_review_level = "ok"
        media_review_label = "正常"
        if not thumb_candidates and not imgs and not lm:
            media_review_reasons.append("相冊沒有可用圖片")
        if not rep_status:
            media_review_reasons.append("尚未進行代表圖篩選")
        elif rep_status == "empty":
            media_review_reasons.append("沒有可用主展示圖")
        elif rep_status == "fallback":
            media_review_reasons.append(rep_reason or "AI 未選出合格展示圖，已降級使用規則圖")
        elif rep_status == "rules":
            media_review_reasons.append("Gemini 未配置或未使用，代表圖由規則選出")
        if rep_status in {"selected", "fallback", "rules"} and not rep_static:
            media_review_reasons.append("代表圖本地靜態檔缺失")
        if rep_status in {"selected", "fallback", "rules"} and rep_static:
            if _case_representative_static_used_by_other(int(d.get("source_item_id") or 0), rep_static):
                media_review_reasons.append("代表圖與其他案件重複，需重新篩選或人工固定")
        if rep_status in {"selected", "fallback", "rules", "manual"} and rep_backup_count <= 0:
            media_review_reasons.append("沒有備用展示圖")
        if failed_polluted_count > 0:
            media_review_reasons.append(f"相冊仍有 {failed_polluted_count} 張污染圖自動清理三次後仍未成功")
        if rep_status == "manual":
            media_review_level = "manual"
            media_review_label = "人工固定"
        elif any(x in " ".join(media_review_reasons) for x in ("沒有可用主展示圖", "相冊沒有可用圖片", "本地靜態檔缺失", "重複")):
            media_review_level = "danger"
            media_review_label = "需人工"
        elif media_review_reasons:
            media_review_level = "warn"
            media_review_label = "待確認"
        items.append(
            {
                "content_id": d.get("content_id"),
                "source_item_id": d.get("source_item_id"),
                "seo_slug": d.get("seo_slug") or "",
                "title_zh_hant": (d.get("title_zh_hant") or "")[:200],
                "source_name": d.get("source_name") or "",
                "item_url": d.get("item_url") or "",
                "updated_at": d.get("updated_at") or "",
                "image_count": len(imgs),
                "thumb_url": thumb,
                "thumb_candidates": thumb_candidates[:8],
                "thumb_kind": _thumbnail_kind_label(thumb) if thumb else "",
                "video_count": len(vids),
                "representative_status": rep_status,
                "representative_provider": rep_provider,
                "representative_score": int(d.get("representative_score") or 0),
                "representative_reason": rep_reason,
                "representative_static_url": rep_static,
                "representative_backup_count": rep_backup_count,
                "gallery_audit_count": audit_count,
                "gallery_polluted_count": polluted_count,
                "gallery_failed_polluted_count": failed_polluted_count,
                "media_review_level": media_review_level,
                "media_review_label": media_review_label,
                "media_review_reasons": media_review_reasons[:6],
                "media_needs_review": media_review_level in {"danger", "warn"},
                "region_code": d.get("region_code") or "",
                "keyword_type": d.get("keyword_type") or "",
                "topic_category": d.get("topic_category") or "",
                "featured_weight": int(d.get("featured_weight") or 0),
                "listing_media": lm,
                "case_transaction_override": str(d.get("case_transaction_override") or ""),
                "case_jp_region_override": str(d.get("case_jp_region_override") or ""),
                "case_transit_override": str(d.get("case_transit_override") or ""),
                "jp_station_id": int(d.get("jp_station_id") or 0),
                "walk_min": int(d.get("walk_min") or 0),
                **meta,
            }
        )
    return JSONResponse(
        {
            "ok": True,
            "total": total,
            "page": page,
            "page_size": page_size,
            "filters": {
                "q": (q or "").strip(),
                "transaction": (transaction or "").strip().lower(),
                "region_code": (region_code or "").strip(),
                "jp_area": (jp_area or "").strip(),
                "jp_line_id": int(jp_line_id or 0),
                "jp_station_id": int(jp_station_id or 0),
                "walk_max": int(walk_max or 0),
            },
            "items": items,
        }
    )


@app.get("/api/admin/media-review/cases")
@app.get("/api/admin/cases/media-review")
def api_admin_cases_media_review(
    request: Request,
    page: int = Query(default=1, ge=1),
    page_size: int = Query(default=20, ge=5, le=100),
    bucket: str = Query(default="actionable"),
):
    """Dedicated admin queue for cases whose representative/gallery media needs human review."""
    _require_admin_password(request)
    page = max(1, int(page))
    page_size = min(100, max(5, int(page_size)))
    bucket_key = str(bucket or "actionable").strip().lower().replace("-", "_")
    bucket_labels = {
        "actionable": "需人工处理",
        "unprocessed": "未筛选",
        "pollution_failed": "污染失败",
        "empty": "无主图/缺图",
        "no_backup": "无备份",
        "duplicate": "重复主图",
        "fallback": "AI降级",
        "rules": "规则选图",
        "no_media": "相册无图",
        "all": "全部问题",
    }
    if bucket_key not in bucket_labels:
        bucket_key = "actionable"
    unprocessed_sql = "(r.source_item_id IS NULL OR COALESCE(r.status, '') = '')"
    no_backup_sql = """(
              COALESCE(r.status, '') IN ('selected', 'fallback', 'rules', 'manual')
              AND COALESCE(r.backup_static_urls_json, '[]') IN ('', '[]')
            )"""
    no_media_sql = """(
              TRIM(COALESCE(s.hero_image_url, '')) = ''
              AND TRIM(COALESCE(s.thumbnail_url, '')) = ''
              AND TRIM(COALESCE(s.image_urls, '')) = ''
              AND TRIM(COALESCE(c.listing_media_json, '')) IN ('', '[]')
            )"""
    duplicate_rep_sql = """(
              COALESCE(r.status, '') IN ('selected', 'fallback', 'rules')
              AND TRIM(COALESCE(r.representative_static_url, '')) <> ''
              AND EXISTS (
                SELECT 1
                FROM case_representative_images r2
                WHERE r2.source_item_id <> r.source_item_id
                  AND COALESCE(r2.status, '') IN ('selected', 'fallback', 'rules')
                  AND r2.representative_static_url = r.representative_static_url
                LIMIT 1
              )
            )"""
    bucket_where_sql_map = {
        "actionable": f"""(
            NOT {unprocessed_sql}
            AND (
              COALESCE(r.status, '') IN ('empty', 'fallback', 'rules')
              OR COALESCE(r.representative_static_url, '') = ''
              OR {no_backup_sql}
              OR {duplicate_rep_sql}
              OR COALESCE(ga.failed_polluted_count, 0) > 0
              OR {no_media_sql}
            )
          )""",
        "unprocessed": unprocessed_sql,
        "pollution_failed": "COALESCE(ga.failed_polluted_count, 0) > 0",
        "empty": f"(NOT {unprocessed_sql} AND (COALESCE(r.status, '') = 'empty' OR COALESCE(r.representative_static_url, '') = ''))",
        "no_backup": no_backup_sql,
        "duplicate": duplicate_rep_sql,
        "fallback": "COALESCE(r.status, '') = 'fallback'",
        "rules": "COALESCE(r.status, '') = 'rules'",
        "no_media": f"(NOT {unprocessed_sql} AND {no_media_sql})",
        "all": f"""(
            {unprocessed_sql}
            OR COALESCE(r.status, '') IN ('empty', 'fallback', 'rules')
            OR COALESCE(r.representative_static_url, '') = ''
            OR {no_backup_sql}
            OR {duplicate_rep_sql}
            OR COALESCE(ga.failed_polluted_count, 0) > 0
            OR {no_media_sql}
          )""",
    }
    bucket_where_sql = bucket_where_sql_map[bucket_key]
    # Keep the review list fast and predictable. Pollution cleanup and stale audit
    # pruning are performed by audit/batch actions; the list endpoint only reports
    # cases that still need manual attention.

    review_from_where_sql = f"""
        FROM source_items s INDEXED BY idx_source_items_content_kind_last_checked
        JOIN content_items c ON c.source_item_id = s.id
        LEFT JOIN case_representative_images r ON r.source_item_id = s.id
        LEFT JOIN (
            SELECT source_item_id,
                   COUNT(1) AS audit_count,
                   SUM(CASE WHEN is_polluted THEN 1 ELSE 0 END) AS polluted_count,
                   SUM(CASE WHEN is_polluted AND cleanup_attempts < 3 THEN 1 ELSE 0 END) AS auto_polluted_count,
                   SUM(CASE WHEN is_polluted AND cleanup_attempts >= 3 THEN 1 ELSE 0 END) AS failed_polluted_count,
                   MAX(cleanup_attempts) AS max_cleanup_attempts,
                   MAX(cleanup_last_error) AS cleanup_last_error
            FROM case_gallery_image_audit
            GROUP BY source_item_id
        ) ga ON ga.source_item_id = s.id
        WHERE COALESCE(s.content_kind, '') = 'jp_listing'
          AND {bucket_where_sql}
    """
    select_sql = f"""
        SELECT
          c.id AS content_id,
          c.source_item_id,
          c.seo_slug,
          c.title_zh_hant,
          c.seo_title,
          c.updated_at,
          COALESCE(c.listing_media_json, '[]') AS listing_media_json,
          COALESCE(c.featured_weight, 0) AS featured_weight,
          s.id AS source_item_id,
          s.source_name,
          s.item_url,
          s.image_urls,
          s.thumbnail_url,
          s.hero_image_url,
          s.title_original,
          substr(COALESCE(s.body_original,''),1,1200) AS body_original,
          COALESCE(NULLIF(TRIM(s.content_kind), ''), '') AS content_kind,
          COALESCE(r.representative_static_url, '') AS representative_static_url,
          COALESCE(r.status, '') AS representative_status,
          COALESCE(r.provider, '') AS representative_provider,
          COALESCE(r.score, 0) AS representative_score,
          COALESCE(r.reason, '') AS representative_reason,
          COALESCE(r.backup_static_urls_json, '[]') AS representative_backup_static_urls_json,
          COALESCE(ga.audit_count, 0) AS gallery_audit_count,
          COALESCE(ga.polluted_count, 0) AS gallery_polluted_count,
          COALESCE(ga.auto_polluted_count, 0) AS gallery_auto_polluted_count,
          COALESCE(ga.failed_polluted_count, 0) AS gallery_failed_polluted_count,
          COALESCE(ga.max_cleanup_attempts, 0) AS gallery_max_cleanup_attempts,
          COALESCE(ga.cleanup_last_error, '') AS gallery_cleanup_last_error
        {review_from_where_sql}
        ORDER BY
          s.last_checked_at DESC,
          s.id DESC
        LIMIT ? OFFSET ?
    """
    with get_conn() as conn:
        start = (page - 1) * page_size
        rows = conn.execute(select_sql, (page_size + 1, start)).fetchall()
    has_more = len(rows) > page_size
    rows = rows[:page_size]

    review_items: list[dict[str, Any]] = []
    for row in rows:
        d = dict(row)
        imgs, vids = extract_media_urls_from_row(d)
        lm = _parse_listing_media_field(d.get("listing_media_json"))
        thumb_candidates: list[str] = []
        for u in imgs:
            s = str(u or "").strip()
            if s and s not in thumb_candidates and _row_image_url_is_usable(s):
                thumb_candidates.append(s)
        for m in lm:
            if not isinstance(m, dict):
                continue
            u = str(m.get("url") or "").strip()
            if u.startswith("http") and u not in thumb_candidates and _row_image_url_is_usable(u):
                thumb_candidates.append(u)
        stored_thumb = _case_stored_representative_static_url(d, thumb_candidates)
        thumb = stored_thumb or (thumb_candidates[0] if thumb_candidates else "")

        rep_status = str(d.get("representative_status") or "").strip()
        rep_reason = str(d.get("representative_reason") or "").strip()
        rep_static = str(d.get("representative_static_url") or "").strip()
        try:
            rep_backups = json.loads(str(d.get("representative_backup_static_urls_json") or "[]"))
        except Exception:
            rep_backups = []
        if not isinstance(rep_backups, list):
            rep_backups = []
        rep_backup_count = len([x for x in rep_backups if str(x or "").strip()])
        failed_polluted = int(d.get("gallery_failed_polluted_count") or 0)
        auto_polluted = int(d.get("gallery_auto_polluted_count") or 0)
        attempts = int(d.get("gallery_max_cleanup_attempts") or 0)
        reasons: list[str] = []
        level = "warn"
        label = "待確認"
        if failed_polluted > 0:
            level = "danger"
            label = "污染圖需人工"
            err = str(d.get("gallery_cleanup_last_error") or "").strip()
            reasons.append(f"相冊仍有 {failed_polluted} 張污染圖，已自動清理 {attempts} 次仍未成功。{err}".strip())
        if not thumb_candidates and not imgs and not lm:
            level = "danger"
            if label == "待確認":
                label = "無圖"
            reasons.append("相冊沒有可用圖片，前台只能顯示無圖占位。")
        if not rep_status:
            reasons.append("尚未進行代表圖篩選，需要執行 AI 代表圖預選。")
        elif rep_status == "empty":
            level = "danger"
            if label == "待確認":
                label = "無主圖"
            reasons.append("AI/規則均未找到可用主展示圖。")
        elif rep_status == "fallback":
            reasons.append(rep_reason or "AI 未選出合格展示圖，已降級使用規則圖。")
        elif rep_status == "rules":
            reasons.append("Gemini 未配置或未使用，代表圖由規則選出，建議人工抽查。")
        if rep_status in {"selected", "fallback", "rules"} and not rep_static:
            level = "danger"
            if label == "待確認":
                label = "檔案缺失"
            reasons.append("代表圖記錄存在，但本地靜態檔缺失。")
        if rep_status in {"selected", "fallback", "rules"} and rep_static:
            if _case_representative_static_used_by_other(int(d.get("source_item_id") or 0), rep_static):
                level = "danger"
                if label == "待確認":
                    label = "重複主圖"
                reasons.append("代表圖已被其他案件使用，需要重新篩選唯一封面或人工固定。")
        if rep_status in {"selected", "fallback", "rules", "manual"} and rep_static:
            static_path = _url_to_local_static_path(rep_static)
            visual_reject = _case_image_visual_reject_reason(rep_static) if static_path else ""
            if not static_path:
                level = "danger"
                if label == "待確認":
                    label = "檔案缺失"
                reasons.append("代表圖記錄存在，但本地靜態檔不存在或不在 static 目錄內。")
            elif visual_reject:
                level = "danger"
                if label == "待確認":
                    label = "展示圖需重選"
                reasons.append(f"代表圖本地視覺檢查未通過：{visual_reject}。")
        if rep_status in {"selected", "fallback", "rules", "manual"} and rep_backup_count <= 0:
            reasons.append("沒有備用展示圖，主圖失效時缺少替補。")
        if auto_polluted > 0:
            reasons.append(f"另有 {auto_polluted} 張污染圖尚在自動清理重試中，未滿三次暫不列為人工失敗。")
        if not reasons:
            continue
        review_items.append(
            {
                "content_id": d.get("content_id"),
                "source_item_id": d.get("source_item_id"),
                "title_zh_hant": d.get("title_zh_hant") or d.get("seo_title") or d.get("title_original") or "",
                "source_name": d.get("source_name") or "",
                "item_url": d.get("item_url") or "",
                "updated_at": d.get("updated_at") or "",
                "thumb_url": thumb,
                "image_count": len(imgs),
                "video_count": len(vids),
                "representative_status": rep_status,
                "representative_provider": str(d.get("representative_provider") or ""),
                "representative_score": int(d.get("representative_score") or 0),
                "representative_backup_count": rep_backup_count,
                "gallery_audit_count": int(d.get("gallery_audit_count") or 0),
                "gallery_polluted_count": int(d.get("gallery_polluted_count") or 0),
                "gallery_failed_polluted_count": failed_polluted,
                "gallery_auto_polluted_count": auto_polluted,
                "gallery_cleanup_attempts": attempts,
                "media_review_level": level,
                "media_review_label": label,
                "media_review_bucket": bucket_key,
                "media_review_bucket_label": bucket_labels[bucket_key],
                "media_review_reasons": reasons[:8],
            }
        )

    return JSONResponse(
        {
            "ok": True,
            "total": start + len(review_items) + (1 if has_more else 0),
            "total_is_estimate": True,
            "has_more": has_more,
            "page": page,
            "page_size": page_size,
            "bucket": bucket_key,
            "bucket_label": bucket_labels[bucket_key],
            "gemini_configured": is_gemini_configured(),
            "items": review_items,
        }
    )


@app.get("/api/admin/cases/{content_id}/preview")
def api_admin_case_preview(content_id: int, request: Request):
    _require_admin_password(request)
    cid = int(content_id)
    with get_conn() as conn:
        row = conn.execute(
            """
            SELECT
              c.id AS content_id,
              c.seo_slug,
              c.seo_title,
              c.seo_description,
              c.title_zh_hant,
              c.title_zh_hans,
              c.body_zh_hant,
              c.body_zh_hans,
              c.region_code,
              c.keyword_type,
              c.topic_category,
              c.updated_at,
              COALESCE(c.case_transaction_override, '') AS case_transaction_override,
              COALESCE(c.case_jp_region_override, '') AS case_jp_region_override,
              COALESCE(c.case_transit_override, '') AS case_transit_override,
              COALESCE(c.jp_station_id, 0) AS jp_station_id,
              COALESCE(c.walk_min, 0) AS walk_min,
              COALESCE(jst.station_name, '') AS jp_bind_station_name,
              COALESCE(jln.line_name, '') AS jp_bind_line_name,
              COALESCE(c.featured_weight, 0) AS featured_weight,
              COALESCE(c.listing_media_json, '[]') AS listing_media_json,
              s.source_name,
              s.item_url,
              s.image_urls,
              s.body_original,
              s.title_original,
              COALESCE(NULLIF(TRIM(s.content_kind), ''), '') AS content_kind
            FROM content_items c
            JOIN source_items s ON s.id = c.source_item_id
            LEFT JOIN jp_trans_station jst ON jst.station_id = c.jp_station_id
            LEFT JOIN jp_trans_line jln ON jln.line_id = jst.line_id
            WHERE c.id = ?
            LIMIT 1
            """,
            (cid,),
        ).fetchone()
    if not row:
        raise HTTPException(status_code=404, detail="case not found")
    d = dict(row)
    imgs, vids = extract_media_urls_from_row(d)
    representative_media = _case_stored_representative_media(d, imgs, limit=1)
    meta = infer_case_metadata(d)
    slug = (d.get("seo_slug") or "").strip()
    article_path = _standard_article_path(slug, d.get("source_item_id")) if slug else ""
    return JSONResponse(
        {
            "ok": True,
            "content_id": d.get("content_id"),
            "source_item_id": d.get("source_item_id"),
            "seo_slug": d.get("seo_slug"),
            "seo_title": d.get("seo_title"),
            "seo_description": d.get("seo_description"),
            "title_zh_hant": d.get("title_zh_hant"),
            "title_zh_hans": d.get("title_zh_hans"),
            "body_zh_hant": d.get("body_zh_hant"),
            "body_zh_hans": d.get("body_zh_hans"),
            "source_name": d.get("source_name"),
            "item_url": d.get("item_url"),
            "updated_at": d.get("updated_at"),
            "image_urls": imgs,
            "video_urls": vids,
            "representative_static_url": representative_media[0] if representative_media else "",
            "article_path": article_path,
            "region_code": d.get("region_code") or "",
            "keyword_type": d.get("keyword_type") or "",
            "topic_category": d.get("topic_category") or "",
            "content_kind": d.get("content_kind") or "",
            "case_transaction_override": str(d.get("case_transaction_override") or ""),
            "case_jp_region_override": str(d.get("case_jp_region_override") or ""),
            "case_transit_override": str(d.get("case_transit_override") or ""),
            "jp_station_id": int(d.get("jp_station_id") or 0),
            "walk_min": int(d.get("walk_min") or 0),
            "featured_weight": int(d.get("featured_weight") or 0),
            "listing_media": _parse_listing_media_field(d.get("listing_media_json")),
            **meta,
        }
    )


@app.patch("/api/admin/cases/{content_id}")
def api_admin_case_patch(content_id: int, payload: AdminCasePatchRequest, request: Request):
    _require_admin_password(request)
    cid = int(content_id)
    fields: list[str] = []
    params: list[Any] = []
    if payload.title_zh_hant is not None:
        fields.append("title_zh_hant = ?")
        params.append(str(payload.title_zh_hant))
    if payload.title_zh_hans is not None:
        fields.append("title_zh_hans = ?")
        params.append(str(payload.title_zh_hans))
    if payload.case_transaction_override is not None:
        fields.append("case_transaction_override = ?")
        params.append(_norm_case_tx_override(payload.case_transaction_override))
    if payload.case_jp_region_override is not None:
        fields.append("case_jp_region_override = ?")
        params.append(str(payload.case_jp_region_override).strip()[:500])
    if payload.case_transit_override is not None:
        fields.append("case_transit_override = ?")
        params.append(str(payload.case_transit_override).strip()[:500])
    if payload.jp_station_id is not None:
        fields.append("jp_station_id = ?")
        params.append(int(payload.jp_station_id))
    if payload.walk_min is not None:
        fields.append("walk_min = ?")
        params.append(int(payload.walk_min))
    if payload.featured_weight is not None:
        fields.append("featured_weight = ?")
        params.append(int(payload.featured_weight))
    if payload.listing_media is not None:
        fields.append("listing_media_json = ?")
        params.append(_listing_media_to_json_str(payload.listing_media))
    if not fields:
        raise HTTPException(status_code=400, detail="no fields to update")
    fields.append("updated_at = CURRENT_TIMESTAMP")
    params.append(cid)
    sql = f"UPDATE content_items SET {', '.join(fields)} WHERE id = ?"
    with get_conn() as conn:
        cur = conn.execute(sql, params)
        conn.commit()
        if cur.rowcount == 0:
            raise HTTPException(status_code=404, detail="case not found")
    return JSONResponse({"ok": True, "content_id": cid})


