@app.get("/api/home-featured-cases")
def api_home_featured_cases(
    limit: int = Query(default=12, ge=1, le=24),
    offset: int = Query(default=0, ge=0, le=5000),
    category: str = Query(default="hot"),
    property_type: str = Query(default=""),
    region: str = Query(default=""),
    q: str = Query(default=""),
    exclude_source_item_ids: str = Query(default=""),
):
    excluded_ids: list[int] = []
    for part in re.split(r"[\s,，;；]+", str(exclude_source_item_ids or "")):
        if not part:
            continue
        try:
            sid = int(part)
        except (TypeError, ValueError):
            continue
        if sid > 0:
            excluded_ids.append(sid)
    preload_payload = _home_featured_cases_payload_from_preload(
        limit=limit,
        offset=offset,
        category=category,
        property_type=property_type,
        region=region,
        q=q,
        excluded_source_item_ids=excluded_ids,
    )
    if preload_payload is not None:
        return JSONResponse(
            preload_payload,
            headers={"Cache-Control": "public, max-age=86400, stale-while-revalidate=86400"},
        )
    max_rounds = 10 if not str(property_type or "").strip() else 8
    return JSONResponse(
        _home_featured_cases_payload_merged(
            limit=limit,
            offset=offset,
            category=category,
            property_type=property_type,
            region=region,
            q=q,
            max_rounds=max_rounds,
            exclude_source_item_ids=excluded_ids,
        ),
        headers={"Cache-Control": "public, max-age=86400, stale-while-revalidate=86400"},
    )


@app.get("/api/home-featured-type-preloads")
def api_home_featured_type_preloads():
    """Return the already-screened first page for every homepage type tab.

    The browser uses this one compact request immediately after first render so
    the first type switch reads from memory instead of causing several queued
    requests on the production workers.
    """
    bundle = _home_featured_index_preload_bundle_cached_only() or {}
    raw_payloads = bundle.get("home_featured_type_preloads") or {}
    if not isinstance(raw_payloads, dict):
        raw_payloads = {}
    types = ("", "公寓", "大樓", "華廈", "套房", "別墅/透天", "辦公", "店面", "土地", "其他")
    payloads: dict[str, dict[str, Any]] = {}
    for property_type in types:
        raw = raw_payloads.get(property_type)
        if not isinstance(raw, dict):
            continue
        # Keep a little extra generic data because the client removes the
        # spotlight cards there before showing its first twelve type cards.
        item_limit = 24 if not property_type else 12
        items = [
            copy.deepcopy(item)
            for item in _home_featured_items_homepage_eligible(list(raw.get("items") or []))[:item_limit]
            if isinstance(item, dict)
        ]
        if not items:
            continue
        payloads[property_type] = {
            "ok": True,
            "items": items,
            "next_offset": int(raw.get("next_offset") or min(12, len(items))),
            "has_more": bool(raw.get("has_more") is not False),
            "property_type": property_type,
            "preloaded": True,
        }
    return JSONResponse(
        {"ok": True, "type_preloads": payloads},
        headers={"Cache-Control": "public, max-age=86400, stale-while-revalidate=86400"},
    )


@app.get("/api/home-intro-video/cases")
def api_home_intro_video_cases(q: str = Query(default=""), limit: int = Query(default=12, ge=1, le=40)):
    query = str(q or "").strip()
    lim = max(1, min(40, int(limit or 12)))
    params: list[Any] = []
    search_sql = ""
    if query:
        like = f"%{query}%"
        search_sql = """
          AND (
            c.title_zh_hant LIKE ?
            OR c.seo_title LIKE ?
            OR c.case_jp_region_override LIKE ?
            OR c.case_transit_override LIKE ?
            OR s.title_original LIKE ?
          )
        """
        params.extend([like, like, like, like, like])
    with get_conn() as conn:
        rows = conn.execute(
            f"""
            SELECT
                c.id AS content_id,
                c.source_item_id,
                c.seo_slug,
                c.seo_title,
                c.seo_description,
                c.title_zh_hant,
                c.title_zh_hans,
                substr(COALESCE(c.body_zh_hant, ''), 1, 900) AS body_zh_hant,
                c.region_code,
                c.keyword_type,
                c.topic_category,
                c.updated_at,
                COALESCE(c.case_transaction_override, '') AS case_transaction_override,
                COALESCE(c.case_jp_region_override, '') AS case_jp_region_override,
                COALESCE(c.case_transit_override, '') AS case_transit_override,
                COALESCE(c.jp_station_id, 0) AS jp_station_id,
                COALESCE(c.walk_min, 0) AS walk_min,
                COALESCE(c.listing_media_json, '[]') AS listing_media_json,
                s.source_name,
                s.item_url,
                s.image_urls,
                substr(COALESCE(s.body_original, ''), 1, 1200) AS body_original,
                s.title_original,
                COALESCE(s.thumbnail_url, '') AS thumbnail_url,
                COALESCE(s.hero_image_url, '') AS hero_image_url,
                COALESCE(NULLIF(TRIM(s.content_kind), ''), '') AS content_kind
            FROM content_items c
            JOIN source_items s ON s.id = c.source_item_id
            WHERE COALESCE(s.content_kind, '') = 'jp_listing'
              AND TRIM(COALESCE(c.seo_slug, '')) <> ''
              {search_sql}
            ORDER BY c.updated_at DESC, c.id DESC
            LIMIT ?
            """,
            [*params, lim],
        ).fetchall()
    items = [_home_intro_case_public_row(dict(r), include_script=True) for r in rows]
    return JSONResponse({"ok": True, "q": query, "items": items})


