_CHAT_GREETING_ONLY = re.compile(
    r"^[\s，。、,!！?？~～…]+$|"
    r"^[\s，。、,!！?？~～…]*("
    r"大家好|各位好|大家好啊|你好|您好|嗨|哈囉|哈喽|hello|hi|hey|hiya|"
    r"早安|午安|晚安|早|在嗎|在嘛|在不在|有人嗎|謝謝|感謝|感恩|辛苦了|"
    r"沒問題|好的|好滴|好喔|收到|嗯|嗯嗯|ok|okay|了解|知道了|掰掰|bye|88"
    r")[\s，。、,!！?？~～…]*$",
    re.I,
)

_CHAT_LIGHT_SUPPORT_ONLY = re.compile(
    r"^[\s，。、,!！?？~～…]*("
    r"你是誰|你是谁|你是什麼|你是什么|你能做什麼|你能做什么|"
    r"你可以做什麼|你可以做什么|你會什麼|你会什么|你有什麼功能|你有什么功能|"
    r"怎麼用|怎么用|如何使用|使用說明|使用说明|help|what can you do|who are you|"
    r"陪我聊聊|隨便聊聊|随便聊聊|聊聊天|闲聊|閒聊|你好吗|你好嗎|心情不好|无聊|無聊"
    r")[\s，。、,!！?？~～…]*$",
    re.I,
)

_CHAT_IDENTITY_QUESTION = re.compile(
    r"^[\s，。、,!！?？~～…]*(?:"
    r"你是誰|你是谁|你是什麼|你是什么|你是真人嗎|你是真人吗|你是真人|"
    r"是不是ai|是ai嗎|是ai吗|你是ai嗎|你是ai吗|你是不是ai|"
    r"你是機器人嗎|你是机器人吗|你是不是機器人|你是不是机器人|"
    r"誰在回我|谁在回我|誰在跟我說話|谁在跟我说话|"
    r"who are you|are you ai|are you a bot|are you human"
    r")[\s，。、,!！?？~～…]*$",
    re.I,
)

_CHAT_SMALL_TALK_HINT = re.compile(
    r"(天氣|天气|心情|無聊|无聊|累|辛苦|吃飯|吃饭|睡不著|睡不着|開心|开心|難過|难过|"
    r"哈哈|呵呵|笑死|隨便聊|随便聊|聊聊天|閒聊|闲聊|你好吗|你好嗎|最近怎樣|最近怎么样)",
    re.I,
)

