def _chat_message_suggests_knowledge_lookup(text: str) -> bool:
    """若訊息可能與日本不動產／站內知識有關才查庫；純問候等略過以加速。"""
    raw = (text or "").strip()
    if not raw:
        return False
    if len(raw) >= 34:
        return True
    if re.search(r"\d", raw):
        return True
    low = raw.lower()
    for h in _RE_HINTS_NEED_KB:
        if h.lower() in low or h in raw:
            return True
    if len(raw) <= 22 and _CHAT_GREETING_ONLY.match(raw):
        return False
    if len(raw) <= 14:
        return False
    return True


def _is_support_greeting_only(text: str) -> bool:
    raw = (text or "").strip()
    return bool(raw and len(raw) <= 24 and _CHAT_GREETING_ONLY.match(raw))


def _is_support_light_chat_only(text: str) -> bool:
    raw = (text or "").strip()
    return bool(raw and len(raw) <= 36 and (_CHAT_LIGHT_SUPPORT_ONLY.match(raw) or _CHAT_IDENTITY_QUESTION.match(raw)))


def _is_support_project_conversation_bridge(text: str) -> bool:
    """Small talk that should not trigger RAG, but should be guided back to the site journey."""
    raw = (text or "").strip()
    if not raw:
        return False
    if _is_support_identity_question(raw):
        return True
    if _is_support_greeting_only(raw) or _is_support_light_chat_only(raw):
        return True
    if len(raw) > 80:
        return False
    low = raw.lower()
    if any(h.lower() in low or h in raw for h in _RE_HINTS_NEED_KB):
        return False
    return bool(_CHAT_SMALL_TALK_HINT.search(raw))


def _build_support_greeting_reply(persona_region: str = "tw") -> str:
    _ = persona_region
    return (
        "您好，歡迎來到日本不動產線上客服。我在這邊協助您整理日本房產相關問題，您可以先把想了解的情況簡單說給我。"
    )


def _is_support_identity_question(text: str) -> bool:
    raw = (text or "").strip()
    return bool(raw and len(raw) <= 40 and _CHAT_IDENTITY_QUESTION.match(raw))


def _build_support_identity_reply(persona_region: str = "tw") -> str:
    _ = persona_region
    return (
        "這裡是網站線上客服，不是人工顧問。您可以把想了解的情況簡單說給我，我先幫您整理；需要人工協助時可填表安排實際顧問跟進。"
    )


def _build_support_light_chat_reply(
    message: str,
    persona_region: str = "tw",
) -> str:
    _ = persona_region
    raw = (message or "").strip()
    if _is_support_identity_question(raw):
        return _build_support_identity_reply(persona_region)
    if _CHAT_LIGHT_SUPPORT_ONLY.match(raw) or _CHAT_SMALL_TALK_HINT.search(raw):
        return (
            "可以，我先幫您整理方向。您回地區、用途或預算其中一項就好。"
        )
    return _build_support_greeting_reply(persona_region)


def _support_fast_empty_knowledge_meta(message: str, *, selected_cases: list[dict] | None = None) -> dict[str, Any]:
    selected = list(selected_cases or [])
    return {
        "query": str(message or "").strip(),
        "days": 0,
        "merged_max": 0,
        "row_count": 0,
        "keyword_hit_count": 0,
        "recent_fill_count": 0,
        "distinct_sources": 0,
        "items": [],
        "skipped_lookup": True,
        "featured_count": 0,
        "featured_recommendations": [],
        "managed_cases": [],
        "managed_case_count": 0,
        "selected_cases": selected,
        "selected_case_count": len(selected),
        "property_listing_intent": False,
        "purchase_discovery_mode": False,
        "purchase_discovery": {"active": False, "dimensions": {}, "missing_fields": [], "skip_reason": "keyword_preset"},
        "client_search": {"figure_keyword": "", "figure_region": "", "dialog_keyword": "", "query_blend": str(message or "").strip()},
    }


def _build_support_selected_case_fast_reply(
    message: str,
    *,
    selected_cases: list[dict] | None = None,
) -> str:
    rows = [x for x in list(selected_cases or []) if isinstance(x, dict)]
    if not rows:
        return "您好，這裡是線上客服，我先幫您接住這筆案件需求。您想先確認價格條件、稅費貸款，還是安排後續顧問跟進？"
    case = rows[0]
    case_title = str(case.get("title") or "這筆案件").strip()[:80]
    price = str(case.get("price_text_hant") or "").strip()
    layout = str(case.get("layout_text_hant") or "").strip()
    area = str(case.get("area_text_hant") or "").strip()
    region = str(case.get("jp_region_display_zh") or case.get("region") or case.get("address_hint_zh") or "").strip()
    meta_line = "｜".join(x for x in [price, layout, area, region] if x)
    next_q = _support_single_followup_question(message, intent_ref=46)
    lines = [
        "您好，這裡是線上客服，我先為您整理。",
        f"已收到您想諮詢的「{case_title}」。",
    ]
    if meta_line:
        lines.append(f"目前案件資料：{meta_line}。")
    lines.extend(
        [
            "我先幫您按這筆案件整理重點，接下來可以直接為您確認總價條件、稅費貸款，或評估是否適合自住／投資。",
            next_q,
        ]
    )
    return sanitize_support_chat_visible_reply("\n".join(lines).strip())


def _support_case_display_value(case: dict[str, Any], *keys: str, fallback: str = "待確認", max_len: int = 80) -> str:
    for key in keys:
        value = str(case.get(key) or "").strip()
        if value:
            return value[:max_len]
    return fallback


def _build_support_selected_cases_compare_reply(
    message: str,
    *,
    selected_cases: list[dict] | None = None,
) -> str:
    rows = [x for x in list(selected_cases or []) if isinstance(x, dict)]
    if not rows:
        return "目前還沒有讀到已加入對比的案件。請先把案件加入對比清單後，再輸入「比較這幾筆」。"
    if len(rows) == 1:
        return _build_support_selected_case_fast_reply(message, selected_cases=rows)

    lines: list[str] = [
        f"可以，我已讀到您加入對比的 {len(rows)} 筆案件。先按價格、區域交通、面積格局與投資風險做初步比較：",
        "",
    ]
    for idx, case in enumerate(rows[:6], start=1):
        title = _support_case_display_value(case, "title", fallback=f"案件 {idx}", max_len=72)
        price = _support_case_display_value(case, "price_text_hant", "price_fx_hant", fallback="價格待確認", max_len=42)
        area = _support_case_display_value(case, "area_text_hant", "building_area", "land_area", fallback="面積待確認", max_len=42)
        layout = _support_case_display_value(case, "layout_text_hant", "layout_structure", fallback="格局待確認", max_len=42)
        region = _support_case_display_value(case, "jp_region_display_zh", "region", "address_hint_zh", fallback="區域待確認", max_len=58)
        transit = _support_case_display_value(case, "transit_line_zh", "transit", fallback="交通待確認", max_len=70)
        sid = int(case.get("source_item_id") or 0)
        prefix = f"{idx}. "
        if sid > 0:
            prefix += f"#{sid} "
        lines.append(f"{prefix}{title}")
        lines.append(f"   價格：{price}｜面積：{area}｜格局：{layout}")
        lines.append(f"   區域：{region}｜交通：{transit}")

    priced_rows = [
        (r, _case_price_man_from_text(str(r.get("price_text_hant") or r.get("price_fx_hant") or "")))
        for r in rows
    ]
    priced_rows = [(r, price_man) for r, price_man in priced_rows if price_man is not None]
    areas_known = [r for r in rows if str(r.get("area_text_hant") or "").strip()]
    lines.extend(["", "初步看法："])
    if priced_rows:
        low, _ = min(priced_rows, key=lambda item: float(item[1] or 0))
        lines.append(
            f"價格先看：目前資料中「{_support_case_display_value(low, 'title', max_len=46)}」可先作為低總價參考，但仍要回頭確認管理費、修繕積立金與實際可租性。"
        )
    else:
        lines.append("價格先看：目前選中的案件有價格未定或缺少可解析金額，建議先確認最新售價、管理費與修繕積立金，再做投報或總成本排序。")
    if areas_known:
        lines.append("使用性先看：面積與格局要和用途綁在一起，自住重生活機能與舒適度，投資則要看出租需求、交通與持有成本。")
    lines.append("下一步建議：您可以先告訴我這幾筆主要是自住還是投資收租，我會再按用途、預算與持有成本幫您重新排序；如果想直接由顧問接上，也可以先填寫諮詢表。")
    lines.append("")
    lines.append("提醒：以上為站內已選案件的初步整理，實際價格、稅費、貸款與成交條件仍以契約、原站資料與銀行審核為準。")
    return sanitize_support_chat_visible_reply("\n".join(lines).strip())


def _build_support_selected_cases_ai_compare_reply(
    message: str,
    *,
    selected_cases: list[dict[str, Any]],
    provider: str,
    model: str,
) -> str:
    cases_text = _format_interest_cases_for_prompt(selected_cases, max_chars=5200, max_items=8)
    system = (
        "你是資深日本不動產資訊顧問。使用者已在網站加入多筆案件，現在要求你做案件對比分析。"
        "你必須直接輸出分析結果，不可只說「我來分析」或只做承接句。"
        "只能使用使用者已選案件資料中的價格、面積、格局、區域、交通、來源與站內編號；"
        "缺少資料要明確寫待確認，禁止自行補不存在的投報率、租金、價格、區域熱度或市場結論。"
        "請用繁體中文，語氣像顧問在 LINE/微信回覆，專業但不要官腔。"
        "格式：先用一句話總結；再逐筆列出重點（價格/面積格局/區域交通/風險或資料缺口）；"
        "最後一定要用「下一步建議：」收尾，提出1個最適合使用者繼續回答的問題，"
        "並自然引導使用者補預算、用途或請顧問核算，不要回答完就停。"
        "不要使用 Markdown 星號、粗體或斜體；若要列點，請用「1.」「2.」或「-」。"
    )
    user = (
        f"使用者問題：{str(message or '').strip()[:800]}\n\n"
        f"{cases_text}\n\n"
        "請基於以上已選案件做真正的比較分析，回覆中要能看出你已讀取每一筆案件。"
    )
    reply = chat_completion(
        [{"role": "system", "content": system}, {"role": "user", "content": user}],
        model=model,
        provider=provider,
        temperature=0.32,
        timeout_sec=34.0,
        max_tokens=1600,
    )
    cleaned = re.sub(r"(?m)^\s*\*\s+", "- ", reply)
    cleaned = re.sub(r"\*\*(.*?)\*\*", r"\1", cleaned)
    cleaned = re.sub(r"(?<!\*)\*(?!\*)", "", cleaned)
    return sanitize_support_chat_visible_reply(cleaned)[:8000]


def _support_should_lookup_managed_cases(
    message: str,
    *,
    case_request: bool = False,
    purchase_discovery_mode: bool = False,
) -> bool:
    raw = str(message or "").strip()
    if not raw or purchase_discovery_mode:
        return False
    if case_request:
        return True
    return bool(
        re.search(
            r"(案件|案源|物件|房源|找房|看房|公寓|大樓|大楼|マンション|一戶建|一户建|戸建|"
            r"東京|东京|大阪|福岡|福冈|京都|神奈川|橫濱|横浜|埼玉|千葉|千叶|"
            r"地區|地区|區域|区域|房價|房价|價格|价格|單價|单价|便宜|低價|低价|"
            r"預算|预算|總價|总价|租金|投資|投资|自住|投報|投报|報酬|报酬|"
            r"收益|利回|利回り|毛利|淨利|净利|現金流|现金流)",
            raw,
            flags=re.I,
        )
    )


def _support_managed_case_query_terms(message: str, *, region_hint: str = "", keyword_hint: str = "") -> tuple[str, str]:
    raw = str(message or "")
    raw_l = raw.lower()
    regions = (
        "東京", "东京", "大阪", "京都", "福岡", "福冈", "名古屋", "神奈川", "横浜", "橫濱",
        "埼玉", "千葉", "千叶", "札幌", "北海道", "沖縄", "冲绳", "首都圈", "首都圏", "關東", "关东",
    )
    props = (
        "公寓", "大樓", "大楼", "マンション", "一戶建", "一户建", "戸建", "別墅", "别墅",
        "套房", "1LDK", "2LDK", "3LDK", "商辦", "商办", "店面", "土地",
    )
    region = str(region_hint or "").strip()
    if not region:
        region = " ".join(dict.fromkeys([x for x in regions if x.lower() in raw_l][:2]))
    found_props = [x for x in props if x.lower() in raw_l]
    explicit_kw = str(keyword_hint or "").strip()
    if explicit_kw and len(explicit_kw) <= 40:
        found_props.insert(0, explicit_kw)
    broad_market_only = bool(
        re.search(
            r"(投報|投报|報酬|报酬|收益|利回|利回り|毛利|淨利|净利|現金流|现金流|"
            r"地區|地区|區域|区域|房價|房价|價格|价格|單價|单价|便宜|低價|低价)",
            raw,
            flags=re.I,
        )
    )
    if broad_market_only and not region and not found_props and not explicit_kw:
        return "", ""
    keyword = " ".join(dict.fromkeys(found_props[:3])).strip()
    if not keyword:
        terms = [
            p
            for p in re.findall(r"[A-Za-z0-9]{2,12}|[\u4e00-\u9fff]{2,8}", raw)
            if p not in {"資料庫", "目前", "已有案件", "整理方向", "下一步"}
        ]
        keyword = " ".join(dict.fromkeys(terms[:4]))
    return region[:80], keyword[:80]


def _support_lookup_managed_case_rows(
    *,
    message: str,
    region_hint: str = "",
    keyword_hint: str = "",
    tx_hint: str = "",
    limit: int = 6,
) -> list[dict[str, Any]]:
    region, query = _support_managed_case_query_terms(message, region_hint=region_hint, keyword_hint=keyword_hint)
    tx = str(tx_hint or transaction_hint_from_message(message) or "buy").strip().lower()
    if tx not in {"buy", "sell", "rent"}:
        tx = "buy"
    try:
        lim = max(1, min(12, int(limit or 6)))
        if tx == "rent":
            tx_sql = "(lower(COALESCE(s.item_url,'')) LIKE '%chintai%' OR c.title_zh_hant LIKE ? OR c.title_zh_hans LIKE ?)"
            tx_params: list[Any] = ["%租%", "%租%"]
        else:
            tx_sql = "(lower(COALESCE(s.item_url,'')) NOT LIKE '%chintai%' OR c.title_zh_hant LIKE ? OR c.title_zh_hans LIKE ?)"
            tx_params = ["%買%", "%买%"]
        terms = [x for x in re.split(r"\s+", f"{region} {query}".strip()) if x][:5]
        where_parts = [
            "s.content_kind = 'jp_listing'",
            tx_sql,
        ]
        params: list[Any] = list(tx_params)
        for term in terms:
            like = f"%{term}%"
            where_parts.append(
                """
                (
                  COALESCE(c.title_zh_hant,'') LIKE ? OR COALESCE(c.title_zh_hans,'') LIKE ?
                  OR COALESCE(c.case_jp_region_override,'') LIKE ? OR COALESCE(c.case_transit_override,'') LIKE ?
                  OR COALESCE(c.topic_category,'') LIKE ? OR COALESCE(s.title_original,'') LIKE ?
                  OR COALESCE(s.source_name,'') LIKE ?
                )
                """
            )
            params.extend([like, like, like, like, like, like, like])
        params.append(lim * 3)
        with get_conn() as conn:
            rows = conn.execute(
                f"""
                SELECT
                  c.id AS content_id,
                  c.source_item_id,
                  c.title_zh_hant,
                  c.title_zh_hans,
                  c.seo_slug,
                  c.topic_category,
                  c.case_transaction_override,
                  c.case_jp_region_override,
                  c.case_transit_override,
                  c.region_code,
                  COALESCE(c.featured_weight, 0) AS featured_weight,
                  substr(COALESCE(c.body_zh_hant, ''), 1, 500) AS body_zh_hant,
                  substr(COALESCE(c.body_zh_hans, ''), 1, 500) AS body_zh_hans,
                  s.title_original,
                  substr(COALESCE(s.body_original, ''), 1, 800) AS body_original,
                  s.item_url,
                  s.source_name,
                  s.content_kind,
                  s.image_urls,
                  c.updated_at
                FROM content_items c
                JOIN source_items s ON s.id = c.source_item_id
                WHERE {" AND ".join(where_parts)}
                ORDER BY COALESCE(c.featured_weight, 0) DESC, datetime(c.updated_at) DESC, c.id DESC
                LIMIT ?
                """,
                params,
            ).fetchall()
        out: list[dict[str, Any]] = []
        seen: set[str] = set()
        for row in rows:
            item = dict(row)
            candidates = [
                ("url", item.get("item_url")),
                ("slug", item.get("seo_slug")),
                ("title", item.get("title_zh_hant") or item.get("title_zh_hans") or item.get("title_original")),
                ("source", item.get("source_item_id")),
            ]
            keys = []
            for label, value in candidates:
                raw_key = str(value or "").strip()
                if not raw_key:
                    continue
                compact_key = re.sub(r"\s+", "", raw_key).lower()
                keys.append(f"{label}:{compact_key}")
            if not keys:
                keys = [f"content:{item.get('content_id') or ''}"]
            if any(key in seen for key in keys):
                continue
            seen.update(keys)
            out.append(item)
            if len(out) >= lim:
                break
        return out
    except Exception as exc:
        _push_backend_error_log(
            method="POST",
            path="/api/ai/chat-support",
            status_code=500,
            message=f"support_managed_cases_lookup_error: {type(exc).__name__}: {exc}"[:900],
            elapsed_ms=0,
        )
        return []


def _support_keyword_preset_reply(
    message: str,
    *,
    session_id: str,
    turn_index: int = 0,
    selected_cases: list[dict] | None = None,
    support_entry: str = "",
) -> dict[str, Any] | None:
    """Return high-confidence canned replies before slow RAG/LLM paths."""
    raw = str(message or "").strip()
    if not raw:
        return None
    if _is_support_identity_question(raw):
        return None
    compact = re.sub(r"\s+", "", raw).lower()
    selected = list(selected_cases or [])
    entry = str(support_entry or "").strip().lower()
    knowledge_meta = _support_fast_empty_knowledge_meta(raw, selected_cases=selected)

    if entry == "detail-case-consult" and selected and _support_message_explicit_case_request(raw):
        knowledge_meta["property_listing_intent"] = True
        knowledge_meta["managed_case_count"] = len(selected)
        sales_mcp = _build_sales_mcp_payload(raw, knowledge_meta, session_id=session_id, turn_index=turn_index)
        reply = _build_support_selected_case_fast_reply(
            raw,
            selected_cases=selected,
        )
        return {
            "kind": "selected_case_consult_fast_track",
            "reply": reply,
            "knowledge": knowledge_meta,
            "llm": {
                "provider": "",
                "enabled": False,
                "model": "",
                "fast_mode": True,
                "knowledge_skipped": True,
                "keyword_preset": True,
                "keyword_preset_kind": "selected_case_consult_fast_track",
            },
            "sales_mcp": sales_mcp,
            "intent_score": int(sales_mcp.get("intent_score") or 42),
        }

    def _payload(kind: str, reply: str, sales_mcp: dict[str, Any], *, intent_score: int = 0) -> dict[str, Any]:
        return {
            "kind": kind,
            "reply": sanitize_support_chat_visible_reply(reply),
            "knowledge": knowledge_meta,
            "llm": {
                "provider": "",
                "enabled": False,
                "model": "",
                "fast_mode": True,
                "knowledge_skipped": True,
                "keyword_preset": True,
                "keyword_preset_kind": kind,
            },
            "sales_mcp": sales_mcp,
            "intent_score": intent_score,
        }

    if _message_wants_human_or_advisor(raw):
        sales_mcp = _build_sales_mcp_payload(raw, knowledge_meta, session_id=session_id, turn_index=turn_index)
        reply = "可以。請先填寫需求表，送出後會由實際顧問依您留下的聯絡方式跟進。"
        return _payload("human_handoff", reply, sales_mcp, intent_score=int(sales_mcp.get("intent_score") or 82))

    flow_terms = ("買房流程", "买房流程", "購買流程", "购买流程", "怎麼買", "怎么买", "如何買", "如何买", "怎麼開始", "怎么开始")
    if any(term in compact for term in flow_terms):
        sales_mcp = _build_sales_mcp_payload(raw, knowledge_meta, session_id=session_id, turn_index=turn_index)
        sales_mcp["next_actions"] = [
            {"id": "buying_consult", "label": "先看買房流程"},
            {"id": "confirm_budget", "label": "確認預算"},
            {"id": "handoff_human", "label": "需要時轉顧問"},
        ]
        reply = (
            "日本買房通常先確認用途和預算，再看地區、稅費與貸款。您偏自住還是收租？"
        )
        return _payload("buying_flow", reply, sales_mcp, intent_score=28)

    fee_terms = ("稅費", "税费", "費用", "费用", "貸款", "贷款", "頭期", "头期", "利率", "管理費", "管理费", "修繕", "修缮")
    if any(term in compact for term in fee_terms):
        sales_mcp = _build_sales_mcp_payload(raw, knowledge_meta, session_id=session_id, turn_index=turn_index)
        sales_mcp["next_actions"] = [
            {"id": "cost_brief", "label": "拆買房成本"},
            {"id": "confirm_budget", "label": "估總預算"},
            {"id": "handoff_human", "label": "顧問核算"},
        ]
        reply = (
            "成本主要看稅費、登記費、管理費和修繕金。您有預算或案件價格嗎？"
        )
        return _payload("cost_loan", reply, sales_mcp, intent_score=34)

    return None


