def _support_purchase_discovery_dimensions(
    text: str,
    *,
    figure_region: str = "",
    figure_keyword: str = "",
    figure_price: str = "",
    figure_layout: str = "",
    figure_property_types: list[str] | None = None,
    dialog_keyword: str = "",
) -> dict[str, bool]:
    type_tokens = " ".join(str(x or "").strip() for x in (figure_property_types or []) if str(x or "").strip())
    raw = " ".join(
        str(x or "").strip()
        for x in (text, figure_region, figure_keyword, figure_price, figure_layout, type_tokens, dialog_keyword)
        if str(x or "").strip()
    )
    low = raw.lower()
    compact = re.sub(r"\s+", "", raw)
    explicit_price = bool((figure_price or "").strip() and (figure_price or "").strip() != "不限")
    explicit_layout = bool((figure_layout or "").strip() and (figure_layout or "").strip() != "不限")
    explicit_types = bool(type_tokens.strip())
    has_budget = bool(
        explicit_price
        or
        re.search(r"\d+(?:\.\d+)?\s*(?:萬|万|億|亿|円|日圓|日元|jpy|yen|nt|台幣|台币)", low, re.I)
        or re.search(r"\d+\s*[-~～]\s*\d+", low)
        or any(k in compact for k in ("預算", "预算", "總價", "总价", "上限", "以下", "以上", "最低", "最高"))
    )
    has_region = bool(figure_region.strip()) or any(k.lower() in low for k in _PURCHASE_DISCOVERY_REGIONS)
    has_type = explicit_types or any(k.lower() in low for k in _PURCHASE_DISCOVERY_TYPES)
    has_purpose = any(k.lower() in low for k in _PURCHASE_DISCOVERY_PURPOSES)
    has_station = bool(re.search(r"(站|駅|車站|车站|沿線|沿线|通勤|步行|徒步|\d+\s*分)", raw))
    has_specs = bool(explicit_layout or re.search(r"(ldk|坪|㎡|m2|平米|房|廳|厅|室|新築|新建|中古|屋齡|屋龄|格局)", low, re.I))
    return {
        "budget": has_budget,
        "region": has_region,
        "type": has_type,
        "purpose": has_purpose,
        "station": has_station,
        "specs": has_specs,
    }


def _support_message_has_purchase_intent(text: str) -> bool:
    raw = str(text or "").strip()
    if not raw:
        return False
    low = raw.lower()
    compact = re.sub(r"\s+", "", raw)
    if any(k.lower() in low or k in compact for k in _PURCHASE_DISCOVERY_INTENT_TERMS):
        return True
    return bool(re.search(r"(買|买).{0,10}(房|屋|物件|不動產|不动产|公寓|マンション)", compact))


def _support_message_is_guidance_question(text: str) -> bool:
    compact = re.sub(r"\s+", "", str(text or ""))
    if not compact:
        return False
    guidance_terms = (
        "流程",
        "怎麼開始",
        "怎么开始",
        "如何開始",
        "如何开始",
        "怎麼買",
        "怎么买",
        "如何買",
        "如何买",
        "先了解",
        "先瞭解",
        "了解一下",
        "瞭解一下",
        "諮詢",
        "咨询",
        "稅費",
        "税费",
        "貸款",
        "贷款",
        "條件",
        "条件",
        "能不能",
        "可不可以",
        "需要準備",
        "需要准备",
    )
    if not any(term in compact for term in guidance_terms):
        return False
    direct_commitment_terms = ("確定要買", "确定要买", "準備買", "准备买", "安排看屋", "安排看房", "預約看屋", "预约看房")
    return not any(term in compact for term in direct_commitment_terms)


def _support_purchase_discovery_missing_fields(dimensions: dict[str, bool]) -> list[str]:
    checks = [
        ("purpose", "用途（自住／收租／資產配置）"),
        ("budget", "總預算帶"),
        ("region", "偏好地區或車站"),
        ("type", "物件類型"),
        ("specs", "格局／房數"),
    ]
    return [label for key, label in checks if not bool(dimensions.get(key))]


def _support_should_enter_purchase_discovery(
    message: str,
    selected_cases: list[dict] | None = None,
    *,
    raw_user_message: str = "",
    figure_region: str = "",
    figure_keyword: str = "",
    figure_price: str = "",
    figure_layout: str = "",
    figure_property_types: list[str] | None = None,
    dialog_keyword: str = "",
) -> bool:
    _ = selected_cases
    user_text = (raw_user_message or message or "").strip()
    if match_jp_real_estate_guidance(user_text):
        return False
    if _support_message_is_guidance_question(user_text):
        return False
    if not _support_message_has_purchase_intent(user_text):
        return False
    dimensions = _support_purchase_discovery_dimensions(
        user_text,
        figure_region=figure_region,
        figure_keyword=figure_keyword,
        figure_price=figure_price,
        figure_layout=figure_layout,
        figure_property_types=figure_property_types,
        dialog_keyword=dialog_keyword,
    )
    filled = sum(1 for ok in dimensions.values() if ok)
    # 有明確購買意願，但用途／地區／類型仍不完整時先盤點需求；
    # 單純「買房 + 預算」不足以直接進入重檢索，否則客服會變慢且推薦失準。
    return filled < 3


def _support_purchase_discovery_prompt_block(
    *,
    selected_cases: list[dict] | None = None,
    missing_fields: list[str] | None = None,
) -> str:
    selected_count = len(selected_cases or [])
    selected_note = f"客戶目前已選 {selected_count} 筆站內案件，僅當背景整理給顧問；本輪不要介紹或推薦案件。" if selected_count else ""
    missing_note = "、".join(missing_fields or []) or "用途、預算、地區、類型、格局"
    return (
        "【購買意向但條件不足：需求盤點 BOT 模式】\n"
        "客戶表示有購買意願，但尚未提供足夠條件。請先協助縮小需求，不要推薦案件。\n"
        f"{selected_note}\n"
        "本輪禁止輸出案件列表、來源 URL、知識庫清單；請明確說明「先不急著丟案件」。\n"
        f"優先補問缺少欄位：{missing_note}。\n"
        "回覆方式：繁體中文、自然私訊口吻；先承接意願，再只問 1 個最重要問題，等客戶回答後下一輪再問下一題。\n"
        "若客戶想找人工顧問，可引導輸入「人工」或留下 LINE／電話／WeChat，並說明會把需求整理成留單。"
    ).strip()


def _build_purchase_discovery_reply(
    message: str,
    *,
    selected_cases: list[dict] | None = None,
    missing_fields: list[str] | None = None,
) -> str:
    direct_buy_intent = _support_has_direct_buying_commitment(message)
    next_q = _support_single_followup_question(message, missing_fields=missing_fields, intent_ref=60)
    selected_count = len(selected_cases or [])
    if direct_buy_intent:
        lines = [
            "收到，我先幫您接入顧問流程。",
            "先補一個關鍵條件，後面會更快。",
        ]
    else:
        lines = [
            "收到，我先幫您把買房條件收斂一下。",
        ]
    if selected_count:
        lines.append(f"已看到您選的 {selected_count} 筆案件。")
    if missing_fields and not direct_buy_intent:
        lines.append("目前先補一個關鍵條件就好。")
    lines.extend(["", next_q])
    if direct_buy_intent:
        lines.append("填完後我再幫您銜接顧問。")
    else:
        lines.append("條件明確後我再幫您接顧問。")
    return sanitize_support_chat_visible_reply("\n".join(lines).strip())


def _support_reply_violates_purchase_discovery(reply: str) -> bool:
    text = str(reply or "")
    if re.search(r"https?://", text, re.I):
        return True
    if re.search(r"(SUUMO|HOME'S|LIFULL|at home|Yahoo!不動産|楽天|イエステーション|OHEYASU)", text, re.I):
        return True
    list_like = len(re.findall(r"(?m)^\s*(?:\d+[\.\)、)]|[-*•])\s+", text))
    return len(text) > 900 or list_like >= 4


def _serialize_handoff_conversation(conv: object) -> str:
    """將前端傳來的對話紀錄壓成 JSON 字串（長度與筆數雙重上限）。"""
    rows: list[dict] = []
    if not isinstance(conv, list):
        return "[]"
    for turn in conv[:100]:
        if not isinstance(turn, dict):
            continue
        role = str(turn.get("role") or "")[:16]
        body = str(turn.get("content") or "").strip()
        if not body and (turn.get("contentHtml") or turn.get("content_html")):
            body = "[表單或圖文訊息]"
        body = body[:8000]
        if not role and not body:
            continue
        rows.append({"role": role, "content": body})
        if len(json.dumps(rows, ensure_ascii=False)) > 300000:
            rows.pop()
            break
    return json.dumps(rows, ensure_ascii=False)


def _append_turn_to_latest_handoff_conversation(session_id: str, *, role: str, content: str) -> bool:
    """將單一回合附加至該 session 最新一筆 human_handoff_requests（供 Telegram 顧問補寫入）。"""
    sid = _normalize_support_session_id(session_id or "")
    if not sid:
        return False
    role_s = str(role or "")[:16]
    body_s = str(content or "").strip()[:8000]
    if not body_s:
        return False
    init_db()
    try:
        with get_conn() as conn:
            row = conn.execute(
                """
                SELECT id, conversation_json
                FROM human_handoff_requests
                WHERE session_id = ?
                ORDER BY id DESC
                LIMIT 1
                """,
                (sid,),
            ).fetchone()
            if not row:
                return False
            hid = int(row["id"])
            raw = str(row["conversation_json"] or "").strip()
            try:
                cur = json.loads(raw) if raw else []
            except Exception:
                cur = []
            if not isinstance(cur, list):
                cur = []
            cur.append({"role": role_s, "content": body_s})
            new_json = _serialize_handoff_conversation(cur)
            conn.execute(
                "UPDATE human_handoff_requests SET conversation_json = ? WHERE id = ?",
                (new_json, hid),
            )
            conn.commit()
    except Exception:
        return False
    return True


def _handoff_conversation_search_blob(conversation: list) -> str:
    """整段對話小寫文字，供後台場景關鍵字加權命中。"""
    parts: list[str] = []
    if not isinstance(conversation, list):
        return ""
    for turn in conversation[:100]:
        if not isinstance(turn, dict):
            continue
        role = str(turn.get("role") or "").strip().lower()
        body = str(turn.get("content") or "").strip()
        if body:
            parts.append(f"{role}:{body}")
    return "\n".join(parts)[:50000].lower()


def _handoff_conversation_user_blob(conversation: list) -> str:
    parts: list[str] = []
    if not isinstance(conversation, list):
        return ""
    for turn in conversation[:100]:
        if not isinstance(turn, dict):
            continue
        if str(turn.get("role") or "").strip().lower() != "user":
            continue
        body = str(turn.get("content") or "").strip()
        if body:
            parts.append(body)
    return "\n".join(parts)[:50000].lower()


def _handoff_conversation_for_prompt(conversation: list, max_chars: int = 12000) -> str:
    parts: list[str] = []
    if not isinstance(conversation, list):
        return ""
    for turn in conversation[:100]:
        if not isinstance(turn, dict):
            continue
        role = str(turn.get("role") or "").strip()
        body = str(turn.get("content") or "").strip()
        if not body:
            continue
        parts.append(f"{role}: {body}")
    return "\n".join(parts)[:max_chars]


def _compute_scenario_weights_for_handoff(
    conversation: list,
    *,
    highlight_scene_id: str = "",
) -> list[dict]:
    """依後台 offline 場景的 priority 與關鍵字在整段對話上計分並排序。"""
    blob = _handoff_conversation_search_blob(conversation)
    user_blob = _handoff_conversation_user_blob(conversation)
    rows = _load_offline_support_scenarios(enabled_only=True)
    if not rows:
        for s in OFFLINE_SUPPORT_SCENARIOS:
            d = dict(s)
            d.setdefault("priority", 100)
            d.setdefault("enabled", True)
            rows.append(d)
    hl = (highlight_scene_id or "").strip().lower()
    by_id: dict[str, dict] = {}
    for sc in rows:
        if not sc.get("enabled", True):
            continue
        sid = str(sc.get("id") or "").strip()
        if not sid:
            continue
        label = str(sc.get("label") or "").strip()
        pr = int(sc.get("priority") or 100)
        kws = [str(k).lower() for k in (sc.get("keywords") or []) if str(k).strip()]
        hits = 0
        hit_kw: list[str] = []
        for k in kws:
            c = blob.count(k)
            if c:
                hits += min(4, c)
                if k not in hit_kw:
                    hit_kw.append(k)
        weight = pr * 2 + hits * 35
        if hl and sid.lower() == hl:
            weight += 85
        if hits > 0 or (hl and sid.lower() == hl):
            by_id[sid] = {
                "scene_id": sid,
                "label": label,
                "priority": pr,
                "keyword_hits": hits,
                "weight": weight,
                "keywords_matched": hit_kw[:16],
            }
    match_text = (user_blob or blob)[:12000]
    guessed = _match_support_scenario(match_text) if match_text.strip() else None
    if guessed:
        gid = str(guessed.get("id") or "").strip()
        if gid:
            if gid in by_id:
                by_id[gid]["weight"] = int(by_id[gid]["weight"]) + 40
            else:
                pr2 = int(guessed.get("priority") or 100)
                by_id[gid] = {
                    "scene_id": gid,
                    "label": str(guessed.get("label") or ""),
                    "priority": pr2,
                    "keyword_hits": 0,
                    "weight": pr2 * 2 + 45,
                    "keywords_matched": [],
                    "note": "整段主匹配",
                }
    out = list(by_id.values())
    out.sort(
        key=lambda x: (
            -int(x.get("weight") or 0),
            -int(x.get("keyword_hits") or 0),
            str(x.get("label") or ""),
        )
    )
    return out[:15]


def _format_scenario_weights_for_tg(weights: list[dict]) -> str:
    lines: list[str] = []
    for w in weights[:10]:
        sid = str(w.get("scene_id") or "")
        lab = str(w.get("label") or "")
        wt = int(w.get("weight") or 0)
        h = int(w.get("keyword_hits") or 0)
        pr = int(w.get("priority") or 0)
        kws = ",".join(str(x) for x in (w.get("keywords_matched") or [])[:8])
        note = str(w.get("note") or "").strip()
        extra = f" {note}" if note else ""
        lines.append(f"· {lab} ({sid}) 優先{pr} 權重{wt} 命中{h}{extra} [{kws}]")
    return "\n".join(lines) if lines else "（無場景關鍵字命中；仍以主匹配補強）"


def _build_handoff_telegram_body(
    *,
    name: str,
    phone: str,
    email: str,
    note: str,
    action_id: str,
    session_id: str,
    matched_scene_id: str,
    matched_scene_label: str,
    context_message: str,
    opinion: str,
    weights: list[dict],
    interest_cases: list[dict[str, Any]],
    ai_summary: str,
    questionnaire_text: str = "",
    max_len: int = 3900,
) -> str:
    """將聯絡資訊置前，避免 Telegram 截斷時遺失可回撥資料。"""
    wblock = _format_scenario_weights_for_tg(weights)
    ai = (ai_summary or "").strip()
    head = [
        "【人工客服／顧問留單】",
        "↩️ 回覆本則訊息可同步給網頁客戶（Session 已綁定）。",
        f"動作：{action_id or '（關鍵字轉人工）'}｜Session：{session_id or '-'}",
        f"命中場景：{matched_scene_label or '-'}（{matched_scene_id or '-'}）",
        f"姓名：{name or '-'}｜電話：{phone or '-'}｜信箱：{email or '-'}",
        f"脈絡：{(context_message or '-')[:420]}",
        f"意見：{opinion or '-'}",
        f"備註：{(note or '-')[:520]}",
        "",
    ]
    parts = list(head)
    qt = (questionnaire_text or "").strip()
    if qt:
        parts.append("【購買諮詢申請表】")
        parts.append(qt[:1800])
        parts.append("")
    if interest_cases:
        parts.append("【客戶有興趣案件】")
        parts.append(_format_interest_cases_for_tg(interest_cases, max_items=6))
        parts.append("")
    if ai:
        parts.append("【系統整理給客服】")
        parts.append(ai)
        parts.append("")
    parts.append("【場景權重（後台優先序＋關鍵字命中）】")
    parts.append(wblock)
    full = "\n".join(parts)
    if len(full) <= max_len:
        return full
    over = len(full) - max_len + 1
    if ai and len(ai) > over + 120:
        ai = ai[: max(0, len(ai) - over - 3)] + "…"
        parts = list(head)
        if qt:
            parts.append("【購買諮詢申請表】")
            parts.append(qt[:1800])
            parts.append("")
        if interest_cases:
            parts.append("【客戶有興趣案件】")
            parts.append(_format_interest_cases_for_tg(interest_cases, max_items=6))
            parts.append("")
        parts.append("【系統整理給客服】")
        parts.append(ai)
        parts.append("")
        parts.append("【場景權重（後台優先序＋關鍵字命中）】")
        parts.append(wblock)
        full = "\n".join(parts)
    if len(full) > max_len:
        full = full[: max_len - 1] + "…"
    return full


def _build_handoff_owner_notice_body(
    *,
    name: str,
    phone: str,
    email: str,
    note: str,
    interest_cases: list[dict[str, Any]],
    ai_summary: str,
    questionnaire_text: str = "",
    max_len: int = 3600,
) -> str:
    """Concise owner/advisor notice for Telegram and LINE; omit internal routing/debug fields."""

    def clean(value: object, limit: int = 260) -> str:
        return str(value or "").strip()[:limit]

    def append_section(parts: list[str], title: str, body: str) -> None:
        text = clean(body, 1400)
        if text:
            parts.append("")
            parts.append(title)
            parts.append(text)

    q_lines: list[str] = []
    for raw in str(questionnaire_text or "").splitlines():
        line = raw.strip()
        if not line:
            continue
        if line.startswith("同意聲明："):
            continue
        if phone and line.startswith("電話識別："):
            continue
        q_lines.append(line)
    q_text = "\n".join(q_lines).strip()

    # `note` may already contain the full questionnaire for DB/internal compatibility.
    # For owner notices, keep only any non-form freeform note to avoid showing the same form twice.
    note_text = clean(note, 1200)
    if "【購買諮詢申請表】" in note_text:
        note_text = note_text.split("【購買諮詢申請表】", 1)[0].strip()
    if "【預算（客戶填寫）】" in note_text:
        note_text = note_text.replace("【預算（客戶填寫）】", "預算：").strip()
    if "【留單勾選諮詢案件】" in note_text:
        note_text = note_text.split("【留單勾選諮詢案件】", 1)[0].strip()

    parts = ["【新購房諮詢】"]
    parts.append(f"姓名：{clean(name) or '-'}")
    parts.append(f"電話：{clean(phone) or '-'}")
    parts.append(f"Email：{clean(email) or '-'}")
    append_section(parts, "【客戶需求】", q_text)
    if interest_cases:
        append_section(parts, "【客戶有興趣案件】", _format_interest_cases_for_tg(interest_cases, max_items=5))
    append_section(parts, "【補充備註】", note_text)
    append_section(parts, "【跟進建議】", ai_summary)

    full = "\n".join(parts).strip()
    if len(full) > max_len:
        full = full[: max_len - 1] + "…"
    return full


def _ai_summarize_handoff_ticket(
    *,
    name: str,
    phone: str,
    email: str,
    note: str,
    opinion: str,
    action_id: str,
    context_message: str,
    scenario_weights: list[dict],
    interest_cases: list[dict[str, Any]],
    conversation_text: str,
) -> str:
    rp = resolve_llm_provider(None)
    if not is_llm_configured(rp):
        return ""
    sw = json.dumps(scenario_weights, ensure_ascii=False)[:4000]
    ic = _format_interest_cases_for_tg(interest_cases, max_items=6)[:2500]
    conv = (conversation_text or "")[:12000]
    system = (
        "你是日本不動產顧問團隊的內部助理，要把「即將由真人跟進」的客戶留單濃縮給銷售看。"
        "請用繁體中文，條列清晰，禁止虛構客戶沒說過的需求。"
        "輸出約 4 到 10 行：①客戶意圖摘要 ②疑似痛點或階段 ③建議真人跟進重點 ④風險或備註（若有）。"
    )
    user_block = (
        f"留單動作：{action_id or '人工'}\n"
        f"聯絡：姓名={name} 電話={phone} 信箱={email}\n"
        f"備註：{note[:800]}\n"
        f"意見：{opinion[:800]}\n"
        f"脈絡：{context_message[:800]}\n\n"
        f"【後台場景權重 JSON（priority 為後台優先序；keyword_hits 為對話關鍵字累計命中）】\n{sw}\n\n"
        f"【客戶有興趣案件】\n{ic}\n\n"
        f"【對話摘錄】\n{conv}\n"
    )
    msgs = [{"role": "system", "content": system}, {"role": "user", "content": user_block}]
    try:
        return chat_completion(
            msgs,
            model=None,
            temperature=0.35,
            timeout_sec=42.0,
            provider=rp,
            max_tokens=900,
        )[:3500]
    except Exception:
        return ""


def _format_support_human_questionnaire_text(questionnaire: dict[str, Any]) -> str:
    if not isinstance(questionnaire, dict) or not questionnaire:
        return ""

    def s(key: str, max_len: int = 220) -> str:
        v = questionnaire.get(key)
        if v is None:
            return ""
        if isinstance(v, bool):
            return "是" if v else "否"
        return str(v).strip()[:max_len]

    def maybe_other(main_key: str, other_key: str) -> str:
        main = s(main_key)
        if not main:
            return ""
        if main == "其他":
            other = s(other_key)
            return f"{main}（{other}）" if other else main
        return main

    lines: list[str] = []
    gender = s("gender")
    if gender:
        lines.append(f"性別：{gender}")
    line_id = s("contact_line")
    if line_id:
        lines.append(f"LINE：{line_id}")
    wechat_id = s("contact_wechat")
    if wechat_id:
        lines.append(f"微信：{wechat_id}")
    if not line_id and not wechat_id:
        linewx = s("contact_line_wechat")
        if linewx:
            lines.append(f"LINE/微信：{linewx}")
    phone_region = s("contact_phone_region_code")
    phone_local = s("contact_phone_local")
    if phone_region or phone_local:
        lines.append(f"電話識別：{phone_region} {phone_local}".strip())
    purpose = maybe_other("purchase_purpose", "purchase_purpose_other")
    if purpose:
        lines.append(f"購買目的：{purpose}")
    budget_total = s("budget_total_yen")
    if budget_total:
        lines.append(f"總預算（日幣）：{budget_total}")
    dp = s("down_payment_yen")
    if dp:
        lines.append(f"自備款（日幣）：{dp}")
    loan_need = s("loan_need")
    if loan_need:
        lines.append(f"貸款需求：{loan_need}")
    ptime = s("purchase_time")
    if ptime:
        lines.append(f"購買時間：{ptime}")
    income_src = maybe_other("income_source", "income_source_other")
    if income_src:
        lines.append(f"收入來源：{income_src}")
    inc = s("annual_income_twd")
    if inc:
        lines.append(f"年收入：{inc}")
    city = s("target_city")
    if city:
        lines.append(f"希望購買城市：{city}")
    region = maybe_other("target_region", "target_region_other")
    if region:
        lines.append(f"希望購買區域：{region}")
    line_station = s("target_line_station")
    if line_station:
        lines.append(f"希望沿線或車站：{line_station}")
    walk = s("station_walk_minutes")
    if walk:
        lines.append(f"距離最近車站步行：{walk}")
    ptype = s("property_type")
    if ptype:
        lines.append(f"物件類型：{ptype}")
    interest_status = s("interest_status")
    if interest_status:
        lines.append(f"屬意物件／區域狀態：{interest_status}")
    residence_status = maybe_other("residence_status", "residence_status_other")
    if residence_status:
        lines.append(f"中長期在留資格：{residence_status}")
    short_stay_usage = s("short_stay_usage")
    if short_stay_usage:
        lines.append(f"短期滯在物件使用規劃：{short_stay_usage}")
    view = s("viewing_intent")
    if view:
        lines.append(f"看房意願：{view}")
    loan_eval = s("loan_eval_interest")
    if loan_eval:
        lines.append(f"貸款評估：{loan_eval}")
    consent = questionnaire.get("consent_agreed")
    if consent is not None:
        lines.append(f"同意聲明：{'是' if bool(consent) else '否'}")
    other = s("other_questions", max_len=900)
    if other:
        lines.append("其他需求：")
        lines.append(other)
    picks = s("interest_pick_summary", max_len=900)
    if picks:
        lines.append("有興趣案件：")
        lines.append(picks)
    return "\n".join(lines).strip()[:2200]


def _validate_support_human_intake_questionnaire(
    *,
    name: str,
    phone: str,
    email: str,
    questionnaire: dict[str, Any],
) -> None:
    """網站智能客服轉人工前，必須先取得完整問卷與可聯絡資訊。"""
    q = questionnaire if isinstance(questionnaire, dict) else {}

    def s(key: str) -> str:
        value = q.get(key)
        if value is None:
            return ""
        return str(value).strip()

    if not name.strip():
        raise HTTPException(status_code=400, detail="請先填寫姓名，人工顧問才會回覆。")

    contact_line = s("contact_line")
    contact_wechat = s("contact_wechat")
    if s("contact_phone_local") and not bool(q.get("contact_phone_valid")):
        raise HTTPException(status_code=400, detail=s("contact_phone_error") or "聯絡電話格式不符合，請重新確認。")
    if not phone.strip() and not email.strip() and not s("contact_line_wechat") and not contact_line and not contact_wechat:
        raise HTTPException(status_code=400, detail="請至少填寫電話、LINE、微信或 Email 其中一項，人工顧問才會回覆。")

    required = [
        ("purchase_purpose", "購買目的"),
    ]
    for key, label in required:
        if not s(key):
            raise HTTPException(status_code=400, detail=f"請先完成問卷欄位：{label}。")
    other_pairs = [
        ("purchase_purpose", "purchase_purpose_other", "其他購買目的"),
    ]
    for main_key, other_key, label in other_pairs:
        if s(main_key) == "其他" and not s(other_key):
            raise HTTPException(status_code=400, detail=f"請先完成問卷欄位：{label}。")
    if not bool(q.get("consent_agreed")):
        raise HTTPException(status_code=400, detail="請先勾選聲明同意，人工顧問才會回覆。")


def _utc_iso_now() -> str:
    return datetime.utcnow().replace(microsecond=0).isoformat() + "Z"


def _claim_phone_login_followup(hid: int) -> dict[str, Any] | None:
    hid = int(hid or 0)
    if hid <= 0:
        return None
    now = _utc_iso_now()
    stale_before = (datetime.utcnow() - timedelta(minutes=8)).replace(microsecond=0).isoformat() + "Z"
    try:
        with get_conn() as conn:
            cur = conn.execute(
                """
                UPDATE human_handoff_requests
                SET followup_status = 'running',
                    followup_attempts = COALESCE(followup_attempts, 0) + 1,
                    followup_started_at = ?,
                    followup_last_error = ''
                WHERE id = ?
                  AND (
                    COALESCE(followup_status, '') IN ('', 'pending', 'retry')
                    OR (
                      COALESCE(followup_status, '') = 'running'
                      AND COALESCE(followup_started_at, '') < ?
                    )
                  )
                """,
                (now, hid, stale_before),
            )
            if int(cur.rowcount or 0) <= 0:
                conn.commit()
                return None
            row = conn.execute(
                """
                SELECT
                    id, name, phone, email, note, action_id, session_id,
                    matched_scene_id, matched_scene_label, context_message, opinion,
                    questionnaire_json, conversation_json, scenario_weights_json,
                    followup_attempts, followup_telegram_sent, followup_line_sent
                FROM human_handoff_requests
                WHERE id = ?
                LIMIT 1
                """,
                (hid,),
            ).fetchone()
            conn.commit()
            return dict(row) if row else None
    except Exception as exc:
        _log_backend_error("phone-login-followup-claim", exc)
        return None


def _mark_phone_login_followup_done(hid: int, *, telegram_sent: bool, line_sent: bool) -> None:
    if int(hid or 0) <= 0:
        return
    try:
        with get_conn() as conn:
            conn.execute(
                """
                UPDATE human_handoff_requests
                SET followup_status = 'done',
                    followup_last_error = '',
                    followup_finished_at = ?,
                    followup_telegram_sent = CASE WHEN ? THEN 1 ELSE followup_telegram_sent END,
                    followup_line_sent = CASE WHEN ? THEN 1 ELSE followup_line_sent END
                WHERE id = ?
                """,
                (_utc_iso_now(), 1 if telegram_sent else 0, 1 if line_sent else 0, int(hid)),
            )
            conn.commit()
    except Exception as exc:
        _log_backend_error("phone-login-followup-done", exc)


def _mark_phone_login_followup_retry(hid: int, error: str) -> None:
    if int(hid or 0) <= 0:
        return
    err = str(error or "")[:500]
    try:
        with get_conn() as conn:
            row = conn.execute(
                "SELECT COALESCE(followup_attempts, 0) AS attempts FROM human_handoff_requests WHERE id = ?",
                (int(hid),),
            ).fetchone()
            attempts = int(row["attempts"] or 0) if row else 0
            status = "failed" if attempts >= 5 else "retry"
            conn.execute(
                """
                UPDATE human_handoff_requests
                SET followup_status = ?,
                    followup_last_error = ?,
                    followup_finished_at = ?
                WHERE id = ?
                """,
                (status, err, _utc_iso_now(), int(hid)),
            )
            conn.commit()
    except Exception as exc:
        _log_backend_error("phone-login-followup-retry", exc)


def _decode_handoff_json_list(raw: Any) -> list:
    try:
        val = json.loads(str(raw or "[]"))
        return val if isinstance(val, list) else []
    except Exception:
        return []


def _decode_handoff_json_dict(raw: Any) -> dict[str, Any]:
    try:
        val = json.loads(str(raw or "{}"))
        return val if isinstance(val, dict) else {}
    except Exception:
        return {}


def _recover_pending_phone_login_followups_once(*, limit: int = 12) -> int:
    lim = max(1, min(50, int(limit or 12)))
    stale_before = (datetime.utcnow() - timedelta(minutes=8)).replace(microsecond=0).isoformat() + "Z"
    try:
        with get_conn() as conn:
            rows = conn.execute(
                """
                SELECT id
                FROM human_handoff_requests
                WHERE (
                    COALESCE(followup_status, '') IN ('pending', 'retry')
                    OR (
                      COALESCE(followup_status, '') = 'running'
                      AND COALESCE(followup_started_at, '') < ?
                    )
                  )
                ORDER BY id ASC
                LIMIT ?
                """,
                (stale_before, lim),
            ).fetchall()
    except Exception as exc:
        _log_backend_error("phone-login-followup-recovery-load", exc)
        return 0
    started = 0
    for row in rows:
        hid = int(dict(row).get("id") or 0)
        if hid <= 0:
            continue
        try:
            threading.Thread(
                target=_human_intake_phone_login_followup,
                kwargs={"hid": hid},
                daemon=True,
                name=f"phone-login-followup-retry-{hid}",
            ).start()
            started += 1
        except Exception as exc:
            _log_backend_error("phone-login-followup-recovery-start-item", exc)
    return started


def _human_intake_phone_login_followup(
    *,
    hid: int,
    name: str = "",
    phone: str = "",
    email: str = "",
    note: str = "",
    opinion: str = "",
    action_id: str = "phone_login",
    session_id: str = "",
    matched_scene_id: str = "",
    matched_scene_label: str = "",
    context_message: str = "",
    conv_list: list | None = None,
    weights: list | None = None,
    questionnaire_text: str = "",
) -> None:
    """Run expensive phone-login handoff sync after the login response returns."""
    claimed = _claim_phone_login_followup(hid)
    if not claimed:
        return
    name = name or str(claimed.get("name") or "")[:120]
    phone = phone or str(claimed.get("phone") or "")[:80]
    email = email or str(claimed.get("email") or "")[:160]
    note = note or str(claimed.get("note") or "")[:2000]
    action_id = action_id or str(claimed.get("action_id") or "phone_login")[:80]
    session_id = session_id or str(claimed.get("session_id") or "")[:120]
    matched_scene_id = matched_scene_id or str(claimed.get("matched_scene_id") or "")[:80]
    matched_scene_label = matched_scene_label or str(claimed.get("matched_scene_label") or "")[:160]
    context_message = context_message or str(claimed.get("context_message") or "")[:2000]
    opinion = opinion or str(claimed.get("opinion") or "")[:2000]
    if conv_list is None:
        conv_list = _decode_handoff_json_list(claimed.get("conversation_json"))
    if weights is None:
        weights = _decode_handoff_json_list(claimed.get("scenario_weights_json"))
    if not questionnaire_text:
        questionnaire = _decode_handoff_json_dict(claimed.get("questionnaire_json"))
        questionnaire_text = _format_support_human_questionnaire_text(questionnaire) if questionnaire else ""
    telegram_already_sent = bool(int(claimed.get("followup_telegram_sent") or 0))
    line_already_sent = bool(int(claimed.get("followup_line_sent") or 0))
    telegram_sent_now = False
    line_sent_now = False
    try:
        conv_prompt = _handoff_conversation_for_prompt(conv_list)
        interest_cases = _load_support_session_interest_cases(session_id, limit=20)
        last_user_msg = ""
        for turn in reversed(conv_list):
            if not isinstance(turn, dict):
                continue
            if str(turn.get("role") or "").strip().lower() == "user":
                last_user_msg = str(turn.get("content") or "").strip()
                if last_user_msg:
                    break
        ai_summary = _ai_summarize_handoff_ticket(
            name=name,
            phone=phone,
            email=email,
            note=note,
            opinion=opinion,
            action_id=action_id,
            context_message=context_message,
            scenario_weights=weights,
            interest_cases=interest_cases,
            conversation_text=conv_prompt,
        )
        if hid > 0 and ai_summary:
            try:
                with get_conn() as conn:
                    conn.execute(
                        "UPDATE human_handoff_requests SET ai_handoff_summary = ? WHERE id = ?",
                        (ai_summary[:8000], hid),
                    )
                    conn.commit()
            except Exception as exc:
                _log_backend_error("phone-login-summary-update", exc)
        try:
            eval_msg = context_message or last_user_msg or "號碼登入／顧問留單"
            eval_knowledge = {
                "row_count": 0,
                "distinct_sources": 0,
                "skipped_lookup": True,
                "selected_case_count": len(interest_cases),
                "managed_case_count": 0,
                "featured_count": 0,
                "property_listing_intent": bool(interest_cases),
                "selected_cases": interest_cases,
            }
            eval_sales = {
                "session_id": session_id,
                "human_handoff_intent": True,
                "should_notify_human": True,
                "lead_capture": _support_lead_capture_blueprint(eval_msg, eval_knowledge, human_intent=True),
            }
            eval_scene = None
            if weights:
                top_w = dict(weights[0])
                eval_scene = {
                    "id": top_w.get("scene_id") or "",
                    "label": top_w.get("label") or "",
                    "keywords": top_w.get("keywords_matched") or [],
                }
            bot_eval = _build_support_bot_self_eval(
                message=eval_msg,
                reply=ai_summary or "已建立號碼登入顧問留單。",
                knowledge_meta=eval_knowledge,
                sales_mcp=eval_sales,
                llm_meta={
                    "enabled": bool(is_llm_configured(resolve_llm_provider(None))),
                    "crm_prompt_injected": bool(_support_crm_enabled_runtime()),
                },
                matched_scene=eval_scene,
                matched_qa=None,
            )
            _save_support_bot_self_eval(session_id=session_id, message=eval_msg, bot_eval=bot_eval)
        except Exception as exc:
            _log_backend_error("phone-login-bot-eval", exc)
        owner_notice_body = _build_handoff_owner_notice_body(
            name=name,
            phone=phone,
            email=email,
            note=note,
            interest_cases=interest_cases,
            ai_summary=ai_summary,
            questionnaire_text=questionnaire_text,
        )
        notify_errors: list[str] = []
        if (not telegram_already_sent) and _support_notify_channel_enabled("telegram"):
            try:
                _telegram_send_and_bridge(owner_notice_body[:3900], session_id, "human_handoff")
                telegram_sent_now = True
                with get_conn() as conn:
                    conn.execute(
                        "UPDATE human_handoff_requests SET followup_telegram_sent = 1 WHERE id = ?",
                        (int(hid),),
                    )
                    conn.commit()
            except Exception as exc:
                err = _sanitize_telegram_error_detail(exc)[:300]
                notify_errors.append(f"telegram: {err}")
                _log_backend_error("phone-login-telegram-notify", err)
        if (not line_already_sent) and _support_notify_channel_enabled("line"):
            try:
                _line_send_and_bridge(owner_notice_body[:4900], session_id, "human_handoff")
                line_sent_now = True
                with get_conn() as conn:
                    conn.execute(
                        "UPDATE human_handoff_requests SET followup_line_sent = 1 WHERE id = ?",
                        (int(hid),),
                    )
                    conn.commit()
            except Exception as exc:
                err = _sanitize_line_error_detail(exc)[:300]
                notify_errors.append(f"line: {err}")
                _log_backend_error("phone-login-line-notify", err)
        if notify_errors:
            raise RuntimeError("; ".join(notify_errors))
        _mark_phone_login_followup_done(
            hid,
            telegram_sent=telegram_already_sent or telegram_sent_now,
            line_sent=line_already_sent or line_sent_now,
        )
    except Exception as exc:
        _mark_phone_login_followup_retry(hid, str(exc))
        _log_backend_error("phone-login-followup", exc)


def _human_intake_core(payload: HumanIntakeRequest, request: Request) -> JSONResponse:
    name = (payload.name or "").strip()[:120]
    phone = (payload.phone or "").strip()[:80]
    email = (payload.email or "").strip()[:160]
    note = (payload.note or "").strip()[:2000]
    budget_text = (payload.budget_text or "").strip()[:500]
    interest_pick_summary = (payload.interest_pick_summary or "").strip()[:4000]
    opinion = (payload.opinion or "").strip()[:2000]
    questionnaire = payload.questionnaire if isinstance(payload.questionnaire, dict) else {}
    questionnaire_text = _format_support_human_questionnaire_text(questionnaire) if questionnaire else ""
    questionnaire_json = ""
    if questionnaire:
        try:
            questionnaire_json = json.dumps(questionnaire, ensure_ascii=False)[:120000]
        except Exception:
            questionnaire_json = ""
    action_id = (payload.action_id or "").strip()[:80]
    strict_questionnaire = (not action_id) or str(questionnaire.get("form_version") or "") == "jp_property_buy_intake_v1"
    if strict_questionnaire:
        _validate_support_human_intake_questionnaire(
            name=name,
            phone=phone,
            email=email,
            questionnaire=questionnaire,
        )
    if not name and not phone and not email:
        # 允許僅填預算／備註／勾選案件／顧問意見（勿僅依 hidden context 放行，避免空白送出）
        if budget_text or note or interest_pick_summary or opinion:
            name = "（未填姓名／電話／信箱｜請見備註／預算／案件）"[:120]
        else:
            raise HTTPException(status_code=400, detail="請至少填寫姓名、電話或信箱其中一項；或填寫預算／備註／勾選案件／顧問意見。")
    note_extra: list[str] = []
    if budget_text:
        note_extra.append(f"【預算（客戶填寫）】{budget_text}")
    if interest_pick_summary:
        note_extra.append(f"【留單勾選諮詢案件】\n{interest_pick_summary}")
    if questionnaire_text:
        note_extra.append(f"【購買諮詢申請表】\n{questionnaire_text}")
    if note_extra:
        note = (note + "\n\n" + "\n".join(note_extra)).strip()[:2000]
    session_id = _normalize_support_session_id(payload.session_id or "")
    if not session_id:
        session_id = f"sess-{uuid4().hex[:16]}"
    matched_scene_id = (payload.matched_scene_id or "").strip()[:80]
    matched_scene_label = (payload.matched_scene_label or "").strip()[:160]
    context_message = (payload.context_message or "").strip()[:2000]
    conv_list: list = list(payload.conversation) if isinstance(payload.conversation, list) else []
    async_followup = True
    weights = _compute_scenario_weights_for_handoff(conv_list, highlight_scene_id=matched_scene_id)
    weights_json = json.dumps(weights, ensure_ascii=False)[:120000]
    conv_json = _serialize_handoff_conversation(payload.conversation)
    ua = str(request.headers.get("user-agent") or "")[:400]
    last_err: Exception | None = None
    hid = 0
    max_attempts = 8
    for attempt in range(max_attempts):
        try:
            with get_conn() as conn:
                cur = conn.execute(
                    """
                    INSERT INTO human_handoff_requests (
                        name, phone, email, note, user_agent,
                        action_id, session_id, matched_scene_id, matched_scene_label, context_message, opinion,
                        questionnaire_json, conversation_json, scenario_weights_json, ai_handoff_summary, followup_status
                    )
                    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, '', ?)
                    """,
                    (
                        name,
                        phone,
                        email,
                        note,
                        ua,
                        action_id,
                        session_id,
                        matched_scene_id,
                        matched_scene_label,
                        context_message,
                        opinion,
                        questionnaire_json,
                        conv_json,
                        weights_json,
                        "pending" if async_followup else "",
                    ),
                )
                hid = int(cur.lastrowid or 0)
                conn.commit()
            last_err = None
            break
        except sqlite3.OperationalError as exc:
            last_err = exc
            el = str(exc).lower()
            if attempt == 0 and "no such column" in el:
                init_db()
                continue
            if attempt < max_attempts - 1 and ("database is locked" in el or "locked" in el or "busy" in el):
                time.sleep(0.06 * (attempt + 1))
                continue
            raise HTTPException(status_code=503, detail=f"資料庫寫入失敗：{exc}") from exc
    if last_err is not None:
        raise HTTPException(status_code=503, detail=f"資料庫寫入失敗：{last_err}") from last_err
    if async_followup:
        try:
            threading.Thread(
                target=_human_intake_phone_login_followup,
                kwargs={
                    "hid": hid,
                    "name": name,
                    "phone": phone,
                    "email": email,
                    "note": note,
                    "opinion": opinion,
                    "action_id": action_id,
                    "session_id": session_id,
                    "matched_scene_id": matched_scene_id,
                    "matched_scene_label": matched_scene_label,
                    "context_message": context_message,
                    "conv_list": conv_list,
                    "weights": weights,
                    "questionnaire_text": questionnaire_text,
                },
                daemon=True,
                name=f"human-intake-followup-{hid or 0}",
            ).start()
        except Exception as exc:
            _log_backend_error("human-intake-followup-start", exc)
        return _mark_form_filled_response(
            JSONResponse(
                {
                    "ok": True,
                    "handoff_id": hid,
                    "session_id": session_id,
                    "scenario_weights": weights,
                    "interested_cases": [],
                    "ai_handoff_summary": "",
                    "telegram_sent": False,
                    "telegram_error": "",
                    "line_sent": False,
                    "line_error": "",
                    "notify_channels": _support_notify_channels(),
                    "line_qr_url": "/static/human-handoff/line-group.png",
                    "line_group_qr_url": "/static/human-handoff/line-group.png",
                    "wechat_qr_url": "",
                    "fast_submit": True,
                    "sync_pending": True,
                    "notify_pending": True,
                }
            )
        )
    conv_prompt = _handoff_conversation_for_prompt(conv_list)
    interest_cases = _load_support_session_interest_cases(session_id, limit=20)
    last_user_msg = ""
    for turn in reversed(conv_list):
        if not isinstance(turn, dict):
            continue
        if str(turn.get("role") or "").strip().lower() == "user":
            last_user_msg = str(turn.get("content") or "").strip()
            if last_user_msg:
                break
    ai_summary = _ai_summarize_handoff_ticket(
        name=name,
        phone=phone,
        email=email,
        note=note,
        opinion=opinion,
        action_id=action_id,
        context_message=context_message,
        scenario_weights=weights,
        interest_cases=interest_cases,
        conversation_text=conv_prompt,
    )
    if hid > 0 and ai_summary:
        try:
            with get_conn() as conn:
                conn.execute(
                    "UPDATE human_handoff_requests SET ai_handoff_summary = ? WHERE id = ?",
                    (ai_summary[:8000], hid),
                )
                conn.commit()
        except Exception:
            pass
    try:
        eval_msg = context_message or last_user_msg or "人工／顧問留單"
        eval_knowledge = {
            "row_count": 0,
            "distinct_sources": 0,
            "skipped_lookup": True,
            "selected_case_count": len(interest_cases),
            "managed_case_count": 0,
            "featured_count": 0,
            "property_listing_intent": bool(interest_cases),
            "selected_cases": interest_cases,
        }
        eval_sales = {
            "session_id": session_id,
            "human_handoff_intent": True,
            "should_notify_human": True,
            "lead_capture": _support_lead_capture_blueprint(eval_msg, eval_knowledge, human_intent=True),
        }
        eval_scene = None
        if weights:
            top_w = dict(weights[0])
            eval_scene = {
                "id": top_w.get("scene_id") or "",
                "label": top_w.get("label") or "",
                "keywords": top_w.get("keywords_matched") or [],
            }
        bot_eval = _build_support_bot_self_eval(
            message=eval_msg,
            reply=ai_summary or "已建立人工顧問留單。",
            knowledge_meta=eval_knowledge,
            sales_mcp=eval_sales,
            llm_meta={
                "enabled": bool(is_llm_configured(resolve_llm_provider(None))),
                "crm_prompt_injected": bool(_support_crm_enabled_runtime()),
            },
            matched_scene=eval_scene,
            matched_qa=None,
        )
        _save_support_bot_self_eval(session_id=session_id, message=eval_msg, bot_eval=bot_eval)
    except Exception:
        pass
    owner_notice_body = _build_handoff_owner_notice_body(
        name=name,
        phone=phone,
        email=email,
        note=note,
        interest_cases=interest_cases,
        ai_summary=ai_summary,
        questionnaire_text=questionnaire_text,
    )
    tg_sent = False
    tg_err = ""
    line_sent = False
    line_err = ""
    if _support_notify_channel_enabled("telegram"):
        try:
            _telegram_send_and_bridge(owner_notice_body[:3900], session_id, "human_handoff")
            tg_sent = True
        except Exception as exc:
            tg_err = _sanitize_telegram_error_detail(exc)[:300]
    if _support_notify_channel_enabled("line"):
        try:
            _line_send_and_bridge(owner_notice_body[:4900], session_id, "human_handoff")
            line_sent = True
        except Exception as exc:
            line_err = _sanitize_line_error_detail(exc)[:300]
    return _mark_form_filled_response(
        JSONResponse(
            {
                "ok": True,
                "handoff_id": hid,
                "session_id": session_id,
                "scenario_weights": weights,
                "interested_cases": interest_cases,
                "ai_handoff_summary": ai_summary,
                "telegram_sent": tg_sent,
                "telegram_error": tg_err,
                "line_sent": line_sent,
                "line_error": line_err,
                "notify_channels": _support_notify_channels(),
                "line_qr_url": "/static/human-handoff/line-group.png",
                "line_group_qr_url": "/static/human-handoff/line-group.png",
                "wechat_qr_url": "",
            }
        )
    )


