def _portal_case_apply_representative_media(items: list[dict[str, Any]]) -> list[dict[str, Any]]:
    """Normalize search card media to the same representative image policy as home cards."""
    sid_media: dict[int, list[str]] = {}
    sid_context: dict[int, dict[str, Any]] = {}
    sids = sorted(
        {
            int(item.get("source_item_id") or 0)
            for item in items
            if isinstance(item, dict) and int(item.get("source_item_id") or 0) > 0
        }
    )
    if sids:
        try:
            placeholders = ",".join("?" for _ in sids)
            with get_conn() as conn:
                rows = conn.execute(
                    f"""
                    SELECT id, source_name, source_category, item_url, title_original,
                           body_original, image_urls, hero_image_url, thumbnail_url
                    FROM source_items
                    WHERE id IN ({placeholders})
                    """,
                    sids,
                ).fetchall()
            for row in rows:
                d = dict(row)
                sid = int(d.get("id") or 0)
                sid_context[sid] = d
                sid_media[sid] = [
                    str(d.get("hero_image_url") or "").strip(),
                    str(d.get("thumbnail_url") or "").strip(),
                    *_row_primary_image_url_lines(d, limit=12),
                ]
        except Exception:
            sid_media = {}
            sid_context = {}
    out: list[dict[str, Any]] = []
    for item in items:
        if not isinstance(item, dict):
            continue
        nit = dict(item)
        sid = int(nit.get("source_item_id") or 0)
        primary_candidates = sid_media.get(sid, [])
        fallback_candidates = [
            str(nit.get("thumb_url") or "").strip(),
            *[str(u or "").strip() for u in (nit.get("gallery_urls") or [])],
            *[str(u or "").strip() for u in (nit.get("image_urls") or [])],
        ]
        raw_candidates = primary_candidates or fallback_candidates
        rep_row = {**sid_context.get(sid, {}), **nit, "source_item_id": sid, "id": sid}
        rep_context = _case_representative_context_text(rep_row)
        rep_profile = _case_representative_profile(rep_row, context=rep_context)
        stored_gallery = _case_stored_representative_media(rep_row, raw_candidates, limit=4)
        gallery = (
            stored_gallery[:]
            if stored_gallery
            else _home_featured_fast_cached_gallery_urls(raw_candidates, limit=8, context=rep_context, profile=rep_profile)
        )
        if not gallery and primary_candidates:
            gallery = _home_featured_fast_cached_gallery_urls(
                fallback_candidates,
                limit=8,
                context=rep_context,
                profile=rep_profile,
            )
        if not gallery:
            gallery = _dedupe_case_gallery_urls(
                [
                    _normalize_listing_image_url_for_display(
                        str(u or "").strip(),
                        suumo_w=_SOURCE_IMAGE_HIGH_RES_W,
                        suumo_h=_SOURCE_IMAGE_HIGH_RES_H,
                    )
                    for u in fallback_candidates
                    if str(u or "").strip() and _is_case_property_gallery_image_url(str(u or "").strip())
                ],
                suumo_w=_SOURCE_IMAGE_HIGH_RES_W,
                suumo_h=_SOURCE_IMAGE_HIGH_RES_H,
            )[:8]
        if gallery:
            nit["thumb_url"] = gallery[0]
            nit["gallery_urls"] = gallery
            nit["thumb_kind"] = _thumb_kind_label(gallery[0])
            nit["image_count"] = max(int(nit.get("image_count") or 0), len(gallery))
        else:
            nit["thumb_url"] = ""
            nit["gallery_urls"] = []
            nit["thumb_kind"] = ""
            nit["image_count"] = 0
        out.append(nit)
    return out


def _portal_case_normalize_response_media(items: list[dict[str, Any]]) -> list[dict[str, Any]]:
    """Normalize media URLs just before API output so cards and detail use one image policy."""
    out: list[dict[str, Any]] = []
    for item in items:
        if not isinstance(item, dict):
            continue
        nit = dict(item)
        gallery_raw = [str(u or "").strip() for u in (nit.get("gallery_urls") or []) if str(u or "").strip()]
        thumb_raw = str(nit.get("thumb_url") or "").strip()
        if thumb_raw:
            gallery_raw = [thumb_raw, *[u for u in gallery_raw if u != thumb_raw]]
        gallery = _dedupe_case_gallery_urls(
            [
                _normalize_listing_image_url_for_display(
                    u,
                    suumo_w=_SOURCE_IMAGE_HIGH_RES_W,
                    suumo_h=_SOURCE_IMAGE_HIGH_RES_H,
                )
                for u in gallery_raw
                if _is_case_property_gallery_image_url(
                    _normalize_listing_image_url_for_display(
                        u,
                        suumo_w=_SOURCE_IMAGE_HIGH_RES_W,
                        suumo_h=_SOURCE_IMAGE_HIGH_RES_H,
                    )
                    or u
                )
            ],
            suumo_w=_SOURCE_IMAGE_HIGH_RES_W,
            suumo_h=_SOURCE_IMAGE_HIGH_RES_H,
        )[:8]
        if gallery:
            nit["thumb_url"] = gallery[0]
            nit["gallery_urls"] = gallery
            nit["thumb_kind"] = _thumb_kind_label(gallery[0])
            nit["image_count"] = max(int(nit.get("image_count") or 0), len(gallery))
        else:
            nit["thumb_url"] = ""
            nit["gallery_urls"] = []
            nit["thumb_kind"] = ""
            nit["image_count"] = 0
        out.append(nit)
    return out


def _normalize_smart_query_portals(*raw_values: Any) -> list[str]:
    out: list[str] = []
    for raw in raw_values:
        if raw is None:
            continue
        if isinstance(raw, (list, tuple, set)):
            for x in raw:
                sx = str(x or "").strip().lower()
                if sx:
                    key = SMART_QUERY_PORTAL_ALIASES.get(sx, sx)
                    if key in SMART_QUERY_PORTAL_KEYS and key not in out:
                        out.append(key)
            continue
        s = str(raw or "").strip().lower()
        if not s:
            continue
        for tok in re.split(r"[,\s|]+", s):
            if not tok:
                continue
            key = SMART_QUERY_PORTAL_ALIASES.get(tok, tok)
            if key in SMART_QUERY_PORTAL_KEYS and key not in out:
                out.append(key)
    return out


@app.post("/api/portal-case-search")
def api_portal_case_search(payload: PortalCaseSearchRequest):
    settings = load_crawl_settings()
    cap = max(1000, min(100000, int(settings.get("portal_query_max_records", 100000))))
    page_offset = max(0, int(payload.offset or 0))
    page_size = max(0, min(240, int(payload.page_size or 0)))
    req_lim = int(payload.limit) if payload.limit is not None else cap
    if req_lim <= 0:
        # Frontend smart-query cards are paged. A zero limit means "use the
        # default", but for a first page we only need a small candidate window;
        # scanning the full portal cap makes common keywords feel frozen.
        req_lim = max(60, page_size * 10) if page_size > 0 else cap
    lim = max(10, min(req_lim, cap))
    allowed_tx = _allowed_portal_transactions(settings)

    tx = (payload.transaction or "").strip().lower()
    if not tx and (payload.deal_side or "").strip():
        tx = (payload.deal_side or "").strip().lower()
    if tx not in allowed_tx:
        tx = "buy"

    portal_keys = _normalize_smart_query_portals(payload.portal, payload.portals)
    portal = ",".join(portal_keys) if portal_keys else "all"
    kw = (payload.keyword or "").strip()
    max_age = int(payload.max_age_days)
    if max_age < 0:
        max_age = 0
    if max_age > 366:
        max_age = 366
    property_types = [str(x or "").strip() for x in (payload.property_types or []) if str(x or "").strip()]
    price_min_man = max(0, min(999_999, int(payload.price_min_man or 0)))
    price_max_man = max(0, min(999_999, int(payload.price_max_man or 0)))
    if price_min_man > 0 and price_max_man > 0 and price_max_man < price_min_man:
        price_min_man, price_max_man = price_max_man, price_min_man
    layout_min_rooms = max(0, min(99, int(payload.layout_min_rooms or 0)))
    layout_max_rooms = max(0, min(99, int(payload.layout_max_rooms or 0)))
    layout_exact_zero = bool(payload.layout_exact_zero)
    if layout_exact_zero:
        layout_min_rooms = 0
        layout_max_rooms = 0
    if layout_min_rooms > 0 and layout_max_rooms > 0 and layout_max_rooms < layout_min_rooms:
        layout_min_rooms, layout_max_rooms = layout_max_rooms, layout_min_rooms
    exact_count_payload = _portal_case_search_exact_count_normalized_payload(
        tx=tx,
        portal=portal,
        region_hint=(payload.region_hint or "").strip(),
        keyword=kw,
        property_types=property_types,
        price_min_man=price_min_man,
        price_max_man=price_max_man,
        layout_min_rooms=layout_min_rooms,
        layout_max_rooms=layout_max_rooms,
        layout_exact_zero=layout_exact_zero,
        max_age_days=max_age,
        limit=lim,
        jp_line_id=int(payload.jp_line_id or 0),
        jp_station_id=int(payload.jp_station_id or 0),
        walk_max=int(payload.walk_max or 0),
        coverage_matrix_aligned=bool(payload.coverage_matrix_aligned),
    )
    exact_count_data, exact_count_status = _portal_case_search_exact_count_get_with_status(
        _portal_case_search_exact_count_key(exact_count_payload)
    )
    def _attach_exact_count_meta(raw: dict[str, Any], *, count_exact_known: bool = False) -> dict[str, Any]:
        out = dict(raw or {})
        if page_size > 0:
            if count_exact_known:
                out["count_status"] = "ready"
                out["count_provisional"] = False
            else:
                # Keep paged-search `count` on the same "current return window" basis.
                # If a background exact total exists, expose it separately so UI logic
                # does not mix provisional page-window counts with exact whole-result totals.
                if exact_count_data is not None:
                    out["count_exact_total"] = int(exact_count_data.get("count") or 0)
                    out["count_exact_total_status"] = "ready"
                else:
                    out["count_exact_total"] = None
                    out["count_exact_total_status"] = "pending" if exact_count_status == "pending" else "miss"
                out["count_status"] = "ready"
                out["count_provisional"] = True
        else:
            out["count_status"] = "ready"
            out["count_provisional"] = False
            out["count_exact_total"] = int(out.get("count") or 0)
            out["count_exact_total_status"] = "ready"
        return out

    cache_key = _portal_case_search_cache_key(
        {
            "tx": tx,
            "portal": portal,
            "region": (payload.region_hint or "").strip(),
            "keyword": kw,
            "property_types": property_types,
            "price_min_man": price_min_man,
            "price_max_man": price_max_man,
            "layout_min_rooms": layout_min_rooms,
            "layout_max_rooms": layout_max_rooms,
            "layout_exact_zero": layout_exact_zero,
            "max_age_days": max_age,
            "limit": lim,
            "jp_line_id": int(payload.jp_line_id or 0),
            "jp_station_id": int(payload.jp_station_id or 0),
            "walk_max": int(payload.walk_max or 0),
            "coverage_matrix_aligned": bool(payload.coverage_matrix_aligned),
            "offset": page_offset if page_size > 0 else 0,
            "page_size": page_size if page_size > 0 else 0,
            "detail_gate": "openable-v1",
            "media_policy": "detail-panel-gallery-v20-yahoo-nf-normalized",
        }
    )
    cached_body, cache_status = _portal_case_search_cache_get_with_status(cache_key)
    if cached_body is not None:
        try:
            cached_data = json.loads(cached_body)
            cached_count_exact = bool(cached_data.get("count_exact")) and not bool(cached_data.get("count_provisional"))
            if page_size > 0:
                cached_items = cached_data.get("items") if isinstance(cached_data, dict) else []
                cached_data["portal_image_warm"] = _portal_case_result_warm_primary_images(
                    list(cached_items or []),
                    limit=min(6, max(1, int(page_size or 6))),
                )
            cached_body = json.dumps(
                _attach_exact_count_meta(cached_data, count_exact_known=cached_count_exact),
                ensure_ascii=False,
                separators=(",", ":"),
            )
        except Exception:
            pass
        return Response(
            content=cached_body,
            media_type="application/json",
            headers={"X-Portal-Case-Search-Cache": cache_status},
        )

    data = search_portal_cases(
        transaction=tx,
        portal=portal,
        region_hint=(payload.region_hint or "").strip(),
        keyword=kw,
        property_types=property_types,
        price_min_man=price_min_man,
        price_max_man=price_max_man,
        layout_min_rooms=layout_min_rooms,
        layout_max_rooms=layout_max_rooms,
        layout_exact_zero=layout_exact_zero,
        max_age_days=max_age,
        limit=lim,
        offset=page_offset,
        page_size=page_size,
        jp_line_id=int(payload.jp_line_id or 0),
        jp_station_id=int(payload.jp_station_id or 0),
        walk_max=int(payload.walk_max or 0),
        coverage_matrix_aligned=bool(payload.coverage_matrix_aligned),
    )
    has_transit_filter = bool(
        int(payload.jp_line_id or 0) > 0
        or int(payload.jp_station_id or 0) > 0
        or int(payload.walk_max or 0) > 0
    )
    if page_size > 0:
        allow_search_live_backfill, live_backfill_reason = False, "paged_fast_mode"
    else:
        allow_search_live_backfill, live_backfill_reason = _portal_search_live_backfill_allowed(
            has_transit_filter=has_transit_filter,
            request_limit=lim,
        )
    items_bf, bf_meta = _portal_api_backfill_empty_thumbs(
        list(data.get("items") or []),
        allow_live_fetch=allow_search_live_backfill,
    )
    if not allow_search_live_backfill:
        bf_meta["skipped_reason"] = live_backfill_reason or "search_fast_mode"
    response_region_hint = (payload.region_hint or "").strip()
    if response_region_hint:
        for item in items_bf:
            if isinstance(item, dict) and not str(item.get("jp_region_display_zh") or "").strip():
                item["jp_region_display_zh"] = response_region_hint
    items_bf, detail_gate_meta = _portal_case_filter_openable_detail_items(items_bf)
    items_bf = _portal_case_prioritize_displayable_media(items_bf)
    if page_size <= 0:
        items_bf = _portal_case_apply_representative_media(items_bf)
        _case_schedule_representative_selection(items_bf[: min(len(items_bf), 4)], limit=4)
    items_bf = _portal_case_normalize_response_media(items_bf)
    data["items"] = items_bf
    data["portal_detail_gate"] = detail_gate_meta
    if page_size > 0:
        data["portal_detail_enrich"] = {"enabled": False, "scheduled": 0, "reason": "paged_fast_mode"}
    else:
        data["portal_detail_enrich"] = _portal_search_schedule_detail_enrich(items_bf)
    if page_size > 0:
        data["portal_image_warm"] = _portal_case_result_warm_primary_images(
            items_bf,
            limit=min(6, max(1, int(page_size or 6))),
        )
        _portal_case_result_prefetch_images(items_bf, limit=12)
    elif lim <= 24:
        _portal_case_result_prefetch_images(items_bf, limit=6)
    data["portal_thumb_backfill"] = bf_meta
    track_filters = {
        "transaction": tx,
        "portal": portal,
        "portal_keys": portal_keys,
        "region": response_region_hint,
        "property_types": property_types,
        "price_min_man": price_min_man,
        "price_max_man": price_max_man,
        "layout_min_rooms": layout_min_rooms,
        "layout_max_rooms": layout_max_rooms,
        "layout_exact_zero": layout_exact_zero,
        "max_age_days": max_age,
        "limit": lim,
        "jp_line_id": int(payload.jp_line_id or 0),
        "jp_station_id": int(payload.jp_station_id or 0),
        "walk_max": int(payload.walk_max or 0),
        "coverage_matrix_aligned": bool(payload.coverage_matrix_aligned),
    }
    threading.Thread(
        target=lambda: track_keyword_search(
            keyword=kw or f"portal_case:{tx}:{portal or 'all'}",
            channel="portal_case_search",
            filters=track_filters,
        ),
        daemon=True,
    ).start()
    data["portal_keys"] = portal_keys or list(SMART_QUERY_PORTAL_KEYS)
    data["allowed_transactions"] = allowed_tx
    data["smart_query_show_sell"] = bool(settings.get("smart_query_show_sell"))
    data["smart_query_show_rent"] = bool(settings.get("smart_query_show_rent"))
    result_count_exact = bool(data.get("count_exact")) and not bool(data.get("count_provisional"))
    data = _attach_exact_count_meta(data, count_exact_known=result_count_exact)
    response_body = json.dumps(data, ensure_ascii=False, separators=(",", ":"))
    _portal_case_search_cache_set(cache_key, response_body)
    return Response(
        content=response_body,
        media_type="application/json",
        headers={"X-Portal-Case-Search-Cache": "miss"},
    )


